DROP TABLE IF EXISTS `orders`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `orders` (
  `order_rec_id` int NOT NULL AUTO_INCREMENT,
  `customer_rec_id` int DEFAULT NULL,
  `account_number` varchar(50) DEFAULT NULL,
  `order_number` varchar(50) DEFAULT NULL,
  `receipt_number` varchar(50) DEFAULT NULL,
  `order_date` datetime DEFAULT NULL,
  `order_status` enum('pending','approved','rejected','completed','failed') DEFAULT NULL,
  `next_action_required` enum('approval','approved','in_progress','rejected','completed','failed') DEFAULT NULL,
  `order_cat` enum('DO','IOC','GTC') DEFAULT NULL,
  `order_type` enum('Buy','Sell','Exchange','Redeem') NOT NULL,
  `limit_or_market` varchar(100) DEFAULT NULL,
  `metal` varchar(50) DEFAULT NULL,
  `order_json` json DEFAULT NULL,
  `row_metadata` json DEFAULT NULL,
  PRIMARY KEY (`order_rec_id`),
  UNIQUE KEY `order_number` (`order_number`),
  UNIQUE KEY `receipt_number` (`receipt_number`)
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
