DELIMITER ;;
CREATE DEFINER=`root`@`localhost` FUNCTION `isValidIP`(	
                            psIPAddress 	VARCHAR(64) 
                        ) RETURNS tinyint(1)
    DETERMINISTIC
BEGIN

    IF NOT EXISTS (SELECT 1 FROM IP_Whitelist WHERE ip_address = psIPAddress) THEN
        RETURN FALSE;
	ELSE
		RETURN TRUE;
    END IF;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP FUNCTION IF EXISTS `mergeIfMissing` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` FUNCTION `mergeIfMissing`(
                            pjTarget    JSON,       -- inventory_json
                            pjKeys      JSON,       -- JSON array of key names to copy from product_json
                            pjSource    JSON        -- product_json
) RETURNS json
    DETERMINISTIC
BEGIN
    DECLARE i           INT DEFAULT 0;
    DECLARE n           INT;
    DECLARE keyName     VARCHAR(255);
    DECLARE vResult     JSON;

    SET vResult         = pjTarget;
    SET n               = JSON_LENGTH(pjKeys);

    WHILE i < n DO
        SET keyName = JSON_UNQUOTE(JSON_EXTRACT(pjKeys, CONCAT('$[', i, ']')));

        -- If key exists in source
        IF JSON_CONTAINS_PATH(pjSource, 'one', CONCAT('$.', keyName)) THEN

            -- If key is missing in target, copy it
            IF NOT JSON_CONTAINS_PATH(vResult, 'one', CONCAT('$.', keyName)) THEN
                SET vResult = JSON_SET(
                    vResult,
                    CONCAT('$.', keyName),
                    JSON_EXTRACT(pjSource, CONCAT('$.', keyName))
                );
            ELSE
                -- If key exists and is an object, merge recursively
                IF JSON_TYPE(JSON_EXTRACT(vResult, CONCAT('$.', keyName))) = 'OBJECT'
                   AND JSON_TYPE(JSON_EXTRACT(pjSource, CONCAT('$.', keyName))) = 'OBJECT' THEN
                    SET vResult = JSON_MERGE_PATCH(
                        vResult,
                        JSON_OBJECT(keyName, JSON_MERGE_PATCH(
                            JSON_EXTRACT(vResult, CONCAT('$.', keyName)),
                            JSON_EXTRACT(pjSource, CONCAT('$.', keyName))
                        ))
                    );
                END IF;
            END IF;

        END IF;

        SET i = i + 1;
    END WHILE;

    RETURN vResult;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `changePassword` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `changePassword`(
								IN  pReqObj       JSON,
								OUT pResObj       JSON
							)
BEGIN
    DECLARE v_login_id        VARCHAR(255);
    DECLARE v_old_password    VARCHAR(255);
    DECLARE v_new_password    VARCHAR(255);
    
    DECLARE v_customer_rec_id 	INT;
    DECLARE v_user_name       	VARCHAR(255);
    DECLARE v_email           	VARCHAR(255);
    DECLARE v_phone             VARCHAR(20);
    DECLARE v_db_password     	VARCHAR(255);

    main_block: BEGIN

        -- =========================
        -- Extract values from JSON
        -- =========================
        SET v_login_id      = getJval(pReqObj, 'P_LOGIN_ID');
        SET v_old_password  = getJval(pReqObj, 'P_OLD_PASSWORD');
        SET v_new_password  = getJval(pReqObj, 'P_NEW_PASSWORD');

        -- Validate input
        IF v_login_id IS NULL OR v_old_password IS NULL OR v_new_password IS NULL THEN
            SET pResObj = JSON_OBJECT(
                'status',  'INVALID_REQUEST',
                'message', 'Login ID, Old Password and New Password are required.'
            );
            LEAVE main_block;
        END IF;

        -- =========================
        -- Find user and get current password
        -- =========================
        SELECT customer_rec_id, 	user_name, 	 email, 	phone,    getJval(auth_json,'$.login_credentials.password')  AS current_password
        INTO   v_customer_rec_id,   v_user_name, v_email,   v_phone,  v_db_password
        FROM   auth a
        JOIN   customer c ON a.parent_table_rec_id = c.customer_rec_id
        WHERE  c.user_name 	= v_login_id
            OR c.email 		= v_login_id
            OR c.phone 		= v_login_id
        LIMIT 1;

        -- User not found
        IF v_customer_rec_id IS NULL THEN
            SET pResObj = JSON_OBJECT(
                'status',  'USER_NOT_FOUND',
                'message', 'No account matches the provided login ID.'
            );
            LEAVE main_block;
        END IF;

        -- =========================
        -- Validate old password
        -- =========================
        IF SHA2(v_old_password,256) <> v_db_password THEN
            SET pResObj = JSON_OBJECT(
										'status', 'INVALID_OLD_PASSWORD',
										'message', 'The old password is incorrect.'
									);
            LEAVE main_block;
        END IF;
        
		-- =========================
        -- Check if new password equals current password
        -- =========================
        
        IF SHA2(v_new_password,256) = v_db_password THEN
            SET pResObj = JSON_OBJECT(
                'status', 'PASSWORD_REUSED',
                'message', 'New password cannot be the same as your current password.'
            );
            LEAVE main_block;
        END IF;
        
        -- =========================
        -- Prevent reuse of last passwords
        -- =========================
        IF EXISTS (
            SELECT 1 
            FROM password_history
            WHERE parent_table_name		 = 'customer'
              AND parent_table_rec_id 	 = v_customer_rec_id
              AND password_hash 		 = SHA2(v_new_password,256)
        ) THEN
            SET pResObj = JSON_OBJECT(
                'status', 'PASSWORD_REUSED',
                'message', 'You cannot reuse a previous password.'
            );
            LEAVE main_block;
        END IF;

        -- =========================
        -- Update password in auth table
        -- =========================
        UPDATE auth
        SET auth_json = JSON_SET(auth_json, '$.login_credentials.password', SHA2(v_new_password,256))
        WHERE 	parent_table_name = 'customer'
		AND		parent_table_rec_id = v_customer_rec_id;

        -- =========================
        -- Deactivate previous password in history
        -- =========================
        UPDATE password_history
        SET is_active = 0
        WHERE parent_table_name = 'customer'
          AND parent_table_rec_id = v_customer_rec_id
          AND is_active = 1;

        -- =========================
        -- Insert new password into password history
        -- =========================
        
          INSERT INTO password_history
        SET   parent_table_name 		= 'customer',
              parent_table_rec_id		= v_customer_rec_id,
              password_hash				= SHA2(v_new_password,256),
              password_set_at			= NOW(),
              password_change_by		= 'customer',
              password_change_reason	= 'Change password',
              last_password_updated_at  = NOW(),
              password_expiration_date	= DATE_ADD(NOW(), INTERVAL 90 DAY),
             is_active					= 1;

        -- =========================
        -- Success response
        -- =========================
        SET pResObj  = JSON_OBJECT(
            'status',  'PASSWORD_CHANGE_SUCCESS',
            'message', 'Your password has been successfully changed.'
        );

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `createAcustomerWallet` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `createAcustomerWallet`(
										IN p_customer_rec_id         INT,
										IN p_tradable_assets_rec_id  INT
									   )
BEGIN
    DECLARE v_customer_json     JSON;
    DECLARE v_asset_json        JSON;
    DECLARE v_wallet            JSON;
    DECLARE v_wallet_path       VARCHAR(100);
    DECLARE v_wallet_id         VARCHAR(100);

    /* ================= VALIDATE + LOAD CUSTOMER ================= */
    SELECT 	customer_json 
    INTO   	v_customer_json
    FROM   	customer
    WHERE  	customer_rec_id = p_customer_rec_id;

    IF v_customer_json IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Customer not found';
    END IF;

    /* ================= VALIDATE + LOAD ASSET ================= */
	SELECT 	tradable_assets_json
    INTO   	v_asset_json
    FROM   	tradable_assets
    WHERE  	tradable_assets_rec_id = p_tradable_assets_rec_id;
    

	IF v_asset_json IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Tradable asset not found or unavailable';
    END IF;

    /* ============== CHECK WALLET EXISTS =============== */
    SET v_wallet_path = JSON_SEARCH(
                            v_customer_json,
                            'one',
                            JSON_UNQUOTE(JSON_EXTRACT(v_asset_json, '$.asset_code')),
                            NULL,
                            '$.customer_wallets[*].asset_code'
                        );

    IF v_wallet_path IS NOT NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'Customer wallet already exists for this asset';
    END IF;

    /* =============== GENERATE WALLET ID ============== */
    CALL getSequence(
					   'CUSTOMER.WALLET_ID',
					   'WID-',
						1122,
						'createCustomerWallet',
                        @wallet_id
					);
    SET v_wallet_id = @wallet_id;

    /* =============== BUILD WALLET JSON ============= */
    SET v_wallet = fillTemplate(
								 v_asset_json,
								 getTemplate('customer_wallets')
								);

    SET v_wallet = JSON_SET( v_wallet,
							'$.wallet_id', 					v_wallet_id,
							'$.wallet_status', 				'OPEN',
							'$.wallet_balance', 			0,
							'$.balance_unit',  				'UNIT',
							'$.balance_last_updated_at', 	NOW()
						 );

    /* ================ APPEND WALLET ============ */
    SET v_customer_json = JSON_ARRAY_APPEND( v_customer_json,
											 '$.customer_wallets',
											  v_wallet
										   );

    /* =============== UPDATE CUSTOMER ============ */
    UPDATE customer
    SET customer_json 	= v_customer_json
    WHERE customer_rec_id = p_customer_rec_id;
    
	/* ================= Wallet_activity ============= */
	CALL wallet_activity(
						  p_customer_rec_id,     -- customer_rec_id
						  v_wallet_id,           -- wallet_id
						  'CREATE',              -- activity type
						  0,                     -- amount
						  'Wallet created',      -- reason
						  NULL,                  -- order_rec_id
						  NULL,                  -- order_number
						  NULL                   -- transaction_num
					    );

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `createBuyOrder` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `createBuyOrder`(
                                        IN      pjReqObj    JSON,
                                        INOUT  pjRespObj    JSON
                                    )
BEGIN

    
        /* ===================== Variables ===================== */
        DECLARE vThisObj                    VARCHAR(32)               DEFAULT 'createBuyOrder';
        DECLARE v_customer_rec_id           INT;
        DECLARE v_account_number            VARCHAR(50);
        DECLARE v_order_rec_id              INT;
        DECLARE v_order_number              VARCHAR(50);
        DECLARE v_receipt_number            VARCHAR(50);
        DECLARE v_order_date                DATETIME;
        DECLARE v_order_status              VARCHAR(20);
        DECLARE v_next_action_required      VARCHAR(20);
        DECLARE v_order_cat                 VARCHAR(10);
        DECLARE v_order_type                VARCHAR(20);
        DECLARE v_order_sub_type            VARCHAR(20);
        DECLARE v_metal                     VARCHAR(50);
        DECLARE v_asset_code                VARCHAR(10);
        DECLARE v_product_type              VARCHAR(20);
        DECLARE v_cr_payment_method         VARCHAR(50);        
        DECLARE v_cr_rate                   DECIMAL(20,6);  
        DECLARE v_cr_weight                 DECIMAL(20,6);       

        DECLARE v_tradable_assets_rec_id    INT;
        DECLARE v_rate_json                 JSON;
        DECLARE v_spot_rate                 DECIMAL(20,6);      

        DECLARE v_customer_json             JSON;
        DECLARE v_order_json                JSON;
        DECLARE v_row_metadata              JSON;

        /*  buy_items variables (shared by SLICE and PRODUCT)  */
        DECLARE v_inventory_json            JSON;
        DECLARE v_item_code                 VARCHAR(50);
        DECLARE v_item_name                 VARCHAR(100);
        DECLARE v_item_type                 VARCHAR(50);
        DECLARE v_item_weight               DECIMAL(20,6);
        DECLARE v_item_quantity             INT;
        DECLARE v_bought_price              DECIMAL(20,6);
        DECLARE v_buy_items_output          JSON;
        DECLARE v_customer_products_json    JSON            DEFAULT JSON_ARRAY();

        /* Order Summary Variables */

        DECLARE v_total_buy_items       INT DEFAULT 0;
        DECLARE v_total_buy_amount      DECIMAL(20,6) DEFAULT 0;
        DECLARE v_total_buy_weight      DECIMAL(20,6) DEFAULT 0;
        DECLARE v_making_charges        DECIMAL(20,6) DEFAULT 0;
        DECLARE v_premium_charged       DECIMAL(20,6) DEFAULT 0;
        DECLARE v_transaction_fee       DECIMAL(20,6) DEFAULT 0;
        DECLARE v_processing_charges    DECIMAL(20,6) DEFAULT 0;
        DECLARE v_taxes                 DECIMAL(20,6) DEFAULT 0;
        DECLARE v_total_discounts       DECIMAL(20,6) DEFAULT 0;

        /* --- PRODUCT loop variables --- */
        DECLARE v_buy_items_input           JSON;
        DECLARE v_single_item               JSON;
        DECLARE v_loop_idx                  INT DEFAULT 0;
        DECLARE v_items_count               INT DEFAULT 0;

        /* --- Transaction / wallet variables --- */
        DECLARE v_txn_num_debit             VARCHAR(50);
        DECLARE v_txn_num_credit            VARCHAR(50);
        DECLARE v_transactions_output       JSON;

        DECLARE v_metal_wallet_id           VARCHAR(100);
        DECLARE v_metal_balance_before      DECIMAL(20,6);
        DECLARE v_metal_balance_after       DECIMAL(20,6);
        DECLARE v_metal_txn_amount          DECIMAL(20,6);

        DECLARE v_cash_wallet_id            VARCHAR(100);
        DECLARE v_cash_balance_before       DECIMAL(20,6);
        DECLARE v_cash_balance_after        DECIMAL(20,6);
        DECLARE v_cash_txn_amount           DECIMAL(20,6);

        DECLARE v_total_order_amount        DECIMAL(20,6) DEFAULT 0;
        DECLARE v_wallets_arr               JSON;
        DECLARE v_wallet_loop_idx           INT DEFAULT 0;
        DECLARE v_wallet_count              INT DEFAULT 0;
        DECLARE v_wallet_item               JSON;
        DECLARE v_wallet_asset_code         VARCHAR(20);
        DECLARE v_wallet_type               VARCHAR(20);

        DECLARE v_errors                    JSON DEFAULT JSON_ARRAY();
        DECLARE v_err_msg                   VARCHAR(500);

        /* ===================== Error Handler ===================== */
        DECLARE EXIT HANDLER FOR SQLEXCEPTION
        BEGIN
            GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
            ROLLBACK;
    
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 	 CONCAT('Insertion failed: ', v_err_msg));

        END;

    main_block: BEGIN
        /* ===================== Step 1: Extract Request Values ===================== */
        SET v_order_type            = 'Buy';
        SET v_account_number        = getJval(pjReqObj, 'jData.P_ACCOUNT_NUMBER');
        SET v_order_sub_type        = getJval(pjReqObj, 'jData.P_ORDER_SUB_TYPE');
        SET v_order_cat             = getJval(pjReqObj, 'jData.P_ORDER_CAT');
        SET v_metal                 = getJval(pjReqObj, 'jData.P_METAL');
        SET v_product_type          = getJval(pjReqObj, 'jData.P_PRODUCT_TYPE');
        SET v_cr_payment_method     = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_PAYMENT_METHOD');

        /* For PRODUCT, order_sub_type is not applicable */
        IF v_product_type = 'PRODUCT' THEN
            SET v_order_sub_type = NULL;
        END IF;

        /* ===================== Step 2: Common Validations ===================== */
        IF isFalsy(v_account_number) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'account_number is required');
        END IF;

        IF isFalsy(v_order_type) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'order_type is required');
        END IF;

        IF isFalsy(v_metal) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'metal is required');
        END IF;

        IF isFalsy(v_cr_payment_method) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.payment_method is required');
        END IF;

        IF JSON_LENGTH(v_errors) > 0 THEN
        
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'Validation failed: ');
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.errors', v_errors);

            LEAVE main_block;
        END IF;

        /* ===================== Step 3: Fetch Customer Record ===================== */
        SELECT  customer_rec_id 
        INTO    v_customer_rec_id
        FROM    customer
        WHERE   account_num = v_account_number
        LIMIT 1;

        -- check if customer record exists for the provided account_number
        IF isFalsy(v_customer_rec_id) THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Customer not found');

            LEAVE main_block;
        END IF;

        SET v_customer_json = getCustomer(v_customer_rec_id);

        IF isFalsy(v_customer_json) THEN
           
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Customer not found for account number: ', v_account_number));
            
            LEAVE main_block;
            
        END IF;      

        /* ===================== Step 5: Generate Order & Receipt Numbers ===================== */
        CALL getSequence('ORDERS.ORDER_NUM',    NULL,   3000, 'createBuyOrder', v_order_number);
        CALL getSequence('ORDERS.RECEIPT_NUM', 'RECP-', 3000, 'createBuyOrder', v_receipt_number);

        /* ===================== Step 6: Set Common Order Header Values ===================== */
        SET v_order_date                = NOW();
        SET v_order_status              = 'pending';
        SET v_next_action_required      = 'approval';

        /* ===================== Step 7: Load Order Template & Row Metadata ===================== */
        SET v_row_metadata      = getTemplate('row_metadata');
        SET v_order_json        = getTemplate('orders');
        
        SET v_row_metadata	    = JSON_SET( v_row_metadata,
                                            '$.status', 		v_order_status,  
                                            '$.created_at',		DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
                                            '$.created_by',    CONCAT(
                                                                            getJval(v_customer_json, 'first_name'), 
                                                                            ' ', 
                                                                            getJval(v_customer_json, 'last_name'),
                                                                            ' Customer Self-Service'
                                                                        )
                                        );

        /* ===================== Step 8: Populate Customer & Rate Info & top level fields ===================== */
        SET v_order_json = JSON_SET(v_order_json,
                                    '$.customer_info.customer_rec_id',          v_customer_rec_id,
                                    '$.customer_info.customer_name',            CONCAT(getJval(v_customer_json, 'first_name'), ' ', getJval(v_customer_json, 'last_name')),
                                    '$.customer_info.customer_account_number',  getJval(v_customer_json, 'main_account_number'),
                                    '$.customer_info.customer_phone',           getJval(v_customer_json, 'phone'),
                                    '$.customer_info.whatsapp',                 getJval(v_customer_json, 'whatsapp'),
                                    '$.customer_info.customer_email',           getJval(v_customer_json, 'email'),
                                    '$.customer_info.customer_address',         CAST(getJval(v_customer_json, 'residential_address') AS JSON),
                                    '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'jData.P_CUSTOMER_IP_ADDRESS'),
                                    '$.customer_info.latitude',                 getJval(pjReqObj, 'jData.P_LATITUDE'),
                                    '$.customer_info.longitude',                getJval(pjReqObj, 'jData.P_LONGITUDE'),
                                    '$.customer_info.notes',                    getJval(pjReqObj, 'jData.P_NOTES'),

                                    '$.customer_rec_id',                        v_customer_rec_id,
                                    '$.account_number',                         v_account_number,
                                    '$.order_number',                           v_order_number,
                                    '$.receipt_number',                         v_receipt_number,
                                    '$.order_date',                             DATE_FORMAT(v_order_date, '%Y-%m-%dT%H:%i:%sZ'),
                                    '$.order_status',                           v_order_status,
                                    '$.next_action_required',                   v_next_action_required,
                                    '$.order_type',                             v_order_type,
                                    '$.limit_or_market',                         v_order_sub_type,
                                    '$.metal',                                  v_metal
                                );

        /* ===================== Step 9: Branch by product_type ===================== */
        IF v_product_type = 'SLICE' THEN

            SET v_item_code         = getJval(pjReqObj, 'jData.P_ITEM_CODE');

            /* Validate order_sub_type for SLICE */
            IF isFalsy(v_order_sub_type) THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'order_sub_type is required for SLICE order');
            END IF;

            /* ---------------------------------------------------------------
            SLICE: validate item_code + customer_request.weight (common to Market & Limit)
            --------------------------------------------------------------- */  
            IF isFalsy(v_item_code) THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'item_code is required for SLICE order');
            END IF;


            IF JSON_LENGTH(v_errors) > 0 THEN
                
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Validation failed: ');
                SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.errors', v_errors);

                LEAVE main_block;
            END IF;

            /* ---------------------------------------------------------------
            SLICE: lookup item_name + item_type from inventory table
            --------------------------------------------------------------- */

            SELECT  inventory_json
            INTO    v_inventory_json
            FROM    inventory
            WHERE   item_code = v_item_code
            LIMIT   1;

            IF isFalsy(v_inventory_json) THEN
                
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Inventory item not found for item code: ', v_item_code));
                
                LEAVE main_block;
            END IF;

            SET v_item_weight      = getJval(pjReqObj,          'jData.P_ITEM_WEIGHT');
            SET v_item_name        = getJval(v_inventory_json,  'item_name');
            SET v_item_type        = getJval(v_inventory_json,  'item_type');
            SET v_asset_code       = getJval(v_inventory_json,  'asset_code');  

                    /* ===================== Fetch Latest Rate for Asset rate history ===================== */
            SELECT   tradable_assets_rec_id,      tradable_assets_json
            INTO     v_tradable_assets_rec_id,    v_rate_json
            FROM     tradable_assets
            WHERE    asset_code = v_asset_code
            ORDER BY tradable_assets_rec_id DESC
            LIMIT 1;
            
            IF isFalsy(v_rate_json) THEN
                
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Rate not found for asset_code: ', v_asset_code));
               
                LEAVE main_block;
            END IF;

              /* Extract spot_rate once - reused in buy_items price calculation */    
            SET v_spot_rate = getJval(v_rate_json, 'spot_rate.current_rate');  

            /*  Populate rate_info in order_json Now we have the rate  */
            SET v_order_json = JSON_SET(v_order_json,
                                        '$.rate_info.rate_rec_id',              v_tradable_assets_rec_id,
                                        '$.rate_info.spot_rate',                v_spot_rate,
                                        '$.rate_info.currency_unit',            getJval(v_rate_json, 'spot_rate.currency'),
                                        '$.rate_info.rate_source',              getJval(v_rate_json, 'spot_rate.url'),
                                        '$.rate_info.foreign_exchange_rate',    getJval(v_rate_json, 'spot_rate.foreign_exchange_rate'),
                                        '$.rate_info.foreign_exchange_source',  getJval(v_rate_json, 'spot_rate.foreign_exchange_source')
                                    );

            /* ---------------------------------------------------------------
            SLICE: build the single-element buy_items array
            --------------------------------------------------------------- */
            SET v_buy_items_output = JSON_ARRAY(
                                                JSON_OBJECT(
                                                            'asset_code',       v_asset_code,
                                                            'item_code',        v_item_code,
                                                            'item_name',        v_item_name,
                                                            'item_type',        v_item_type,
                                                            'item_quantity',    1,
                                                            'item_weight',      v_item_weight,
                                                            'bought_price',     v_bought_price
                                                        )
                                                );  

                                                     

            /* ------- sub-branch: Market ------- */
            IF v_order_sub_type = 'Market' THEN


                IF isFalsy(getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_AMOUNT')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.amount is required for Market order');
                END IF;

                

                IF isFalsy(getJval(pjReqObj, 'jData.P_ITEM_WEIGHT')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'item_weight is required for Market order');
                END IF;

                IF JSON_LENGTH(v_errors) > 0 THEN
                    
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Validation failed');
                    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.errors', v_errors);

                    LEAVE main_block;
                END IF; 

                SET v_bought_price     = v_spot_rate * v_item_weight;
                
                SET v_buy_items_output = JSON_SET(v_buy_items_output, 
                                                '$[0].bought_price', v_bought_price
                                                );

                SET v_order_cat = 'DO';
                SET v_order_json = JSON_SET(v_order_json,
                                            '$.order_cat',                              v_order_cat,
                                            '$.buy_items',                              v_buy_items_output,            
                                            '$.customer_request.amount',                getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_AMOUNT'),
                                            '$.customer_request.payment_method',        v_cr_payment_method,            
                                            '$.customer_request.date_of_purchase',      DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ')
                                        );

            /* ------- sub-branch: Limit ------- */
            ELSEIF v_order_sub_type = 'Limit' THEN
                /* Set default order_cat to GTC if not provided */
                IF isFalsy(v_order_cat) THEN
                    SET v_order_cat = 'GTC';
                END IF;

                IF isFalsy(getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_RATE')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.rate is required for Limit order');
                END IF;

                IF isFalsy(getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_AMOUNT')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.amount is required for Limit order');
                END IF;

                IF isFalsy(getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_WEIGHT')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.weight is required for Limit order');
                END IF;

                IF isFalsy(getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_EXPIRATION_TIME')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.Expiration_time is required for Limit order');
                END IF;

                IF v_order_cat NOT IN ('GTC','IOC') THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'order_cat must be GTC or IOC for Limit order');
                END IF;

                IF JSON_LENGTH(v_errors) > 0 THEN
                    
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Validation failed');
                    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.errors', v_errors);
                    
                    LEAVE main_block;
                END IF;

                /* Use customer's requested rate for Limit orders */
                SET v_cr_rate       = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_RATE');
                SET v_cr_weight     = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_WEIGHT');

                SET v_bought_price  = v_cr_rate * v_cr_weight;

                -- update rate_info after setting v_cr_rate in Limit branch
                SET v_order_json = JSON_SET(v_order_json,
                    '$.rate_info.customer_requested_rate', v_cr_rate
                );

                /* Update the bought_price in the already-built array */
                SET v_buy_items_output = JSON_SET(v_buy_items_output, 
                                                '$[0].bought_price', v_bought_price,
                                                '$[0].item_weight',  v_cr_weight 
                                                );
                

                SET v_order_json = JSON_SET(v_order_json,
                                            '$.order_cat',                                  v_order_cat,
                                            '$.buy_items',                                  v_buy_items_output,             
                                            '$.customer_request.rate',                      v_cr_rate,          
                                            '$.customer_request.weight',                    v_cr_weight,                    
                                            '$.customer_request.amount',                    getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_AMOUNT'),
                                            '$.customer_request.Expiration_time',           getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_EXPIRATION_TIME'),
                                            '$.customer_request.is_partial_fill_allowed',   getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_IS_PARTIAL_FILL_ALLOWED'),
                                            '$.customer_request.payment_method',            v_cr_payment_method,            
                                            '$.customer_request.date_of_purchase',          DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ')
                                        );

            ELSE

                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Unknown order_sub_type for SLICE. Must be Market or Limit');
                LEAVE main_block;
            END IF;

        ELSEIF v_product_type = 'PRODUCT' THEN  

            /* ---------------------------------------------------------------
            PRODUCT: validate buy_items array is present and non-empty
            --------------------------------------------------------------- */
            SET v_buy_items_input = getJval(pjReqObj, 'jData.P_BUY_ITEMS');

            IF isFalsy(v_buy_items_input) OR JSON_LENGTH(v_buy_items_input) = 0 THEN

                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'buy_items array is required and must not be empty for PRODUCT order');
            
                LEAVE main_block;
            END IF;

            /* ---------------------------------------------------------------
            PRODUCT: loop : validate each item, lookup inventory,
                        calculate bought_price = spot_rate * item_quantity
            --------------------------------------------------------------- */
            SET v_items_count      = JSON_LENGTH(v_buy_items_input);
            SET v_loop_idx         = 0;
            SET v_buy_items_output = JSON_ARRAY();

            IF JSON_LENGTH(v_errors) > 0 THEN
                   
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Validation failed on buy_items');
                    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.errors', v_errors);
                    LEAVE main_block;
            END IF;

            WHILE v_loop_idx < v_items_count DO

            /* Extract current item from input array */
                SET v_single_item   = JSON_EXTRACT(v_buy_items_input, CONCAT('$[', v_loop_idx, ']'));
                SET v_item_code     = getJval(v_single_item, 'P_ITEM_CODE');
                SET v_item_weight   = getJval(v_single_item, 'P_ITEM_WEIGHT');
                SET v_item_quantity = getJval(v_single_item, 'P_ITEM_QUANTITY');

                /* Per-item field validation */
                IF isFalsy(v_item_code) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$',
                        CONCAT('buy_items[', v_loop_idx, '].item_code is required'));
                END IF;

                IF isFalsy(v_item_weight) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$',
                        CONCAT('buy_items[', v_loop_idx, '].item_weight is required'));
                END IF;

                IF isFalsy(v_item_quantity) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$',
                        CONCAT('buy_items[', v_loop_idx, '].item_quantity is required'));
                END IF;
                

                IF JSON_LENGTH(v_errors) > 0 THEN
                    
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Validation failed on buy_items');
                    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.errors', v_errors);

                    LEAVE main_block;
                END IF;

                /* Lookup item_name + item_type from inventory */

                SELECT  inventory_json
                INTO    v_inventory_json
                FROM    inventory
                WHERE   item_code = v_item_code
                LIMIT   1;

                IF isFalsy(v_inventory_json) THEN
                    
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Inventory item not found for item_code: ', v_item_code));
                    
                    LEAVE main_block;
                END IF;

                SET v_item_name    = getJval(v_inventory_json, 'item_name');
                SET v_item_type    = getJval(v_inventory_json, 'item_type');
                SET v_asset_code   = getJval(v_inventory_json, 'asset_code');

            /*  Fetch spot_rate per item based on its own asset_code */
                SELECT   tradable_assets_rec_id,   tradable_assets_json
                INTO     v_tradable_assets_rec_id, v_rate_json
                FROM     tradable_assets
                WHERE    asset_code = v_asset_code
                ORDER BY tradable_assets_rec_id DESC
                LIMIT 1;

                 IF isFalsy(v_rate_json) THEN
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Rate not found for asset_code: ', v_asset_code));
                    LEAVE main_block;
                END IF;

                SET v_spot_rate             = getJval(v_rate_json, 'spot_rate.current_rate');

                /* bought_price = spot_rate * item_weight * item_quantity */
                SET v_bought_price          = v_spot_rate * v_item_weight * v_item_quantity;

                /* Append fully-populated item into output array */
                SET v_buy_items_output = JSON_ARRAY_APPEND( v_buy_items_output,
                                                            '$',
                                                            JSON_OBJECT(
                                                                        'asset_code',       v_asset_code,
                                                                        'item_code',        v_item_code,
                                                                        'item_name',        v_item_name,
                                                                        'item_type',        v_item_type,
                                                                        'item_quantity',    v_item_quantity,
                                                                        'item_weight',      v_item_weight,
                                                                        'spot_rate',        v_spot_rate,
                                                                        'bought_price',     v_bought_price
                                                                        )
                                                        );

                SET v_loop_idx = v_loop_idx + 1;

            END WHILE;

            /*Store a note at order level instead */
            SET v_order_json = JSON_SET(v_order_json,
                                        '$.rate_info',  'See individual buy_items for per-item rate details'
                                        );
            /* ---------------------------------------------------------------
            PRODUCT: merge into order_json
            --------------------------------------------------------------- */
            SET v_order_cat = 'DO';
            SET v_order_json = JSON_SET(v_order_json,
                                        '$.order_cat',                          v_order_cat,
                                        '$.buy_items',                          v_buy_items_output,
                                        '$.customer_request.payment_method',    v_cr_payment_method,
                                        '$.customer_request.date_of_purchase',  DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ'),
                                        '$.customer_request.amount',            getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_AMOUNT')
                                    );

        ELSE
           
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Unknown product_type for Buy. Must be SLICE or PRODUCT');
            LEAVE main_block;
        END IF;


        /* ===================== Step 9.5: Calculate Order Summary ===================== */

        /* --- Calculate totals from buy_items array --- */
        SET v_items_count = JSON_LENGTH(v_buy_items_output);
        SET v_loop_idx = 0;

        WHILE v_loop_idx < v_items_count DO

            SET v_single_item       = JSON_EXTRACT(v_buy_items_output, CONCAT('$[', v_loop_idx, ']'));
            
            SET v_total_buy_items   = v_total_buy_items +  CAST(getJval(v_single_item, 'item_quantity') AS UNSIGNED);
            SET v_total_buy_weight  = v_total_buy_weight + CAST(getJval(v_single_item, 'item_weight')   AS DECIMAL(20,6)) * CAST(getJval(v_single_item, 'item_quantity') AS DECIMAL(20,6));
            SET v_total_buy_amount  = v_total_buy_amount + CAST(getJval(v_single_item, 'bought_price')  AS DECIMAL(20,6));
        
            SET v_loop_idx = v_loop_idx + 1;

        END WHILE;

        /* --- Apply business logic for charges --- */
        
        /* Option 1: Flat fees from config/parameters */
        SET v_transaction_fee    = 100.00;  -- or getJval(pjReqObj, 'jData.P_TRANSACTION_FEE')
        SET v_processing_charges = 50.00;

        /* Option 2: Percentage-based (e.g., 2% making charges) */
        SET v_making_charges = v_total_buy_amount * 0.02;

        /* Option 3: Weight-based premium (e.g., 50 PKR per gram) */
        SET v_premium_charged = v_total_buy_weight * 50;

        /* Option 4: Tax calculation (e.g., 5% GST) */
        SET v_taxes = v_total_buy_amount * 0.05;

        /* Apply discounts if any */
        SET v_total_discounts = COALESCE(getJval(pjReqObj, 'jData.P_DISCOUNT_AMOUNT'), 0);

        /* --- Final total order amount --- */
        SET v_total_order_amount = v_total_buy_amount 
                                    + v_making_charges 
                                    + v_premium_charged 
                                    + v_transaction_fee 
                                    + v_processing_charges 
                                    + v_taxes 
                                    - v_total_discounts;

        /* Now validate */
        IF v_total_order_amount < 0 THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Net Buy amount cannot be negative');
            LEAVE main_block;
        END IF;  
        /* --- Populate order_summary in order_json --- */
        SET v_order_json = JSON_SET(v_order_json,
                                    '$.customer_request.total_qty_to_buy',  v_total_buy_items,
                                    '$.order_summary.total_buy_items',      v_total_buy_items,
                                    '$.order_summary.total_buy_amount',     v_total_buy_amount,
                                    '$.order_summary.total_buy_weight',     v_total_buy_weight,
                                    '$.order_summary.items_total_amount',   v_total_buy_amount,
                                    '$.order_summary.making_charges',       v_making_charges,
                                    '$.order_summary.premium_charged',      v_premium_charged,
                                    '$.order_summary.transaction_fee',      v_transaction_fee,
                                    '$.order_summary.processing_charges',   v_processing_charges,
                                    '$.order_summary.taxes',                v_taxes,
                                    '$.order_summary.taxes_description',    'GST @ 5%',
                                    '$.order_summary.total_discounts',      v_total_discounts,
                                    '$.order_summary.total_order_amount',   v_total_order_amount
                                );

        /* ===================== Step 11: Build Transactions, Update Wallets, Call wallet_activity ============== */

        /*  11.1 : Read customer_wallets array  */
        SET v_wallets_arr   = getJval(v_customer_json, 'customer_wallets');

        IF v_wallets_arr IS NULL OR JSON_LENGTH(v_wallets_arr) = 0 THEN
           
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Customer wallets not found');
            LEAVE main_block;
        END IF;

        SET v_wallet_count  = JSON_LENGTH(v_wallets_arr);

        SET v_metal_wallet_id  = NULL;
        SET v_cash_wallet_id   = NULL;
        SET v_wallet_loop_idx  = 0;

        WHILE v_wallet_loop_idx < v_wallet_count DO

            SET v_wallet_item        = JSON_EXTRACT(v_wallets_arr, CONCAT('$[', v_wallet_loop_idx, ']'));
            SET v_wallet_asset_code  = getJval(v_wallet_item, 'asset_code');
            SET v_wallet_type        = getJval(v_wallet_item, 'wallet_type');

            /* Match METAL wallet by asset_code (e.g. GLD matches v_asset_code) */
            IF v_wallet_asset_code = v_asset_code AND v_wallet_type = 'METAL' THEN
                SET v_metal_wallet_id          = getJval(v_wallet_item, 'wallet_id');
                SET v_metal_balance_before     = COALESCE( CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);
            END IF;

            /* Match CASH wallet by wallet_type */
            IF v_wallet_type = 'CASH' THEN
                SET v_cash_wallet_id            = getJval(v_wallet_item, 'wallet_id');
                SET v_cash_balance_before       = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);
            END IF;

            SET v_wallet_loop_idx               = v_wallet_loop_idx + 1;

        END WHILE;

        /* ---- 11.2 : Guard - wallets must exist ---- */
        IF v_product_type != 'PRODUCT' AND isFalsy(v_metal_wallet_id) THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Metal wallet not found for asset_code', ' ', v_asset_code));
            LEAVE main_block;
        END IF;

        IF isFalsy(v_cash_wallet_id) THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Cash wallet not found for customer', ' ', v_account_number));
            LEAVE main_block;
        END IF;

        /* ---- 11.3 : Calculate transaction amounts ---- */

        /* Metal credit = already calculated in order summary (only for SLICE) */
        IF v_product_type != 'PRODUCT' THEN
            SET v_metal_txn_amount = v_total_buy_weight;
        ELSE
            SET v_metal_txn_amount = 0;
        END IF;

        /* Cash debit = total_order_amount from order_summary */
        SET v_cash_txn_amount    = v_total_order_amount;

        /* ---- 11.4 : Calculate balances after ---- */
        IF v_product_type != 'PRODUCT' THEN
            SET v_metal_balance_after = v_metal_balance_before + v_metal_txn_amount;
        END IF;
        SET v_cash_balance_after  = v_cash_balance_before  - v_cash_txn_amount;

        /* ---- 11.4b : Guard - insufficient cash balance ---- */
        IF v_cash_balance_after < 0 THEN
           
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Insufficient cash balance', ' ','balance: ', v_cash_balance_before, ', transaction amount: ', v_cash_txn_amount));
            LEAVE main_block;
        END IF;

        /* ---- 11.5 : Generate transaction numbers for each leg ---- */
        CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createBuyOrder', v_txn_num_credit);
        CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createBuyOrder', v_txn_num_debit);

        /* ---- 11.6 : Build transactions array ---- */
        IF v_product_type = 'PRODUCT' THEN
            SET v_transactions_output = JSON_ARRAY(
                /* TXN-B : Cash DEBIT */
                JSON_OBJECT(
                            'transaction_num',      v_txn_num_debit,
                            'transaction_type',     'Debit',
                            'wallet_type',          'Cash',
                            "asset_code",           'CSH',
                            'wallet_id',            v_cash_wallet_id,
                            'balance_before',       v_cash_balance_before,
                            'transaction_amount',   v_cash_txn_amount,
                            'balance_after',        v_cash_balance_after
                        )
            );
        ELSE
            SET v_transactions_output = JSON_ARRAY(
                /* TXN-A : Metal CREDIT */
                JSON_OBJECT(
                            'transaction_num',      v_txn_num_credit,
                            'transaction_type',     'Credit',
                            'wallet_type',          'Metal',
                            "asset_code",           v_asset_code,
                            'wallet_id',            v_metal_wallet_id,
                            'balance_before',       v_metal_balance_before,
                            'transaction_amount',   v_metal_txn_amount,
                            'balance_after',        v_metal_balance_after
                        ),
                /* TXN-B : Cash DEBIT */
                JSON_OBJECT(
                            'transaction_num',      v_txn_num_debit,
                            'transaction_type',     'Debit',
                            'wallet_type',          'Cash',
                            "asset_code",           'CSH',
                            'wallet_id',            v_cash_wallet_id,
                            'balance_before',       v_cash_balance_before,
                            'transaction_amount',   v_cash_txn_amount,
                            'balance_after',        v_cash_balance_after
                        )
            );
        END IF;

        /* ===================== Step 10: INSERT into orders table ===================== */
        
            INSERT INTO orders
                SET customer_rec_id         = v_customer_rec_id,
                    account_number          = v_account_number,
                    order_number            = v_order_number,
                    receipt_number          = v_receipt_number,
                    order_date              = v_order_date,
                    order_status            = v_order_status,
                    next_action_required    = v_next_action_required,
                    order_cat               = v_order_cat,
                    order_type              = v_order_type,
                    limit_or_market         = v_order_sub_type,
                    metal                   = v_metal,
                    order_json              = v_order_json,
                    row_metadata            = v_row_metadata;

            SET v_order_rec_id = LAST_INSERT_ID();

            SET v_order_json = JSON_SET(v_order_json, '$.order_rec_id', v_order_rec_id);

            /* ---- 11.7 : Write transactions into order_json and persist ---- */
            SET v_order_json = JSON_SET(v_order_json, '$.transactions', v_transactions_output);

            UPDATE  orders
            SET     order_json   = v_order_json
            WHERE   order_rec_id = v_order_rec_id;

        /* ---- 11.8 : Call wallet_activity - METAL CREDIT (only for SLICE) ---- */
        IF v_product_type != 'PRODUCT' THEN
            CALL wallet_activity(
                                    v_customer_rec_id,
                                    v_metal_wallet_id,
                                    'CREDIT',
                                    v_metal_txn_amount,
                                    CONCAT('Buy order credited: ', v_order_number),
                                    v_order_rec_id,
                                    v_order_number,
                                    v_txn_num_credit
                                );
        END IF;

        /* ---- 11.9 : Call wallet_activity - CASH DEBIT ---- */
        CALL wallet_activity(
                                v_customer_rec_id,
                                v_cash_wallet_id,
                                'DEBIT',
                                v_cash_txn_amount,
                                CONCAT('Buy order debited: ', v_order_number),
                                v_order_rec_id,
                                v_order_number,
                                v_txn_num_debit
                                );

        /* ---- 11.10 : Update customer_products for PRODUCT orders ---- */
        IF v_product_type = 'PRODUCT' THEN

            -- Loop through buy_items and append to customer_products
            SET v_items_count = JSON_LENGTH(v_buy_items_output);
            SET v_loop_idx = 0;
            
            WHILE v_loop_idx < v_items_count DO

                SET v_single_item             = JSON_EXTRACT(v_buy_items_output, CONCAT('$[', v_loop_idx, ']'));

                SET v_customer_products_json  = JSON_ARRAY_APPEND(v_customer_products_json, '$', 
                                                                JSON_OBJECT(
                                                                                'asset_code',           getJVal(v_single_item, 'asset_code'),
                                                                                'product_name',         getJVal(v_single_item, 'item_name'),
                                                                                'product_type',         getJVal(v_single_item, 'item_type'),
                                                                                'product_price',        getJVal(v_single_item, 'bought_price'),
                                                                                'product_weight',       getJVal(v_single_item, 'item_weight'),
                                                                                'status',               'Not Picked up',
                                                                                'product_quantity',     getJVal(v_single_item, 'item_quantity'),
                                                                                'order_rec_id',         v_order_rec_id,
                                                                                'customer_rec_id',      v_customer_rec_id,
                                                                                'purchase_date',        DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ'),
                                                                                'item_code',            getJval(v_single_item, 'item_code')
                                                                            )
                                                                );

                    SET v_loop_idx = v_loop_idx + 1;

            END WHILE;

        INSERT INTO customer_products
        SET customer_rec_id         = v_customer_rec_id,
            order_rec_id            = v_order_rec_id,
            order_type              = v_order_type,
            status                  = 'Not Picked up',
            customer_products_json  = v_customer_products_json,
            row_metadata            = v_row_metadata;
        END IF;

        /* ===================== Step 12: Success Response ===================== */
 
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 	0);
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',    CONCAT('Buy order created successfully for order number: ', v_order_number));

        END main_block;



    END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `createExchangeOrder` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `createExchangeOrder`(
                                        IN      pjReqObj     JSON,
                                        INOUT   pjRespObj    JSON
                                    )
BEGIN

    /* ===================== Variables ===================== */
    DECLARE v_customer_rec_id               INT;
    DECLARE v_account_number                VARCHAR(50);
    DECLARE v_order_rec_id                  INT;
    DECLARE v_order_number                  VARCHAR(50);
    DECLARE v_receipt_number                VARCHAR(50);
    DECLARE v_order_date                    DATETIME;
    DECLARE v_order_status                  VARCHAR(20);
    DECLARE v_next_action_required          VARCHAR(20);
    DECLARE v_order_cat                     VARCHAR(10);
    DECLARE v_order_type                    VARCHAR(20);

    /* From (Sell) side */
    DECLARE v_from_asset_code               VARCHAR(10);
    DECLARE v_from_metal                    VARCHAR(50);
    DECLARE v_from_item_code                VARCHAR(50);
    DECLARE v_from_item_name                VARCHAR(100);
    DECLARE v_from_item_type                VARCHAR(50);
    DECLARE v_from_weight                   DECIMAL(18,6);
    DECLARE v_from_spot_rate                DECIMAL(18,6);
    DECLARE v_sold_price                    DECIMAL(18,2);
    DECLARE v_from_tradable_assets_rec_id   INT;
    DECLARE v_from_rate_json                JSON;
    DECLARE v_from_inventory_json           JSON;
    DECLARE v_sell_items_output             JSON;

    /* To (Buy) side */
    DECLARE v_to_asset_code                 VARCHAR(10);
    DECLARE v_to_metal                      VARCHAR(50);
    DECLARE v_to_item_code                  VARCHAR(50);
    DECLARE v_to_item_name                  VARCHAR(100);
    DECLARE v_to_item_type                  VARCHAR(50);
    DECLARE v_to_weight                     DECIMAL(18,6);
    DECLARE v_to_spot_rate                  DECIMAL(18,6);
    DECLARE v_bought_price                  DECIMAL(18,2);
    DECLARE v_to_tradable_assets_rec_id     INT;
    DECLARE v_to_rate_json                  JSON;
    DECLARE v_to_inventory_json             JSON;
    DECLARE v_buy_items_output              JSON;

    /* Customer & order JSON */
    DECLARE v_customer_json                 JSON;
    DECLARE v_order_json                    JSON;
    DECLARE v_row_metadata                  JSON;

    /* Order Summary */
    DECLARE v_total_sell_items              INT DEFAULT 0;
    DECLARE v_total_sell_amount             DECIMAL(20,6) DEFAULT 0;
    DECLARE v_total_sell_weight             DECIMAL(20,6) DEFAULT 0;
    DECLARE v_total_buy_items               INT DEFAULT 0;
    DECLARE v_total_buy_amount              DECIMAL(20,6) DEFAULT 0;
    DECLARE v_total_buy_weight              DECIMAL(20,6) DEFAULT 0;
    DECLARE v_making_charges                DECIMAL(20,6) DEFAULT 0;
    DECLARE v_premium_charged               DECIMAL(20,6) DEFAULT 0;
    DECLARE v_transaction_fee               DECIMAL(20,6) DEFAULT 0;
    DECLARE v_processing_charges            DECIMAL(20,6) DEFAULT 0;
    DECLARE v_taxes                         DECIMAL(20,6) DEFAULT 0;
    DECLARE v_total_discounts               DECIMAL(20,6) DEFAULT 0;
    DECLARE v_total_order_amount            DECIMAL(20,6) DEFAULT 0;
    DECLARE v_items_total_amount            DECIMAL(20,6) DEFAULT 0;

    /* Wallet variables */
    DECLARE v_txn_num_debit                 VARCHAR(50);
    DECLARE v_txn_num_credit                VARCHAR(50);
    DECLARE v_txn_num_cash_debit            VARCHAR(50);
    DECLARE v_txn_num_cash_credit           VARCHAR(50);   /* Sell leg cash credit txn number  */
    DECLARE v_transactions_output           JSON;

    DECLARE v_from_wallet_id                VARCHAR(100);
    DECLARE v_from_balance_before           DECIMAL(20,6);
    DECLARE v_from_balance_after            DECIMAL(20,6);
    DECLARE v_from_txn_amount               DECIMAL(20,6);

    DECLARE v_to_wallet_id                  VARCHAR(100);
    DECLARE v_to_balance_before             DECIMAL(20,6);
    DECLARE v_to_balance_after              DECIMAL(20,6);
    DECLARE v_to_txn_amount                 DECIMAL(20,6);

    DECLARE v_cash_wallet_id                VARCHAR(100);
    DECLARE v_cash_balance_before           DECIMAL(20,6);
    DECLARE v_cash_balance_after            DECIMAL(20,6);
    DECLARE v_cash_txn_amount               DECIMAL(20,6);
    DECLARE v_cash_credit_txn_amount        DECIMAL(20,6);  /* NEW: Sell leg cash credit amount = v_sold_price     */
    DECLARE v_cash_after_sell_credit        DECIMAL(20,6);  /* NEW: Intermediate balance after sell credit leg     */

    DECLARE v_wallets_arr                   JSON;
    DECLARE v_wallet_loop_idx               INT DEFAULT 0;
    DECLARE v_wallet_count                  INT DEFAULT 0;
    DECLARE v_wallet_item                   JSON;
    DECLARE v_wallet_asset_code             VARCHAR(20);
    DECLARE v_wallet_type                   VARCHAR(20);

    DECLARE v_errors                        JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg                       VARCHAR(500);

    /* ===================== Error Handler ===================== */
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
        ROLLBACK;

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Insertion failed: ', v_err_msg));

    END;

main_block: BEGIN

    /* ===================== Step 1: Extract Request Values ===================== */
    SET v_order_type        = 'Exchange';
    SET v_account_number    = getJval(pjReqObj, 'jData.P_ACCOUNT_NUMBER');
    SET v_from_asset_code   = getJval(pjReqObj, 'jData.P_FROM_ASSET_CODE');
    SET v_to_asset_code     = getJval(pjReqObj, 'jData.P_TO_ASSET_CODE');
    SET v_from_metal        = getJval(pjReqObj, 'jData.P_FROM_METAL');
    SET v_to_metal          = getJval(pjReqObj, 'jData.P_TO_METAL');
    SET v_from_item_code    = getJval(pjReqObj, 'jData.P_FROM_ITEM_CODE');
    SET v_to_item_code      = getJval(pjReqObj, 'jData.P_TO_ITEM_CODE');
    SET v_from_weight       = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_FROM_WEIGHT');
    SET v_to_weight         = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_TO_WEIGHT');

    /* ===================== Step 2: Validations ===================== */
    IF isFalsy(v_account_number) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'account_number is required');
    END IF;

    IF isFalsy(v_from_asset_code) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'from_asset_code is required');
    END IF;

    IF isFalsy(v_to_asset_code) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'to_asset_code is required');
    END IF;

    IF isFalsy(v_from_metal) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'from_metal is required');
    END IF;

    IF isFalsy(v_to_metal) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'to_metal is required');
    END IF;

    IF isFalsy(v_from_item_code) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'from_item_code is required');
    END IF;

    IF isFalsy(v_to_item_code) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'to_item_code is required');
    END IF;

    IF isFalsy(v_from_weight) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.from_weight is required');
    END IF;

    IF isFalsy(v_to_weight) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.to_weight is required');
    END IF;

    /* Guard: cannot exchange same asset into itself */
    IF v_from_asset_code = v_to_asset_code THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'from_asset_code and to_asset_code must be different');
    END IF;

    IF JSON_LENGTH(v_errors) > 0 THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Validations failed');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.errors',     v_errors);

        LEAVE main_block;
    END IF;

    /* ===================== Step 3: Fetch Customer Record ===================== */
    SELECT  customer_rec_id
    INTO    v_customer_rec_id
    FROM    customer
    WHERE   account_num = v_account_number
    LIMIT 1;

    IF isFalsy(v_customer_rec_id) THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Customer not found');

        LEAVE main_block;
    END IF;

    SET v_customer_json = getCustomer(v_customer_rec_id);

    IF isFalsy(v_customer_json) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Customer not found for account number: ', v_account_number));

        LEAVE main_block;
    END IF;

    /* ===================== Step 4: Fetch Rates for Both Assets ===================== */

    /* --- FROM asset rate --- */
    SELECT   tradable_assets_rec_id,         tradable_assets_json
    INTO     v_from_tradable_assets_rec_id,  v_from_rate_json
    FROM     tradable_assets
    WHERE    asset_code = v_from_asset_code
    ORDER BY tradable_assets_rec_id DESC
    LIMIT 1;

    IF isFalsy(v_from_rate_json) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Rate not found for from_asset_code: ', v_from_asset_code));

        LEAVE main_block;
    END IF;

    SET v_from_spot_rate = getJval(v_from_rate_json, 'spot_rate.current_rate');

    /* --- TO asset rate --- */
    SELECT   tradable_assets_rec_id,         tradable_assets_json
    INTO     v_to_tradable_assets_rec_id,    v_to_rate_json
    FROM     tradable_assets
    WHERE    asset_code = v_to_asset_code
    ORDER BY tradable_assets_rec_id DESC
    LIMIT 1;

    IF isFalsy(v_to_rate_json) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Rate not found for to_asset_code: ', v_to_asset_code));

        LEAVE main_block;
    END IF;

    SET v_to_spot_rate = getJval(v_to_rate_json, 'spot_rate.current_rate');

    /* ===================== Step 5: Generate Order & Receipt Numbers ===================== */
    CALL getSequence('ORDERS.ORDER_NUM',   NULL,    3000, 'createExchangeOrder', v_order_number);
    CALL getSequence('ORDERS.RECEIPT_NUM', 'RECP-', 3000, 'createExchangeOrder', v_receipt_number);

    /* ===================== Step 6: Set Common Order Header Values ===================== */
    SET v_order_date            = NOW();
    SET v_order_status          = 'Pending';
    SET v_next_action_required  = 'approval';
    SET v_order_cat             = 'DO';

    /* ===================== Step 7: Load Order Template & Row Metadata ===================== */
    SET v_order_json            = getTemplate('orders');
    SET v_row_metadata          = getTemplate('row_metadata');

    SET v_row_metadata = JSON_SET(v_row_metadata,
                                    '$.status',     v_order_status,
                                    '$.created_at', DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
                                    '$.created_by', CONCAT(
                                                            getJval(v_customer_json, 'first_name'),
                                                            ' ',
                                                            getJval(v_customer_json, 'last_name'),
                                                            ' Customer Self-Service'
                                                        )
                                );

    /* ===================== Step 8: Populate Customer, Rate Info & Top-Level Fields ===================== */
    SET v_order_json = JSON_SET(v_order_json,
                                '$.customer_info.customer_rec_id',          v_customer_rec_id,
                                '$.customer_info.customer_name',            CONCAT(getJval(v_customer_json, 'first_name'), ' ', getJval(v_customer_json, 'last_name')),
                                '$.customer_info.customer_account_number',  getJval(v_customer_json, 'main_account_number'),
                                '$.customer_info.customer_phone',           getJval(v_customer_json, 'phone'),
                                '$.customer_info.whatsapp',                 getJval(v_customer_json, 'whatsapp'),
                                '$.customer_info.customer_email',           getJval(v_customer_json, 'email'),
                                '$.customer_info.customer_address',         getJval(v_customer_json, 'residential_address'),
                                '$.customer_info.customer_ip_address',      getJval(pjReqObj,        'jData.P_CUSTOMER_IP_ADDRESS'),
                                '$.customer_info.latitude',                 getJval(pjReqObj,        'jData.P_LATITUDE'),
                                '$.customer_info.longitude',                getJval(pjReqObj,        'jData.P_LONGITUDE'),
                                '$.customer_info.notes',                    getJval(pjReqObj,        'jData.P_NOTES'),

                                /* Store both rate records - from and to */
                                '$.rate_info.from_rate_rec_id',             v_from_tradable_assets_rec_id,
                                '$.rate_info.from_spot_rate',               v_from_spot_rate,
                                '$.rate_info.from_currency_unit',           getJval(v_from_rate_json, 'spot_rate.currency'),
                                '$.rate_info.from_rate_source',             getJval(v_from_rate_json, 'spot_rate.url'),
                                '$.rate_info.from_foreign_exchange_rate',   getJval(v_from_rate_json, 'spot_rate.foreign_exchange_rate'),
                                '$.rate_info.from_foreign_exchange_source', getJval(v_from_rate_json, 'spot_rate.foreign_exchange_source'),

                                '$.rate_info.to_rate_rec_id',               v_to_tradable_assets_rec_id,
                                '$.rate_info.to_spot_rate',                 v_to_spot_rate,
                                '$.rate_info.to_currency_unit',             getJval(v_to_rate_json, 'spot_rate.currency'),
                                '$.rate_info.to_rate_source',               getJval(v_to_rate_json, 'spot_rate.url'),
                                '$.rate_info.to_foreign_exchange_rate',     getJval(v_to_rate_json, 'spot_rate.foreign_exchange_rate'),
                                '$.rate_info.to_foreign_exchange_source',   getJval(v_to_rate_json, 'spot_rate.foreign_exchange_source'),

                                '$.customer_rec_id',                        v_customer_rec_id,
                                '$.account_number',                         v_account_number,
                                '$.order_number',                           v_order_number,
                                '$.receipt_number',                         v_receipt_number,
                                '$.order_date',                             DATE_FORMAT(v_order_date, '%Y-%m-%dT%H:%i:%sZ'),
                                '$.order_status',                           v_order_status,
                                '$.next_action_required',                   v_next_action_required,
                                '$.order_type',                             v_order_type,
                                '$.order_cat',                              v_order_cat,
                                '$.limit_or_market',                        NULL,
                                '$.metal',                                  CONCAT(v_from_metal, ' to ', v_to_metal)
                            );

    /* ===================== Step 9: Lookup Inventory & Build sell_items / buy_items ===================== */

    /* --- FROM side: inventory lookup for sell_items --- */
    SELECT  inventory_json
    INTO    v_from_inventory_json
    FROM    inventory
    WHERE   item_code = v_from_item_code
    LIMIT 1;

    IF isFalsy(v_from_inventory_json) THEN
       
       SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
       SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Inventory item not found for from_item_code: ', v_from_item_code));
    
        LEAVE main_block;
    END IF;

    SET v_from_item_name    = getJval(v_from_inventory_json, 'item_name');
    SET v_from_item_type    = getJval(v_from_inventory_json, 'item_type');
    SET v_sold_price        = v_from_spot_rate * v_from_weight;

    SET v_sell_items_output = JSON_ARRAY(
                                            JSON_OBJECT(
                                                        'item_code',        v_from_item_code,
                                                        'item_name',        v_from_item_name,
                                                        'item_type',        v_from_item_type,
                                                        'item_quantity',    1,
                                                        'item_weight',      v_from_weight,
                                                        'sold_price',       v_sold_price
                                                    )
                                        );

    /* --- TO side: inventory lookup for buy_items --- */
    SELECT  inventory_json
    INTO    v_to_inventory_json
    FROM    inventory
    WHERE   item_code = v_to_item_code
    LIMIT 1;

    IF isFalsy(v_to_inventory_json) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Inventory item not found for to_item_code: ', v_to_item_code));

        LEAVE main_block;
    END IF;

    SET v_to_item_name  = getJval(v_to_inventory_json, 'item_name');
    SET v_to_item_type  = getJval(v_to_inventory_json, 'item_type');
    SET v_bought_price  = v_to_spot_rate * v_to_weight;

    SET v_buy_items_output = JSON_ARRAY(
                                            JSON_OBJECT(
                                                        'item_code',        v_to_item_code,
                                                        'item_name',        v_to_item_name,
                                                        'item_type',        v_to_item_type,
                                                        'item_quantity',    1,
                                                        'item_weight',      v_to_weight,
                                                        'bought_price',     v_bought_price
                                                    )
                                        );

    /* Merge both item arrays into order_json */
    SET v_order_json = JSON_SET(v_order_json,
                                '$.sell_items',                             v_sell_items_output,
                                '$.buy_items',                              v_buy_items_output,
                                '$.customer_request.from_weight',           v_from_weight,
                                '$.customer_request.to_weight',             v_to_weight,
                                '$.customer_request.date_of_purchase',      DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ')
                            );

    /* ===================== Step 9.5: Calculate Order Summary ===================== */

    /* Sell side totals (single item, quantity = 1) */
    SET v_total_sell_items  = 1;
    SET v_total_sell_weight = v_from_weight;
    SET v_total_sell_amount = v_sold_price;

    /* Buy side totals (single item, quantity = 1) */
    SET v_total_buy_items   = 1;
    SET v_total_buy_weight  = v_to_weight;
    SET v_total_buy_amount  = v_bought_price;

    /* items_total_amount: value of what is being received (to side) */
    SET v_items_total_amount = v_total_buy_amount;

    /* Charges - mirroring createBuyOrder structure */
    SET v_transaction_fee    = 100.00;
    SET v_processing_charges = 50.00;
    SET v_making_charges     = v_items_total_amount * 0.02;
    SET v_premium_charged    = v_total_buy_weight   * 50;
    SET v_taxes              = v_items_total_amount * 0.05;
    SET v_total_discounts    = COALESCE(getJval(pjReqObj, 'jData.P_DISCOUNT_AMOUNT'), 0);

    /* Total charges only (fees + taxes - discounts) */
    SET v_total_order_amount =   v_making_charges
                               + v_premium_charged
                               + v_transaction_fee
                               + v_processing_charges
                               + v_taxes
                               - v_total_discounts;

    IF v_total_order_amount < 0 THEN
        SET pjRespObj = JSON_OBJECT(
                                    'status',       'error',
                                    'status_code',  '10',
                                    'message',      'Net exchange amount cannot be negative'
                                );
        LEAVE main_block;
    END IF;

    SET v_order_json = JSON_SET(v_order_json,
                                '$.customer_request.total_qty_to_sell', v_total_sell_items,
                                '$.customer_request.total_qty_to_buy',  v_total_buy_items,
                                '$.order_summary.total_sell_items',     v_total_sell_items,
                                '$.order_summary.total_sell_amount',    v_total_sell_amount,
                                '$.order_summary.total_sell_weight',    v_total_sell_weight,
                                '$.order_summary.total_buy_items',      v_total_buy_items,
                                '$.order_summary.total_buy_amount',     v_total_buy_amount,
                                '$.order_summary.total_buy_weight',     v_total_buy_weight,
                                '$.order_summary.items_total_amount',   v_items_total_amount,
                                '$.order_summary.making_charges',       v_making_charges,
                                '$.order_summary.premium_charged',      v_premium_charged,
                                '$.order_summary.transaction_fee',      v_transaction_fee,
                                '$.order_summary.processing_charges',   v_processing_charges,
                                '$.order_summary.taxes',                v_taxes,
                                '$.order_summary.taxes_description',    'GST @ 5%',
                                '$.order_summary.total_discounts',      v_total_discounts,
                                '$.order_summary.total_order_amount',   v_total_order_amount
                            );

    /* ===================== Step 11: Wallet Processing ===================== */

    /* 11.1: Read customer_wallets array */
    SET v_wallets_arr = getJval(v_customer_json, 'customer_wallets');
     CALL debugLog('customer_wallets', v_wallets_arr);

    IF v_wallets_arr IS NULL OR JSON_LENGTH(v_wallets_arr) = 0 THEN
       
       SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
       SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Customer wallets not found');

        LEAVE main_block;
    END IF;

    SET v_wallet_count      = JSON_LENGTH(v_wallets_arr);
    SET v_from_wallet_id    = NULL;
    SET v_to_wallet_id      = NULL;
    SET v_wallet_loop_idx   = 0;

    WHILE v_wallet_loop_idx < v_wallet_count DO

        SET v_wallet_item       = JSON_EXTRACT(v_wallets_arr, CONCAT('$[', v_wallet_loop_idx, ']'));
        SET v_wallet_asset_code = getJval(v_wallet_item, 'asset_code');
        SET v_wallet_type       = getJval(v_wallet_item, 'wallet_type');

        /* Match FROM metal wallet */
        IF v_wallet_asset_code = v_from_asset_code AND v_wallet_type = 'METAL' THEN
            SET v_from_wallet_id        = getJval(v_wallet_item, 'wallet_id');
            SET v_from_balance_before   = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);
        END IF;

        /* Match TO metal wallet */
        IF v_wallet_asset_code = v_to_asset_code AND v_wallet_type = 'METAL' THEN
            SET v_to_wallet_id          = getJval(v_wallet_item, 'wallet_id');
            SET v_to_balance_before     = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);
        END IF;

        /* Match CASH wallet */
        IF v_wallet_type = 'CASH' THEN
            SET v_cash_wallet_id        = getJval(v_wallet_item, 'wallet_id');
            SET v_cash_balance_before   = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);
        END IF;

        SET v_wallet_loop_idx = v_wallet_loop_idx + 1;

    END WHILE;

    /* 11.2: Guard - both metal wallets and cash wallet must exist */
    IF isFalsy(v_from_wallet_id) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Metal wallet not found for from_asset_code: ', v_from_asset_code));

        LEAVE main_block;
    END IF;

    IF isFalsy(v_to_wallet_id) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Metal wallet not found for to_asset_code: ', v_to_asset_code));

        LEAVE main_block;
    END IF;

    IF isFalsy(v_cash_wallet_id) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Cash wallet not found for customer: ', v_account_number));

        LEAVE main_block;
    END IF;

    /* 11.3: Transaction amounts
       -----------------------------------------------------------------
       TXN-A  FROM metal DEBIT   : weight leaving from_metal wallet
       TXN-B  Cash     CREDIT    : sell proceeds (sold_price) entering cash wallet
       TXN-C  TO metal CREDIT    : weight entering to_metal wallet
       TXN-D  Cash     DEBIT     : buy cost (bought_price) + charges leaving cash wallet
       ----------------------------------------------------------------- */
    SET v_from_txn_amount        = v_from_weight;                          /* metal weight out            */
    SET v_to_txn_amount          = v_to_weight;                            /* metal weight in             */
    SET v_cash_credit_txn_amount = v_sold_price;                           /* cash in  (sell proceeds)    */
    SET v_cash_txn_amount        = v_bought_price + v_total_order_amount;  /* cash out (buy cost+charges) */

    /* 11.4: Compute all balances after
       Intermediate state after sell-credit is stored in v_cash_after_sell_credit
       so TXN-D can use it as its balance_before, giving a clean audit trail. */
    SET v_from_balance_after     = v_from_balance_before  - v_from_txn_amount;
    SET v_to_balance_after       = v_to_balance_before    + v_to_txn_amount;
    SET v_cash_after_sell_credit = v_cash_balance_before  + v_cash_credit_txn_amount;  /* after TXN-B */
    SET v_cash_balance_after     = v_cash_after_sell_credit - v_cash_txn_amount;        /* after TXN-D */

    /* 11.4b: Guard - insufficient from_metal balance */
    IF v_from_balance_after < 0 THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Insufficient metal balance for exchange. balance: ', v_from_balance_before, ', required: ', v_from_txn_amount));

        LEAVE main_block;
    END IF;

    /* 11.4c: Guard - insufficient cash balance after netting sell credit against buy debit */
    IF v_cash_balance_after < 0 THEN
      
      SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
      SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Insufficient cash balance to cover exchange. balance: ', v_cash_balance_before, ', sell credit: ', v_cash_credit_txn_amount, ', buy debit: ', v_cash_txn_amount));

      LEAVE main_block;
    END IF;

    /* 11.5: Generate transaction numbers - one per leg */
    CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createExchangeOrder', v_txn_num_debit);        /* TXN-A */
    CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createExchangeOrder', v_txn_num_cash_credit);  /* TXN-B */
    CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createExchangeOrder', v_txn_num_credit);       /* TXN-C */
    CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createExchangeOrder', v_txn_num_cash_debit);   /* TXN-D */

    /* 11.6: Build transactions array - four legs in execution order */
    SET v_transactions_output = JSON_ARRAY(

        /* TXN-A : FROM metal DEBIT (Sell leg - metal out) */
        JSON_OBJECT(
                    'transaction_num',      v_txn_num_debit,
                    'transaction_type',     'Debit',
                    'wallet_type',          'Metal',
                    'asset_code',           v_from_asset_code,
                    'wallet_id',            v_from_wallet_id,
                    'balance_before',       v_from_balance_before,
                    'transaction_amount',   v_from_txn_amount,
                    'balance_after',        v_from_balance_after
                ),

        /* TXN-B : Cash CREDIT (Sell leg - proceeds in) */
        JSON_OBJECT(
                    'transaction_num',      v_txn_num_cash_credit,
                    'transaction_type',     'Credit',
                    'wallet_type',          'Cash',
                    'asset_code',           'CSH',
                    'wallet_id',            v_cash_wallet_id,
                    'balance_before',       v_cash_balance_before,
                    'transaction_amount',   v_cash_credit_txn_amount,
                    'balance_after',        v_cash_after_sell_credit
                ),

        /* TXN-C : TO metal CREDIT (Buy leg - metal in) */
        JSON_OBJECT(
                    'transaction_num',      v_txn_num_credit,
                    'transaction_type',     'Credit',
                    'wallet_type',          'Metal',
                    'asset_code',           v_to_asset_code,
                    'wallet_id',            v_to_wallet_id,
                    'balance_before',       v_to_balance_before,
                    'transaction_amount',   v_to_txn_amount,
                    'balance_after',        v_to_balance_after
                ),

        /* TXN-D : Cash DEBIT (Buy leg - bought_price + charges out) */
        JSON_OBJECT(
                    'transaction_num',      v_txn_num_cash_debit,
                    'transaction_type',     'Debit',
                    'wallet_type',          'Cash',
                    'asset_code',           'CSH',
                    'wallet_id',            v_cash_wallet_id,
                    'balance_before',       v_cash_after_sell_credit,
                    'transaction_amount',   v_cash_txn_amount,
                    'balance_after',        v_cash_balance_after
                )
    );

    /* ===================== Step 10: INSERT into orders table ===================== */
    INSERT INTO orders
        SET customer_rec_id         = v_customer_rec_id,
            account_number          = v_account_number,
            order_number            = v_order_number,
            receipt_number          = v_receipt_number,
            order_date              = v_order_date,
            order_status            = v_order_status,
            next_action_required    = v_next_action_required,
            order_cat               = v_order_cat,
            order_type              = v_order_type,
            limit_or_market         = NULL,
            metal                   = CONCAT(v_from_metal, ' to ', v_to_metal),
            order_json              = v_order_json,
            row_metadata            = v_row_metadata;

    SET     v_order_rec_id          = LAST_INSERT_ID();

    SET v_order_json = JSON_SET(v_order_json, '$.order_rec_id', v_order_rec_id);

    /* 11.7: Write transactions into order_json and persist */
    SET v_order_json = JSON_SET(v_order_json, '$.transactions', v_transactions_output);

    UPDATE  orders
    SET     order_json   = v_order_json
    WHERE   order_rec_id = v_order_rec_id;

    /* 11.8: wallet_activity - TXN-A: FROM metal DEBIT (Sell leg) */
    CALL wallet_activity(
                            v_customer_rec_id,
                            v_from_wallet_id,
                            'DEBIT',
                            v_from_txn_amount,
                            CONCAT('Exchange sell leg metal debited (', v_from_asset_code, '): ', v_order_number),
                            v_order_rec_id,
                            v_order_number,
                            v_txn_num_debit
                        );

    /* 11.9: wallet_activity - TXN-B: Cash CREDIT (Sell leg proceeds) */
    CALL wallet_activity(
                            v_customer_rec_id,
                            v_cash_wallet_id,
                            'CREDIT',
                            v_cash_credit_txn_amount,
                            CONCAT('Exchange sell leg cash credited (', v_from_asset_code, '): ', v_order_number),
                            v_order_rec_id,
                            v_order_number,
                            v_txn_num_cash_credit
                        );

    /* 11.10: wallet_activity - TXN-C: TO metal CREDIT (Buy leg) */
    CALL wallet_activity(
                            v_customer_rec_id,
                            v_to_wallet_id,
                            'CREDIT',
                            v_to_txn_amount,
                            CONCAT('Exchange buy leg metal credited (', v_to_asset_code, '): ', v_order_number),
                            v_order_rec_id,
                            v_order_number,
                            v_txn_num_credit
                        );

    /* 11.11: wallet_activity - TXN-D: Cash DEBIT (Buy leg cost + charges) */
    CALL wallet_activity(
                            v_customer_rec_id,
                            v_cash_wallet_id,
                            'DEBIT',
                            v_cash_txn_amount,
                            CONCAT('Exchange buy leg cash debited (', v_to_asset_code, '): ', v_order_number),
                            v_order_rec_id,
                            v_order_number,
                            v_txn_num_cash_debit
                        );

    /* ===================== Step 12: Success Response ===================== */
    
    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);
    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',       CONCAT('Exchange order created successfully for order number: ', v_order_number));

END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `createMoneyTransaction` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `createMoneyTransaction`(
										 IN    pjReqObj JSON,
										 INOUT pjRespObj JSON
									   )
BEGIN

	/* =============== Variable Declarations ============= */
    
    DECLARE v_mm_rec_id           		INT;
    DECLARE v_cc_rec_id           		INT;
    DECLARE v_status					VARCHAR(50) 		DEFAULT 'INITIATED';
    DECLARE v_request_type        		VARCHAR(20);							-- deposit | withdraw
    DECLARE v_transaction_type    		VARCHAR(50);							-- Cash Deposit, Bank transfer, Check deposite, e-wallets, credit_card
    DECLARE v_customer_rec_id     		INT;
    
    
    DECLARE v_mm_json          			JSON;
    DECLARE v_cc_json          			JSON;
	DECLARE v_row_metadata           	JSON;
    DECLARE v_customer_json				JSON;
    DECLARE v_trans_life_cycle			JSON;
    
    DECLARE v_errors 					JSON 				DEFAULT JSON_ARRAY();	-- Validation errors
	DECLARE v_err_msg       		    VARCHAR(1000);								-- SQL error message
    
    /* =============== Exception Handler ============= */
    /* Any SQL error will rollback transaction and return error response */
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
		BEGIN
				ROLLBACK;
				GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
				SET pjRespObj       = buildJSONSmart( pjRespObj,  'jHeader.responseCode',   '1');
				SET pjRespObj 	   = buildJSONSmart( pjRespObj,
													'jHeader.message', CONCAT('Unexpected Error - Money manager creation failed', v_err_msg)
													);   
		END;
   
   
    /* =============== Main Logical Block ============= */
	main_block: BEGIN
    
    /* =============== Extract Required Fields ============= */
		SET v_request_type     		= getJval(pjReqObj,'P_REQUEST_TYPE');
		SET v_transaction_type 		= getJval(pjReqObj,'P_TRANSACTION_TYPE');
		SET v_customer_rec_id 		= CAST(getJval(pjReqObj,'P_CUSTOMER_REC_ID') AS UNSIGNED);

    /* =============== Basic Validations ============= */
		IF isFalsy(v_request_type) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','request_type is required');
		END IF;

		IF v_request_type NOT IN ('deposit','withdraw') THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','Invalid request_type');
		END IF;

		IF isFalsy(v_transaction_type) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','transaction_type is required');
		END IF;
        
	 /* =============== Business Rule Validation ============= */
     /* Withdrawal cannot be done via deposit-only transaction types */
		IF v_transaction_type IN ('cash deposit','bank transfer','check deposit','e wallets','credit card') THEN
			
			IF 	v_request_type = 'withdraw' AND 
				v_transaction_type IN ('cash deposit','check deposit','credit card') THEN
			
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','Invalid transaction_type for withdrawal');
			END IF;
			
		END IF;

	 /* =============== Amount Validation ============= */
		IF isFalsy(getJval(pjReqObj,'P_SENDER_INFO.P_AMOUNT_SENT') OR getJval(pjReqObj,'P_RECEIVER_INFO.P_AMOUNT_RECEIVED')) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','amount is required');
			
		ELSEIF CAST(getJval(pjReqObj,'P_SENDER_INFO.P_AMOUNT_SENT') AS DECIMAL(18,2)) 	   <= 0  OR 
			   CAST(getJval(pjReqObj,'P_RECEIVER_INFO.P_AMOUNT_RECEIVED') AS DECIMAL(18,2))  <= 0  THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','amount must be greater than zero');
		
		END IF;

	/* =============== Customer & Account Validation ============= */
		IF isFalsy(v_customer_rec_id) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','customer_rec_id is required');
		END IF;
    
   
	/* =============== Credit Card Specific Validation ============= */
    
		IF v_transaction_type = 'card_info.credit card' THEN
		    IF isFalsy(getJval(pjReqObj,'P_CARD_NUMBER')) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','card_number is required');
			END IF;

			IF isFalsy(getJval(pjReqObj,'P_CARD_INFO.P_CVV2')) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','cvv2 is required');
			END IF;

			IF isFalsy(getJval(pjReqObj,'P_PROCESSOR_NAME')) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','processor_name is required');
			END IF;			
		END IF;
    
	/* =============== Return Validation Errors ============= */
    /* Stop execution if any validation failed */
    
		IF JSON_LENGTH(v_errors) > 0 THEN

			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        v_errors); 

			LEAVE main_block;
		END IF;
        /* =============== All Validations Done ============= */
    
    /* =============== Prepare JSON Templates ============= */
    
		SET v_customer_json			= getCustomer(v_customer_rec_id);    
		SET v_mm_json 				= fillTemplate(pjReqObj,getTemplate('money_manager'));
		SET v_cc_json 				= fillTemplate(pjReqObj, getTemplate('credit_card'));
        SET v_trans_life_cycle		= getTemplate('transaction_life_cycle');
        
		SET v_trans_life_cycle		= JSON_SET(v_trans_life_cycle,
												 "$.status",              v_status,
												 "$.user_name",           getJval(v_customer_json,'user_name'),
												 "$.action_by",           CONCAT(getJval(v_customer_json,'first_name'),
																				 ' ',
																				  getJval(v_customer_json,'last_name')
																				),
												 "$.action_at",           NOW(),
                                                 "$.notes", 			  'Initial setup'
                                                );
											
        
            /* ================ APPEND OBJ in life cycle array in money manager ============ */
		SET v_mm_json	 		= JSON_ARRAY_APPEND( v_mm_json,
														 '$.life_cycle',
														  v_trans_life_cycle
														);
                                                        
                /* ================ APPEND OBJ in life cycle array in credit card ============ */
		SET v_cc_json	 		= JSON_ARRAY_APPEND( v_cc_json,
														 '$.life_cycle',
														  v_trans_life_cycle
														);																
                                             
        
        SET v_row_metadata 			= getTemplate('row_metadata');		
		SET v_row_metadata 			= JSON_SET( v_row_metadata,
												'$.status', 		v_status,
												'$.created_at',		NOW(),
												'$.created_by', 	'createMoneyManager'
											);

  /* =============== Start Transaction ============= */
		START TRANSACTION;

 /* =============== Insert into money_manager ============= */
 
		INSERT INTO money_manager
		SET customer_rec_id			= v_customer_rec_id,
			status					= v_status,
			account_num				= getJval(v_customer_json,'account_number'),
			request_type			= v_request_type,
			transaction_type		= v_transaction_type,
			money_manager_json		= v_mm_json,
			row_metadata			= v_row_metadata;

		SET v_mm_rec_id 			= LAST_INSERT_ID();
    
  /* =============== Sync Generated ID into JSON ============= */
		SET v_mm_json 				= JSON_SET( v_mm_json,
												'$.money_manager_rec_id',  v_mm_rec_id,
                                                '$.account_num', 		   getJval(v_customer_json,'account_number'),
												'$.status', 			   v_status
												);
		
		UPDATE money_manager
		SET    money_manager_json 		= v_mm_json
		WHERE  money_manager_rec_id 	= v_mm_rec_id;

     /* =============== Credit Card Insert (Conditional) ============= */

	
     
		IF v_transaction_type = 'credit card' THEN
		
			INSERT INTO credit_card
			SET	money_manager_rec_id 	 = v_mm_rec_id,
				status					 = v_status,
				account_num				 = getJval(v_customer_json,'account_number'),
				processor_name			 = getJval(pjReqObj,'P_PROCESSOR_NAME'),
				processor_token			 = getJval(pjReqObj,'P_PROCESSOR_TOKEN'),
				card_last_4				 = RIGHT(getJval(pjReqObj,'P_CARD_INFO.P_CARD_NUMBER'),4),
				credit_card_json		 = v_cc_json,
				row_metadata			 = v_row_metadata;
		
			SET v_cc_rec_id 			= LAST_INSERT_ID();
		
	  /* =============== Sync Credit Card ID into JSON ============= */
			SET v_cc_json 				= JSON_SET( v_cc_json,
												'$.credit_card_rec_id', v_cc_rec_id,
                                                '$.money_manager_rec_id', v_mm_rec_id,
												'$.status', v_status,
                                                '$.card_last_4', RIGHT(getJval(pjReqObj,'card_number'),4)
												);
		
			UPDATE credit_card
			SET    credit_card_json 	= v_cc_json
			WHERE  credit_card_rec_id 	= v_cc_rec_id;
    
		END IF;

    COMMIT;
    
    /* =============== Success Response ============= */
    

	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);

	SET pjRespObj = buildJSONSmart( pjRespObj,
								   'jHeader.message', 'Success - Your transaction has been submitted. It will be posted to your wallet within 3 business days.'
								);  
						
     END main_block;
     
     -- inert general code here like LOG
	-- call log proc
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `createRedeemOrder` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `createRedeemOrder`(
                                    IN      pjReqObj    JSON,
                                    INOUT   pjRespObj    JSON
                                )
BEGIN

    /* ===================== Variables ===================== */
    DECLARE v_customer_rec_id           INT;
    DECLARE v_account_number            VARCHAR(50);
    DECLARE v_order_rec_id              INT;
    DECLARE v_order_number              VARCHAR(50);
    DECLARE v_receipt_number            VARCHAR(50);
    DECLARE v_order_date                DATETIME;
    DECLARE v_order_status              VARCHAR(20);
    DECLARE v_next_action_required      VARCHAR(20);
    DECLARE v_order_cat                 VARCHAR(10);
    DECLARE v_order_type                VARCHAR(20);
    DECLARE v_metal                     VARCHAR(50);
    DECLARE v_asset_code                VARCHAR(10);
    DECLARE v_product_type              VARCHAR(20);
    DECLARE v_cr_weight                 DECIMAL(20,6);
    DECLARE v_asset_code_metal          VARCHAR(50);

    DECLARE v_tradable_assets_rec_id    INT;
    DECLARE v_rate_json                 JSON;
    DECLARE v_spot_rate                 DECIMAL(20,6);

    DECLARE v_customer_json             JSON;
    DECLARE v_order_json                JSON;
    DECLARE v_row_metadata              JSON;

    /*  buy_items variables   */
    DECLARE v_inventory_json            JSON;
    DECLARE v_item_code                 VARCHAR(50);
    DECLARE v_item_name                 VARCHAR(100);
    DECLARE v_item_type                 VARCHAR(50);
    DECLARE v_item_weight               DECIMAL(20,6);
    DECLARE v_item_quantity             INT;
    DECLARE v_bought_price              DECIMAL(20,6);
    DECLARE v_buy_items_input           JSON;
    DECLARE v_buy_items_output          JSON;
    DECLARE v_single_item               JSON;
    DECLARE v_loop_idx                  INT             DEFAULT 0;
    DECLARE v_items_count               INT             DEFAULT 0;
    DECLARE v_customer_products_json    JSON            DEFAULT JSON_ARRAY();

    /* Order Summary Variables */
    DECLARE v_total_redeem_items        INT DEFAULT 0;
    DECLARE v_total_redeem_weight       DECIMAL(20,6)   DEFAULT 0;
    DECLARE v_total_buy_amount          DECIMAL(20,6)   DEFAULT 0;    
    DECLARE v_making_charges            DECIMAL(20,6)   DEFAULT 0;
    DECLARE v_premium_charged           DECIMAL(20,6)   DEFAULT 0;
    DECLARE v_transaction_fee           DECIMAL(20,6)   DEFAULT 0;
    DECLARE v_processing_charges        DECIMAL(20,6)   DEFAULT 0;
    DECLARE v_taxes                     DECIMAL(20,6)   DEFAULT 0;
    DECLARE v_total_discounts           DECIMAL(20,6)   DEFAULT 0;
    DECLARE v_total_charges_amount      DECIMAL(20,6)   DEFAULT 0;   

    /* Weight cross-check: (item_weight * item_quantity) must equal customer_request.weight */
    DECLARE v_calc_total_weight         DECIMAL(20,6)   DEFAULT 0;

    /* Transaction / wallet variables */
    DECLARE v_txn_num_metal_debit       VARCHAR(50);
    DECLARE v_txn_num_cash_debit        VARCHAR(50);
    DECLARE v_transactions_output       JSON;

    DECLARE v_metal_wallet_id           VARCHAR(100);
    DECLARE v_metal_balance_before      DECIMAL(20,6);
    DECLARE v_metal_balance_after       DECIMAL(20,6);
    DECLARE v_metal_txn_amount          DECIMAL(20,6);

    DECLARE v_cash_wallet_id            VARCHAR(100);
    DECLARE v_cash_balance_before       DECIMAL(20,6);
    DECLARE v_cash_balance_after        DECIMAL(20,6);
    DECLARE v_cash_txn_amount           DECIMAL(20,6);

    DECLARE v_wallets_arr               JSON;
    DECLARE v_wallet_loop_idx           INT DEFAULT 0;
    DECLARE v_wallet_count              INT DEFAULT 0;
    DECLARE v_wallet_item               JSON;
    DECLARE v_wallet_asset_code         VARCHAR(20);
    DECLARE v_wallet_type               VARCHAR(20);

    DECLARE v_errors                    JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg                   VARCHAR(500);

    /* ===================== Error Handler ===================== */
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
        ROLLBACK;

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 	 CONCAT('Insertion failed: ', v_err_msg));

    END;

    main_block: BEGIN

        /* ===================== Step 1: Extract Request Values ===================== */
        SET v_order_type        = 'Redeem';
        SET v_product_type      = 'PRODUCT';                -- Redeem is always PRODUCT, no SLICE, no order_sub_type
        SET v_account_number    = getJval(pjReqObj, 'jData.P_ACCOUNT_NUMBER');
        SET v_asset_code_metal  = getJval(pjReqObj, 'jData.P_ASSET_CODE'); -- extract asset_code of metal 
        SET v_metal             = getJval(pjReqObj, 'jData.P_METAL');
        SET v_cr_weight         = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_WEIGHT');

        /* ===================== Step 2: Common Validations ===================== */
        IF isFalsy(v_account_number) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'account_number is required');
        END IF;

        IF isFalsy(v_asset_code_metal) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', CONCAT('Asset code of', v_metal,  'is required'));
        END IF;

        IF isFalsy(v_metal) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'metal is required');
        END IF;

        IF isFalsy(v_cr_weight) OR v_cr_weight <= 0 THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.weight is required and must be greater than 0');
        END IF;

        IF JSON_LENGTH(v_errors) > 0 THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',  'Validation failed');
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.errors',     v_errors);

            LEAVE main_block;
        END IF;

        /* ===================== Step 3: Fetch Customer Record ===================== */
        SELECT  customer_rec_id
        INTO    v_customer_rec_id
        FROM    customer
        WHERE   account_num = v_account_number
        LIMIT 1;

        IF isFalsy(v_customer_rec_id) THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Customer not found');

            LEAVE main_block;
        END IF;

        SET v_customer_json = getCustomer(v_customer_rec_id);

        IF isFalsy(v_customer_json) THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Customer not found for account number: ', v_account_number));

            LEAVE main_block;
        END IF;

        /* ===================== Step 5: Generate Order & Receipt Numbers ===================== */
        CALL getSequence('ORDERS.ORDER_NUM',    NULL,    3000, 'createRedeemOrder', v_order_number);
        CALL getSequence('ORDERS.RECEIPT_NUM', 'RECP-',  3000, 'createRedeemOrder', v_receipt_number);

        /* ===================== Step 6: Set Common Order Header Values ===================== */
        SET v_order_date            = NOW();
        SET v_order_status          = 'Pending';
        SET v_next_action_required  = 'approval';
        SET v_order_cat             = 'DO';

        /* ===================== Step 7: Load Order Template & Row Metadata ===================== */
        SET v_order_json            = getTemplate('orders');
        SET v_row_metadata          = getTemplate('row_metadata');

        SET v_row_metadata = JSON_SET( v_row_metadata,
                                    '$.status',     v_order_status,
                                    '$.created_at', DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
                                    '$.created_by', CONCAT(
                                                                getJval(v_customer_json, 'first_name'),
                                                                ' ',
                                                                getJval(v_customer_json, 'last_name'),
                                                                ' Customer Self-Service'
                                                            )
                                    );

        /* ===================== Step 8: Populate Customer & Rate Info in order json ===================== */
        SET v_order_json = JSON_SET(v_order_json,
                                    '$.customer_info.customer_rec_id',          v_customer_rec_id,
                                    '$.customer_info.customer_name',            CONCAT(getJval(v_customer_json, 'first_name'), ' ', getJval(v_customer_json, 'last_name')),
                                    '$.customer_info.customer_account_number',  getJval(v_customer_json, 'main_account_number'),
                                    '$.customer_info.customer_phone',           getJval(v_customer_json, 'phone'),
                                    '$.customer_info.whatsapp',                 getJval(v_customer_json, 'whatsapp'),
                                    '$.customer_info.customer_email',           getJval(v_customer_json, 'email'),
                                    '$.customer_info.customer_address',         CAST(getJval(v_customer_json, 'residential_address') AS JSON),
                                    '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'jData.P_CUSTOMER_IP_ADDRESS'),
                                    '$.customer_info.latitude',                 getJval(pjReqObj, 'jData.P_LATITUDE'),
                                    '$.customer_info.longitude',                getJval(pjReqObj, 'jData.P_LONGITUDE'),
                                    '$.customer_info.notes',                    getJval(pjReqObj, 'jData.P_NOTES'),

                                    '$.customer_rec_id',                        v_customer_rec_id,
                                    '$.account_number',                         v_account_number,
                                    '$.order_number',                           v_order_number,
                                    '$.receipt_number',                         v_receipt_number,
                                    '$.order_date',                             DATE_FORMAT(v_order_date, '%Y-%m-%dT%H:%i:%sZ'),
                                    '$.order_status',                           v_order_status,
                                    '$.next_action_required',                   v_next_action_required,
                                    '$.order_type',                             v_order_type,
                                    '$.order_cat',                              v_order_cat,
                                    '$.limit_or_market',                        NULL,
                                    '$.metal',                                  v_metal
                                );

        /* ===================== Step 9: Validate & Process buy_items ===================== */

        /*
            The customer types their weight (e.g. 12g), sees available physical products,
            selects them and submits. The frontend sends the selected products as 'redeem_items'.
            Internally we read from 'redeem_items' but store in order_json as 'buy_items'
            to stay consistent with the orders template used across all order types.
        */
        SET v_buy_items_input = getJval(pjReqObj, 'jData.P_REDEEM_ITEMS');

        IF isFalsy(v_buy_items_input) OR JSON_LENGTH(v_buy_items_input) = 0 THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Validation failed: redeem_items array is required and must not be empty');

            LEAVE main_block;
        END IF;

        SET v_items_count           = JSON_LENGTH(v_buy_items_input);
        SET v_loop_idx              = 0;
        SET v_buy_items_output      = JSON_ARRAY();
        SET v_calc_total_weight     = 0;

        WHILE v_loop_idx < v_items_count DO

            SET v_single_item       = JSON_EXTRACT(v_buy_items_input, CONCAT('$[', v_loop_idx, ']'));
            SET v_item_code         = getJval(v_single_item, 'P_ITEM_CODE');
            SET v_item_weight       = getJval(v_single_item, 'P_ITEM_WEIGHT');
            SET v_item_quantity     = getJval(v_single_item, 'P_ITEM_QUANTITY');

            /* Per-item field validation */
            IF isFalsy(v_item_code) THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$',
                    CONCAT('redeem_items[', v_loop_idx, '].item_code is required'));
            END IF;

            IF isFalsy(v_item_weight) OR v_item_weight <= 0 THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$',
                    CONCAT('redeem_items[', v_loop_idx, '].item_weight is required and must be greater than 0'));
            END IF;

            IF isFalsy(v_item_quantity) OR v_item_quantity <= 0 THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$',
                    CONCAT('redeem_items[', v_loop_idx, '].item_quantity is required and must be greater than 0'));
            END IF;

            IF JSON_LENGTH(v_errors) > 0 THEN
                
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Validation failed on redeem_items');
                SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.errors',     v_errors);

                LEAVE main_block;
            END IF;

            /* Lookup item_name + item_type from inventory */
            SET v_inventory_json = NULL;

            SELECT  inventory_json
            INTO    v_inventory_json
            FROM    inventory
            WHERE   item_code = v_item_code
            LIMIT   1;

            IF isFalsy(v_inventory_json) THEN
                
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Inventory item not found for item_code: ', v_item_code));

                LEAVE main_block;
            END IF;

            SET v_item_name     = getJval(v_inventory_json, 'item_name');
            SET v_item_type     = getJval(v_inventory_json, 'item_type');
            SET v_asset_code    = getJval(v_inventory_json, 'asset_code');


            /* Fetch spot_rate per item based on its own asset_code */
            SELECT   tradable_assets_rec_id,   tradable_assets_json
            INTO     v_tradable_assets_rec_id, v_rate_json
            FROM     tradable_assets
            WHERE    asset_code = v_asset_code
            ORDER BY tradable_assets_rec_id DESC
            LIMIT 1;

            IF isFalsy(v_rate_json) THEN
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Rate not found for asset_code: ', v_asset_code));
                LEAVE main_block;
            END IF;

            SET v_spot_rate = getJval(v_rate_json, 'spot_rate.current_rate');

            /* bought_price */
            SET v_bought_price = v_spot_rate * v_item_weight * v_item_quantity;

            /* Accumulate weight - will be cross-checked against customer_request.weight after loop */
            SET v_calc_total_weight = v_calc_total_weight + (v_item_weight * v_item_quantity);

            /* Append item to buy_items array */
            SET v_buy_items_output = JSON_ARRAY_APPEND( v_buy_items_output,
                                                        '$',
                                                        JSON_OBJECT(
                                                                    'asset_code',       v_asset_code,
                                                                    'item_code',        v_item_code,
                                                                    'item_name',        v_item_name,
                                                                    'item_type',        v_item_type,
                                                                    'item_quantity',    v_item_quantity,
                                                                    'item_weight',      v_item_weight,
                                                                    'spot_rate',        v_spot_rate, 
                                                                    'bought_price',     v_bought_price
                                                                )
                                                    );

            SET v_loop_idx = v_loop_idx + 1;

        END WHILE;

        /*Store a note at order level instead */
        SET v_order_json = JSON_SET(v_order_json,
                                    '$.rate_info',  'See individual buy_items for per-item rate details'
                                    );

        /* ----
        Critical cross-check: the weight the customer typed at step 1
        must exactly equal the total weight of products they selected.
        Uses epsilon comparison to guard against floating-point drift.
        ---- */
        IF ABS(v_cr_weight - v_calc_total_weight) > 0.000001 THEN

            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('customer_request.weight does not match total weight of selected redeem items. requested: ', v_cr_weight, ', calculated: ', v_calc_total_weight));                                

            LEAVE main_block;
        END IF;

        /* Stored as 'buy_items' in order_json */
        SET v_order_json = JSON_SET(v_order_json,
                                    '$.buy_items',                              v_buy_items_output,
                                    '$.customer_request.weight',                v_cr_weight,
                                    '$.customer_request.date_of_redemption',    DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ')
                                );

        /* ===================== Step 9.5: Calculate Order Summary ===================== */

        SET v_items_count = JSON_LENGTH(v_buy_items_output);
        SET v_loop_idx    = 0;

        WHILE v_loop_idx < v_items_count DO

            SET v_single_item           = JSON_EXTRACT(v_buy_items_output, CONCAT('$[', v_loop_idx, ']'));

            SET v_total_redeem_items    = v_total_redeem_items  + CAST(getJval(v_single_item, 'item_quantity') AS UNSIGNED);
            SET v_total_redeem_weight   = v_total_redeem_weight + CAST(getJval(v_single_item, 'item_weight')   AS DECIMAL(20,6))
                                                                * CAST(getJval(v_single_item, 'item_quantity') AS DECIMAL(20,6));
            SET v_total_buy_amount      = v_total_buy_amount    + CAST(getJval(v_single_item, 'bought_price')  AS DECIMAL(20,6));

            SET v_loop_idx              = v_loop_idx + 1;

        END WHILE;

        /* --- Charges (deducted from Cash wallet only; no cash credit on redeem) --- */
        SET v_transaction_fee       = 100.00;
        SET v_processing_charges    = 50.00;
        SET v_making_charges        = v_total_buy_amount    * 0.02;    -- 2% of spot reference value
        SET v_premium_charged       = v_total_redeem_weight * 50;      -- 50 PKR per gram
        SET v_taxes                 = v_total_buy_amount    * 0.05;    -- 5% GST on spot reference value
        SET v_total_discounts       = COALESCE(getJval(pjReqObj, 'jData.P_DISCOUNT_AMOUNT'), 0);

        SET v_total_charges_amount  = v_making_charges
                                    + v_premium_charged
                                    + v_transaction_fee
                                    + v_processing_charges
                                    + v_taxes
                                    - v_total_discounts;

        IF v_total_charges_amount < 0 THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Net charges amount cannot be negative');

            LEAVE main_block;
        END IF;

        SET v_order_json = JSON_SET(v_order_json,
                                    '$.customer_request.total_qty_to_buy',      v_total_redeem_items,
                                    '$.order_summary.total_redeem_items',       v_total_redeem_items,
                                    '$.order_summary.total_redeem_weight',      v_total_redeem_weight,
                                    '$.order_summary.total_buy_amount',         v_total_buy_amount,         
                                    '$.order_summary.making_charges',           v_making_charges,
                                    '$.order_summary.premium_charged',          v_premium_charged,
                                    '$.order_summary.transaction_fee',          v_transaction_fee,
                                    '$.order_summary.processing_charges',       v_processing_charges,
                                    '$.order_summary.taxes',                    v_taxes,
                                    '$.order_summary.taxes_description',        'GST @ 5%',
                                    '$.order_summary.total_discounts',          v_total_discounts,
                                    '$.order_summary.total_charges_amount',     v_total_charges_amount      
                                );

        /* ===================== Step 11: Wallets - Metal DEBIT + Cash DEBIT (charges only) ===================== */

        /* 11.1: Read customer_wallets array */
        SET v_wallets_arr       = getJval(v_customer_json, 'customer_wallets');

        IF v_wallets_arr IS NULL OR JSON_LENGTH(v_wallets_arr) = 0 THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   'Customer wallets not found');

            LEAVE main_block;
        END IF;

        SET v_wallet_count      = JSON_LENGTH(v_wallets_arr);
        SET v_metal_wallet_id   = NULL;
        SET v_cash_wallet_id    = NULL;
        SET v_wallet_loop_idx   = 0;


    WHILE v_wallet_loop_idx < v_wallet_count DO

        SET v_wallet_item                = JSON_EXTRACT(v_wallets_arr, CONCAT('$[', v_wallet_loop_idx, ']'));
        SET v_wallet_asset_code          = getJval(v_wallet_item, 'asset_code');
        SET v_wallet_type                = getJval(v_wallet_item, 'wallet_type');

        IF v_wallet_asset_code = v_asset_code_metal AND v_wallet_type = 'METAL' THEN
            SET v_metal_wallet_id        = getJval(v_wallet_item, 'wallet_id');
            SET v_metal_balance_before   = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);
        END IF;

        IF v_wallet_type = 'CASH' THEN
            SET v_cash_wallet_id        = getJval(v_wallet_item, 'wallet_id');
            SET v_cash_balance_before   = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);
        END IF;

        SET v_wallet_loop_idx = v_wallet_loop_idx + 1;

    END WHILE;

        /* 11.2: Guard - both wallets must exist */
        IF isFalsy(v_metal_wallet_id) THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Metal wallet not found for asset codes'));

            LEAVE main_block;
        END IF;

        IF isFalsy(v_cash_wallet_id) THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Cash wallet not found for customer: ', v_account_number));  

            LEAVE main_block;
        END IF;

        /* 11.3: Transaction amounts */
        SET v_metal_txn_amount = v_cr_weight;               -- metal DEBIT = weight customer entered 
        SET v_cash_txn_amount  = v_total_charges_amount;    -- cash  DEBIT = charges only

        /* 11.4: Balances after */
        SET v_metal_balance_after = v_metal_balance_before - v_metal_txn_amount;
        SET v_cash_balance_after  = v_cash_balance_before  - v_cash_txn_amount;

        /* 11.4a: Guard - insufficient metal balance */
        IF v_metal_balance_after < 0 THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Insufficient metal balance. balance: ', v_metal_balance_before, ', required: ', v_metal_txn_amount));

            LEAVE main_block;
        END IF;

        /* 11.4b: Guard - insufficient cash balance for charges */
        IF v_cash_balance_after < 0 THEN
            
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',   CONCAT('Insufficient cash balance to cover redemption charges. balance: ', v_cash_balance_before, ', required: ', v_cash_txn_amount));

            LEAVE main_block;
        END IF;

        /* 11.5: Generate transaction numbers */
        CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createRedeemOrder', v_txn_num_metal_debit);
        CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createRedeemOrder', v_txn_num_cash_debit);

        /* 11.6: Build transactions array */
        SET v_transactions_output = JSON_ARRAY(

                                            /* TXN-A : Metal DEBIT - customer gives up gold weight */
                                            JSON_OBJECT(
                                                        'transaction_num',      v_txn_num_metal_debit,
                                                        'transaction_type',     'Debit',
                                                        'wallet_type',          'Metal',
                                                        'asset_code',           v_asset_code,
                                                        'wallet_id',            v_metal_wallet_id,
                                                        'balance_before',       v_metal_balance_before,
                                                        'transaction_amount',   v_metal_txn_amount,
                                                        'balance_after',        v_metal_balance_after
                                                    ),

                                            /* TXN-B : Cash DEBIT - charges only */
                                            JSON_OBJECT(
                                                        'transaction_num',      v_txn_num_cash_debit,
                                                        'transaction_type',     'Debit',
                                                        'wallet_type',          'Cash',
                                                        'asset_code',           'CSH',
                                                        'wallet_id',            v_cash_wallet_id,
                                                        'balance_before',       v_cash_balance_before,
                                                        'transaction_amount',   v_cash_txn_amount,
                                                        'balance_after',        v_cash_balance_after
                                                    )
        );

        /* ===================== Step 10: INSERT into orders table ===================== */

        INSERT INTO orders
            SET customer_rec_id         = v_customer_rec_id,
                account_number          = v_account_number,
                order_number            = v_order_number,
                receipt_number          = v_receipt_number,
                order_date              = v_order_date,
                order_status            = v_order_status,
                next_action_required    = v_next_action_required,
                order_cat               = v_order_cat,
                order_type              = v_order_type,
                limit_or_market         = NULL,
                metal                   = v_metal,
                order_json              = v_order_json,
                row_metadata            = v_row_metadata;

        SET v_order_rec_id = LAST_INSERT_ID();

        SET v_order_json = JSON_SET(v_order_json, '$.order_rec_id', v_order_rec_id);

        /* 11.7: Write transactions into order_json and persist */
        SET v_order_json = JSON_SET(v_order_json, '$.transactions', v_transactions_output);

        UPDATE  orders
        SET     order_json   = v_order_json
        WHERE   order_rec_id = v_order_rec_id;

        /* 11.8: Call wallet_activity - METAL DEBIT */
        CALL wallet_activity(
                                v_customer_rec_id,
                                v_metal_wallet_id,
                                'DEBIT',
                                v_metal_txn_amount,
                                CONCAT('Redeem order metal debited: ', v_order_number),
                                v_order_rec_id,
                                v_order_number,
                                v_txn_num_metal_debit
                            );

        /* 11.9: Call wallet_activity - CASH DEBIT (charges) */
        CALL wallet_activity(
                                v_customer_rec_id,
                                v_cash_wallet_id,
                                'DEBIT',
                                v_cash_txn_amount,
                                CONCAT('Redeem order charges debited: ', v_order_number),
                                v_order_rec_id,
                                v_order_number,
                                v_txn_num_cash_debit
                            );

        /* ---- 11.10 : Update customer_products Table for Redeem orders ---- */

        -- Loop through buy_items and append to customer_products
        SET v_loop_idx = 0;

        WHILE v_loop_idx < v_items_count DO

            SET v_single_item             = JSON_EXTRACT(v_buy_items_output, CONCAT('$[', v_loop_idx, ']'));

            SET v_customer_products_json  = JSON_ARRAY_APPEND(v_customer_products_json, '$', 
                                                            JSON_OBJECT(
                                                                            'asset_code',           getJVal(v_single_item, 'asset_code'),
                                                                            'product_name',         getJVal(v_single_item, 'item_name'),
                                                                            'product_type',         getJVal(v_single_item, 'item_type'),
                                                                            'product_price',        getJVal(v_single_item, 'bought_price'),
                                                                            'product_weight',       getJVal(v_single_item, 'item_weight'),
                                                                            'status',               'Redeem Request',
                                                                            'product_quantity',     getJVal(v_single_item, 'item_quantity'),
                                                                            'order_rec_id',         v_order_rec_id,
                                                                            'customer_rec_id',      v_customer_rec_id,
                                                                            'purchase_date',        DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ'),
                                                                            'item_code',            getJval(v_single_item, 'item_code')
                                                                        )
                                                            );

            SET v_loop_idx = v_loop_idx + 1;

        END WHILE;

        INSERT INTO customer_products
        SET customer_rec_id         = v_customer_rec_id,
            order_rec_id            = v_order_rec_id,
            order_type              = v_order_type,
            status                  = 'Redeem Request',
            customer_products_json  = v_customer_products_json,
            row_metadata            = v_row_metadata;

        /* ===================== Step 12: Success Response ===================== */

        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	0);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		CONCAT('Redeem order created successfully for order number: ', v_order_number));


    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `createSellOrder` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `createSellOrder`(
                                    IN      pjReqObj    JSON,
                                    INOUT   pjRespObj    JSON
                                )
BEGIN

    /* ===================== Variables ===================== */
    DECLARE v_customer_rec_id           INT;
    DECLARE v_account_number            VARCHAR(50);
    DECLARE v_order_rec_id              INT;
    DECLARE v_order_number              VARCHAR(50);
    DECLARE v_receipt_number            VARCHAR(50);
    DECLARE v_order_date                DATETIME;
    DECLARE v_order_status              VARCHAR(20);
    DECLARE v_next_action_required      VARCHAR(20);
    DECLARE v_order_cat                 VARCHAR(10);
    DECLARE v_order_type                VARCHAR(20);
    DECLARE v_order_sub_type            VARCHAR(20);
    DECLARE v_metal                     VARCHAR(50);
    DECLARE v_asset_code                VARCHAR(10);
    DECLARE v_product_type              VARCHAR(20);
    DECLARE v_cr_payment_method         VARCHAR(50);
    DECLARE v_cr_rate                   DECIMAL(18,6);
    DECLARE v_cr_weight                 DECIMAL(18,6);
    DECLARE v_cr_amount                 DECIMAL(18,6);
    DECLARE v_cr_expiration_time        DATETIME;
    DECLARE v_is_partial_fill_allowed   VARCHAR(20);

    DECLARE v_tradable_assets_rec_id    INT;
    DECLARE v_rate_json                 JSON;
    DECLARE v_spot_rate                 DECIMAL(18,6);

    DECLARE v_customer_json             JSON;
    DECLARE v_order_json                JSON;
    DECLARE v_row_metadata              JSON;

    /* sell_items variables */
    DECLARE v_inventory_json            JSON;
    DECLARE v_item_code                 VARCHAR(50);
    DECLARE v_item_name                 VARCHAR(100);
    DECLARE v_item_type                 VARCHAR(50);
    DECLARE v_item_quantity             INT;
    DECLARE v_sold_price                DECIMAL(20,6);
    DECLARE v_sell_items_output         JSON;

    /* Order Summary Variables */
    DECLARE v_total_sell_items          INT DEFAULT 0;
    DECLARE v_total_sell_amount         DECIMAL(20,6) DEFAULT 0;
    DECLARE v_total_sell_weight         DECIMAL(20,6) DEFAULT 0;
    DECLARE v_making_charges            DECIMAL(20,6) DEFAULT 0;
    DECLARE v_premium_charged           DECIMAL(20,6) DEFAULT 0;
    DECLARE v_transaction_fee           DECIMAL(20,6) DEFAULT 0;
    DECLARE v_processing_charges        DECIMAL(20,6) DEFAULT 0;
    DECLARE v_taxes                     DECIMAL(20,6) DEFAULT 0;
    DECLARE v_total_discounts           DECIMAL(20,6) DEFAULT 0;

    /* Transaction / wallet variables */
    DECLARE v_txn_num_debit             VARCHAR(50);
    DECLARE v_txn_num_credit            VARCHAR(50);
    DECLARE v_transactions_output       JSON;

    DECLARE v_metal_wallet_id           VARCHAR(100);
    DECLARE v_metal_balance_before      DECIMAL(20,6);
    DECLARE v_metal_balance_after       DECIMAL(20,6);
    DECLARE v_metal_txn_amount          DECIMAL(20,6);

    DECLARE v_cash_wallet_id            VARCHAR(100);
    DECLARE v_cash_balance_before       DECIMAL(20,6);
    DECLARE v_cash_balance_after        DECIMAL(20,6);
    DECLARE v_cash_txn_amount           DECIMAL(20,6);

    DECLARE v_total_order_amount        DECIMAL(20,6) DEFAULT 0;
    DECLARE v_wallets_arr               JSON;
    DECLARE v_wallet_loop_idx           INT DEFAULT 0;
    DECLARE v_wallet_count              INT DEFAULT 0;
    DECLARE v_wallet_item               JSON;
    DECLARE v_wallet_asset_code         VARCHAR(20);
    DECLARE v_wallet_type               VARCHAR(20);

    DECLARE v_errors                    JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg                   VARCHAR(500);

    /* ===================== Error Handler ===================== */
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
        ROLLBACK;
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Insertion failed ', v_err_msg));
    END;

main_block: BEGIN

    /* ===================== Step 1: Extract Request Values ===================== */
    SET v_order_type        = 'Sell';
    SET v_product_type      = 'SLICE';          
    SET v_account_number    = getJval(pjReqObj, 'jData.P_ACCOUNT_NUMBER');
    SET v_asset_code        = getJval(pjReqObj, 'jData.P_ASSET_CODE');
    SET v_order_sub_type    = getJval(pjReqObj, 'jData.P_ORDER_SUB_TYPE');
    SET v_order_cat         = getJval(pjReqObj, 'jData.P_ORDER_CAT');
    SET v_metal             = getJval(pjReqObj, 'jData.P_METAL');
    SET v_cr_payment_method = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_PAYMENT_METHOD');

    /* ===================== Step 2: Common Validations ===================== */
    IF isFalsy(v_account_number) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'account_number is required');
    END IF;

    IF isFalsy(v_asset_code) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'asset_code is required');
    END IF;

    IF isFalsy(v_metal) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'metal is required');
    END IF;

    IF isFalsy(v_cr_payment_method) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.payment_method is required');
    END IF;

    IF isFalsy(v_order_sub_type) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'order_sub_type is required (Market or Limit)');
    END IF;

    IF JSON_LENGTH(v_errors) > 0 THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', v_errors);

        LEAVE main_block;
    END IF;

    /* ===================== Step 3: Fetch Customer Record ===================== */
    SELECT  customer_rec_id
    INTO    v_customer_rec_id
    FROM    customer
    WHERE   account_num = v_account_number
    LIMIT 1;

    IF isFalsy(v_customer_rec_id) THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Customer not found');

        LEAVE main_block;
    END IF;

    SET v_customer_json = getCustomer(v_customer_rec_id);

    IF isFalsy(v_customer_json) THEN
        
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Customer not found for account number: ', v_account_number));

        LEAVE main_block;
    END IF;

    /* ===================== Step 4: Fetch Latest Rate for Asset ===================== */
    SELECT    tradable_assets_rec_id,     tradable_assets_json
    INTO      v_tradable_assets_rec_id,   v_rate_json
    FROM      tradable_assets
    WHERE     asset_code = v_asset_code
    ORDER BY  tradable_assets_rec_id DESC
    LIMIT 1;

    IF isFalsy(v_rate_json) THEN
       
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Rate not found for asset_code: ', v_asset_code));

        LEAVE main_block;
    END IF;

    SET v_spot_rate = getJval(v_rate_json, 'spot_rate.current_rate');

    /* Guard: spot_rate must be valid for Market orders */
    IF isFalsy(v_spot_rate) OR v_spot_rate <= 0 THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Invalid spot_rate for asset_code: ', v_asset_code, '. Current value: ', COALESCE(CAST(v_spot_rate AS CHAR), 'NULL')));

        LEAVE main_block;
    END IF;

    /* ===================== Step 5: Generate Order & Receipt Numbers ===================== */
    CALL getSequence('ORDERS.ORDER_NUM',    NULL,   3000, 'createSellOrder', v_order_number);
    CALL getSequence('ORDERS.RECEIPT_NUM', 'RECP-', 3000, 'createSellOrder', v_receipt_number);

    /* ===================== Step 6: Set Common Order Header Values ===================== */
    SET v_order_date            = NOW();
    SET v_order_status          = 'Pending';
    SET v_next_action_required  = 'approval';

    /* ===================== Step 7: Load Order Template & Row Metadata ===================== */
    SET v_order_json    = getTemplate('orders');
    SET v_row_metadata  = getTemplate('row_metadata');

    SET v_row_metadata = JSON_SET( v_row_metadata,
                                    '$.status',     v_order_status,
                                    '$.created_at', DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
                                    '$.created_by', CONCAT(
                                                            getJval(v_customer_json, 'first_name'),
                                                            ' ',
                                                            getJval(v_customer_json, 'last_name'),
                                                            ' Customer Self-Service'
                                                        )
                                 );

    /* ===================== Step 8: Populate Customer & Rate Info ===================== */
    SET v_order_json = JSON_SET(v_order_json,
                                '$.customer_info.customer_rec_id',          v_customer_rec_id,
                                '$.customer_info.customer_name',            CONCAT(getJval(v_customer_json,     'first_name'), ' ', getJval(v_customer_json,    'last_name')),
                                '$.customer_info.customer_account_number',  getJval(v_customer_json,            'main_account_number'),
                                '$.customer_info.customer_phone',           getJval(v_customer_json,            'phone'),
                                '$.customer_info.whatsapp',                 getJval(v_customer_json,            'whatsapp'),
                                '$.customer_info.customer_email',           getJval(v_customer_json,            'email'),
                                '$.customer_info.customer_address',         CAST(getJval(v_customer_json,       'residential_address') AS JSON),
                                '$.customer_info.customer_ip_address',      getJval(pjReqObj,                   'jData.P_CUSTOMER_IP_ADDRESS'),
                                '$.customer_info.latitude',                 getJval(pjReqObj,                   'jData.P_LATITUDE'),
                                '$.customer_info.longitude',                getJval(pjReqObj,                   'jData.P_LONGITUDE'),
                                '$.customer_info.notes',                    getJval(pjReqObj,                   'jData.P_NOTES'),

                                '$.rate_info.rate_rec_id',                  v_tradable_assets_rec_id,
                                '$.rate_info.spot_rate',                    getJval(v_rate_json,                'spot_rate.current_rate'),
                                '$.rate_info.currency_unit',                getJval(v_rate_json,                'spot_rate.currency'),
                                '$.rate_info.rate_source',                  getJval(v_rate_json,                'spot_rate.url'),
                                '$.rate_info.foreign_exchange_rate',        getJval(v_rate_json,                'spot_rate.foreign_exchange_rate'),
                                '$.rate_info.foreign_exchange_source',      getJval(v_rate_json,                'spot_rate.foreign_exchange_source'),

                                '$.customer_rec_id',                        v_customer_rec_id,
                                '$.account_number',                         v_account_number,
                                '$.order_number',                           v_order_number,
                                '$.receipt_number',                         v_receipt_number,
                                '$.order_date',                             DATE_FORMAT(v_order_date, '%Y-%m-%dT%H:%i:%sZ'),
                                '$.order_status',                           v_order_status,
                                '$.next_action_required',                   v_next_action_required,
                                '$.order_type',                             v_order_type,
                                '$.limit_or_market',                        v_order_sub_type,
                                '$.metal',                                  v_metal
                            );

    /* ===================== Step 9: SLICE - Validate item_code + item_weight ===================== */

    SET v_item_code     = getJval(pjReqObj, 'jData.P_ITEM_CODE');
    SET v_cr_weight     = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_WEIGHT');

    IF isFalsy(v_item_code) THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'item_code is required for SLICE order');
    END IF;

    IF isFalsy(v_cr_weight) OR v_cr_weight <= 0 THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.weight is required for SLICE order');
    END IF;

    /* Sanity check: weight cannot exceed 100,000g (100kg) */
    IF v_cr_weight > 100000 THEN
        SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', CONCAT('customer_request.weight exceeds maximum allowed: ', v_cr_weight, 'g. Max: 100000g'));
    END IF;

    IF JSON_LENGTH(v_errors) > 0 THEN
       
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', v_errors);

        LEAVE main_block;
    END IF;

    /* ===================== Step 9.1: Lookup inventory ===================== */

    SELECT  inventory_json
    INTO    v_inventory_json
    FROM    inventory
    WHERE   item_code = v_item_code
    LIMIT   1;

    IF v_inventory_json IS NULL THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Inventory item not found for item_code: ', v_item_code));

        LEAVE main_block;
    END IF;

    SET v_item_name = getJval(v_inventory_json, 'item_name');
    SET v_item_type = getJval(v_inventory_json, 'item_type');

    /* ===================== Step 9.2: Branch by order_sub_type ===================== */
    IF v_order_sub_type = 'Market' THEN

        SET v_sold_price = v_spot_rate * v_cr_weight;

        SET v_order_cat  = 'DO';

        SET v_sell_items_output = JSON_ARRAY(
                                            JSON_OBJECT(
                                                        'item_code',        v_item_code,
                                                        'item_name',        v_item_name,
                                                        'item_type',        v_item_type,
                                                        'item_quantity',    1,
                                                        'item_weight',      v_cr_weight,
                                                        'sold_price',       v_sold_price
                                                    )
                                            );

        SET v_order_json = JSON_SET(v_order_json,
                                    '$.order_cat',                              v_order_cat,
                                    '$.sell_items',                             v_sell_items_output,
                                    '$.customer_request.weight',                v_cr_weight,
                                    '$.customer_request.payment_method',        v_cr_payment_method,
                                    '$.customer_request.date_of_purchase',      DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ')
                                );

    ELSEIF v_order_sub_type = 'Limit' THEN

        SET v_cr_rate                  = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_RATE');
        SET v_cr_amount                 = v_cr_rate * v_cr_weight;
        SET v_cr_expiration_time       = STR_TO_DATE(getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_EXPIRATION_TIME'),'%Y-%m-%d %H:%i:%s');
        SET v_is_partial_fill_allowed  = getJval(pjReqObj, 'jData.P_CUSTOMER_REQUEST.P_IS_PARTIAL_FILL_ALLOWED');

        IF isFalsy(v_cr_rate) OR v_cr_rate <= 0 THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.rate is required for Limit Sell order');
        END IF;

        IF v_cr_expiration_time IS NULL THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_request.expiration_time is required for Limit Sell order');
        END IF;

        /* Default order_cat to GTC if not provided */
        IF isFalsy(v_order_cat) THEN
            SET v_order_cat = 'GTC';
        END IF;

        IF JSON_LENGTH(v_errors) > 0 THEN
           
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
            SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', v_errors);

            LEAVE main_block;
        END IF;

        
        SET v_sold_price    = v_cr_rate * v_cr_weight;

        SET v_sell_items_output = JSON_ARRAY(
                                            JSON_OBJECT(
                                                        'item_code',        v_item_code,
                                                        'item_name',        v_item_name,
                                                        'item_type',        v_item_type,
                                                        'item_quantity',    1,
                                                        'item_weight',      v_cr_weight,
                                                        'sold_price',       v_sold_price
                                                    )
                                            );

        SET v_order_json = JSON_SET(v_order_json,
                                    '$.order_cat',                                  v_order_cat,
                                    '$.sell_items',                                 v_sell_items_output,
                                    '$.customer_request.rate',                      v_cr_rate,
                                    '$.customer_request.weight',                    v_cr_weight,
                                    '$.customer_request.amount',                    v_cr_amount,
                                    '$.customer_request.expiration_time',           v_cr_expiration_time,
                                    '$.customer_request.is_partial_fill_allowed',   v_is_partial_fill_allowed,
                                    '$.customer_request.payment_method',            v_cr_payment_method,
                                    '$.customer_request.date_of_purchase',          DATE_FORMAT(NOW(), '%Y-%m-%dT%H:%i:%sZ')
                                );

    ELSE

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Unknown order_sub_type for Sell. Must be Market or Limit');

        LEAVE main_block;
    END IF;
    
       /* ===================== Step 9.5: Calculate Order Summary ===================== */
    /* Use already-validated variables directly (avoid re-extracting from JSON) */
    SET v_total_sell_items  = 1;                            /* SLICE always has qty 1 */
    SET v_total_sell_weight = v_cr_weight;                  /* Already validated at Step 9 */
    SET v_total_sell_amount = v_sold_price;                 /* Already calculated at Step 9.2 */

    /* --- Charges & fees (deducted from proceeds on a Sell) --- */
    SET v_transaction_fee    = 100.00;
    SET v_processing_charges = 50.00;
    SET v_making_charges     = v_total_sell_amount * 0.02;      /* 2% of amount */
    SET v_premium_charged    = v_total_sell_amount * 0.01;      /* 1% of amount (not per-gram) */
    SET v_taxes              = v_total_sell_amount * 0.05;      /* 5% GST */
    SET v_total_discounts    = COALESCE(getJval(pjReqObj, 'jData.P_DISCOUNT_AMOUNT'), 0);

    /* Net cash customer receives = gross proceeds minus charges */
    SET v_total_order_amount =  v_total_sell_amount
                                - v_making_charges
                                - v_premium_charged
                                - v_transaction_fee
                                - v_processing_charges
                                - v_taxes
                                + v_total_discounts;
    /* Now validate */
    IF v_total_order_amount < 0 THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Net sell amount cannot be negative');
        LEAVE main_block;
    END IF;                                

    SET v_order_json        = JSON_SET(v_order_json,
                                        '$.customer_request.total_qty_to_sell', v_total_sell_items,
                                        '$.order_summary.total_sell_items',     v_total_sell_items,
                                        '$.order_summary.total_sell_amount',    v_total_sell_amount,
                                        '$.order_summary.total_sell_weight',    v_total_sell_weight,
                                        '$.order_summary.items_total_amount',   v_total_sell_amount,
                                        '$.order_summary.making_charges',       v_making_charges,
                                        '$.order_summary.premium_charged',      v_premium_charged,
                                        '$.order_summary.transaction_fee',      v_transaction_fee,
                                        '$.order_summary.processing_charges',   v_processing_charges,
                                        '$.order_summary.taxes',                v_taxes,
                                        '$.order_summary.taxes_description',    'GST @ 5%',
                                        '$.order_summary.total_discounts',      v_total_discounts,
                                        '$.order_summary.total_order_amount',   v_total_order_amount
                                    );


    /* ===================== Step 11: Build Transactions, Update Wallets ===================== */

    /* 11.1: Read customer_wallets array */
    SET v_wallets_arr   = getJval(v_customer_json, 'customer_wallets');

    IF v_wallets_arr IS NULL OR JSON_LENGTH(v_wallets_arr) = 0 THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Customer wallets not found');

        LEAVE main_block;
    END IF;

    SET v_wallet_count  = JSON_LENGTH(v_wallets_arr);

    SET v_metal_wallet_id = NULL;
    SET v_cash_wallet_id  = NULL;
    SET v_wallet_loop_idx = 0;

    WHILE v_wallet_loop_idx < v_wallet_count DO

        SET v_wallet_item       = JSON_EXTRACT(v_wallets_arr, CONCAT('$[', v_wallet_loop_idx, ']'));
        SET v_wallet_asset_code = getJval(v_wallet_item, 'asset_code');
        SET v_wallet_type       = getJval(v_wallet_item, 'wallet_type');

        IF v_wallet_asset_code  = v_asset_code AND v_wallet_type = 'METAL' THEN

            SET v_metal_wallet_id       = getJval(v_wallet_item, 'wallet_id');
            SET v_metal_balance_before  = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);

        END IF;

        IF v_wallet_type = 'CASH' THEN

            SET v_cash_wallet_id      = getJval(v_wallet_item,    'wallet_id');
            SET v_cash_balance_before = COALESCE(CAST(getJval(v_wallet_item, 'wallet_balance') AS DECIMAL(20,6)), 0);

        END IF;

        SET v_wallet_loop_idx = v_wallet_loop_idx + 1;

    END WHILE;

    /* 11.2: Guard - both wallets must exist */
    IF isFalsy(v_metal_wallet_id) THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Metal wallet not found for asset_code: ', v_asset_code));

        LEAVE main_block;
    END IF;

    IF isFalsy(v_cash_wallet_id) THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Cash wallet not found for account_number: ', v_account_number));

        LEAVE main_block;
    END IF;

    /* 11.3: Transaction amounts */

    /* Metal DEBIT = total weight being sold */
    SET v_metal_txn_amount = v_total_sell_weight;

    /* Cash CREDIT = net proceeds after charges */
    SET v_cash_txn_amount = v_total_order_amount;

    /* Ensure balance values are never NULL */
    SET v_metal_balance_before = COALESCE(v_metal_balance_before, 0);
    SET v_cash_balance_before  = COALESCE(v_cash_balance_before, 0);

    /* 11.4: Balances after */
    SET v_metal_balance_after = v_metal_balance_before - v_metal_txn_amount;
    SET v_cash_balance_after  = v_cash_balance_before  + v_cash_txn_amount;

    /* 11.4b: Guard - insufficient metal balance */
    IF v_metal_balance_after < 0 THEN

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '1');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Insufficient metal balance: ', ROUND(v_metal_balance_before, 2), 'g available, ', ROUND(v_metal_txn_amount, 2), 'g required'));

        LEAVE main_block;
    END IF;

    /* 11.5: Generate transaction numbers */
    CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createSellOrder', v_txn_num_debit);
    CALL getSequence('ORDERS.TXN_NUM', 'TXN-', 5000, 'createSellOrder', v_txn_num_credit);

    /* 11.6: Build transactions array */
    SET v_transactions_output = JSON_ARRAY(

                                            /* TXN-A : Metal DEBIT */
                                            JSON_OBJECT(
                                                        'transaction_num',      v_txn_num_debit,
                                                        'transaction_type',     'Debit',
                                                        'wallet_type',          'Metal',
                                                        'asset_code',           v_asset_code,
                                                        'wallet_id',            v_metal_wallet_id,
                                                        'balance_before',       v_metal_balance_before,
                                                        'transaction_amount',   v_metal_txn_amount,
                                                        'balance_after',        v_metal_balance_after
                                                    ),

                                            /* TXN-B : Cash CREDIT */
                                            JSON_OBJECT(
                                                        'transaction_num',      v_txn_num_credit,
                                                        'transaction_type',     'Credit',
                                                        'wallet_type',          'Cash',
                                                        'asset_code',           'CSH',
                                                        'wallet_id',            v_cash_wallet_id,
                                                        'balance_before',       v_cash_balance_before,
                                                        'transaction_amount',   v_cash_txn_amount,
                                                        'balance_after',        v_cash_balance_after
                                                    )
    );

    /* ===================== Step 11-A: INSERT into orders table ===================== */
    INSERT INTO orders
        SET customer_rec_id         = v_customer_rec_id,
            account_number          = v_account_number,
            order_number            = v_order_number,
            receipt_number          = v_receipt_number,
            order_date              = v_order_date,
            order_status            = v_order_status,
            next_action_required    = v_next_action_required,
            order_cat               = v_order_cat,
            order_type              = v_order_type,
            limit_or_market         = v_order_sub_type,
            metal                   = v_metal,
            order_json              = v_order_json,
            row_metadata            = v_row_metadata;

    SET     v_order_rec_id          = LAST_INSERT_ID();

    SET     v_order_json            = JSON_SET(v_order_json, '$.order_rec_id', v_order_rec_id);

    /* 11.7: Write transactions into order_json and persist */
    SET v_order_json = JSON_SET(v_order_json, '$.transactions', v_transactions_output);

    UPDATE  orders
    SET     order_json   = v_order_json
    WHERE   order_rec_id = v_order_rec_id;

    /* 11.8: Call wallet_activity - METAL DEBIT */
    CALL wallet_activity(
                            v_customer_rec_id,
                            v_metal_wallet_id,
                            'DEBIT',
                            v_metal_txn_amount,
                            CONCAT('Sell order debited: ', v_order_number),
                            v_order_rec_id,
                            v_order_number,
                            v_txn_num_debit
                        );

    /* 11.9: Call wallet_activity - CASH CREDIT */
    CALL wallet_activity(
                            v_customer_rec_id,
                            v_cash_wallet_id,
                            'CREDIT',
                            v_cash_txn_amount,
                            CONCAT('Sell order credited: ', v_order_number),
                            v_order_rec_id,
                            v_order_number,
                            v_txn_num_credit
                        );


    /* ===================== Step 12: Success Response ===================== */
    
    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);
    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',       CONCAT('Sell order created successfully for order number: ', v_order_number));

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
