/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `documentManagment` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `documentManagment`(
									IN pjReqObj JSON,
                                    OUT pjResObj JSON
								)
BEGIN
	
    DECLARE v_document_management_rec_id		INT;
    DECLARE v_login_id							VARCHAR(255);
    DECLARE v_doc_type	     					VARCHAR(150);
    DECLARE v_notes	        					TEXT;
    DECLARE v_attachment_url   					VARCHAR(255);
    DECLARE v_user_type             			VARCHAR(50);
    
    DECLARE v_customer_rec_id					INT;
    DECLARE v_org_employee_rec_id				INT;
    
    DECLARE v_document_mng_json					JSON;
    DECLARE v_row_metadata          			JSON DEFAULT getTemplate('row_metadata');
    
    DECLARE v_errors              				JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg       					TEXT;
    
    /* ===================== Exception Handler ===================== */
	DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
        SET pjResObj = JSON_OBJECT(
									'status', 			'error',
									'status_code',		'1',
									'message', 			'Failed to upload document',
									'system_error',		v_err_msg
								   );
    END;
    
    main_block: BEGIN
    
		/* ===================== Extract Scalars ===================== */
		SET v_doc_type   		= getJval(pjReqObj, 'P_DOC_TYPE');
		SET v_notes		 		= getJval(pjReqObj, 'P_NOTES');
		SET v_attachment_url  	= getJval(pjReqObj, 'P_ATTACHMENT_URL');
        SET v_login_id			= getJval(pjReqObj, 'P_LOGIN_ID');
        SET v_user_type			= getJval(pjReqObj, 'P_USER_TYPE'); -- CUSTOMER OR EMPLOYEE
        
        /* -------- Normalize -------- */
        SET v_user_type			= UPPER(TRIM(v_user_type));
    
    
    
	  /* ===================== Validations ===================== */
        IF isFalsy(v_login_id) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'login_id is required');
        END IF;
        
		IF isFalsy(v_user_type) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'User type is required');
        END IF;

        IF isFalsy(v_doc_type) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'document type is required');
        END IF;

        IF isFalsy(v_attachment_url) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'attachment url is required');
        END IF;
        
          /* Validate allowed user types */
        IF NOT isFalsy(v_user_type)
           AND v_user_type NOT IN ('CUSTOMER','EMPLOYEE') THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'user_type must be CUSTOMER or EMPLOYEE');
        END IF;

        IF JSON_LENGTH(v_errors) > 0 THEN
            SET pjResObj = JSON_OBJECT(
										'status',      'error',
										'status_code', 0,
										'errors',      v_errors
									);
            LEAVE main_block;
        END IF;

        
        /* ===================== Identify User Based on Type ===================== */

        IF v_user_type = 'CUSTOMER' THEN

            SELECT  customer_rec_id
            INTO 	v_customer_rec_id
            FROM    customer
            WHERE   email = v_login_id
               OR  phone = v_login_id
               OR  user_name = v_login_id
            LIMIT 1;

            IF v_customer_rec_id IS NULL THEN
                SET pjResObj = JSON_OBJECT(
											'status',		'error',
											'status_code',	0,
											'message',		'Customer not found'
										);
                LEAVE main_block;
            END IF;
		
        ELSEIF v_user_type = 'EMPLOYEE' THEN

            SELECT  org_employee_rec_id
            INTO 	v_org_employee_rec_id
            FROM 	org_employees
            WHERE 	primary_phone_number 	= v_login_id
               OR 	primary_email_address 	= v_login_id
               OR 	user_name 				= v_login_id
            LIMIT 1;

            IF v_org_employee_rec_id IS NULL THEN
                SET pjResObj = JSON_OBJECT(
											'status',		'error',
											'status_code',	0,
											'message',		'Employee not found'
										);
                LEAVE main_block;
            END IF;

        END IF;
            
        
		/* ===================== Build Template ===================== */
        SET v_document_mng_json 	=  fillTemplate(pjReqObj, getTemplate('document_management'));
        
        SET v_row_metadata			= JSON_SET(v_row_metadata,
												'$.created_at',	 NOW(),
                                                '$.created_by', v_login_id
                                                );
        
      /* ===================== Insert Document  ===================== */
		IF v_user_type = 'CUSTOMER' THEN

            INSERT INTO document_management
            SET customer_rec_id        			= v_customer_rec_id,
                document_management_json 		= v_document_mng_json,
                row_metadata           			= v_row_metadata;
			
            SET v_document_management_rec_id 	= LAST_INSERT_ID();
            SET v_document_mng_json				= JSON_SET(v_document_mng_json,
															'$.document_management_rec_id', v_document_management_rec_id,
															'$.customer_rec_id', v_customer_rec_id);
                                                            
			UPDATE  document_management
			SET 	document_management_json  	= v_document_mng_json
			WHERE   document_management_rec_id = v_document_management_rec_id;

        ELSE

            INSERT INTO document_management
            SET org_employee_rec_id      	= v_org_employee_rec_id,
                document_management_json 	= v_document_mng_json,
                row_metadata             	= v_row_metadata;
                
			SET v_document_management_rec_id 	= LAST_INSERT_ID();
            
            SET v_document_mng_json				= JSON_SET(v_document_mng_json,
															'$.document_management_rec_id', v_document_management_rec_id,
															'$.employee_rec_id', v_org_employee_rec_id);
                                                            
			UPDATE  document_management
			SET 	document_management_json  	= v_document_mng_json
			WHERE   document_management_rec_id 	= v_document_management_rec_id;

        END IF;
        
		 /* ===================== Success Response ===================== */
        SET pjResObj = JSON_OBJECT(
									'status',      	'success',
									'status_code', 	1,
									'message',     	'Document uploaded successfully'
								);
    END main_block;
    
    -- logging

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `exchangeMetalCalculator` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `exchangeMetalCalculator`(
											IN  	pjReqObj JSON,
											INOUT 	pjRespObj  JSON
										)
BEGIN
	
    DECLARE v_from_asset_code		VARCHAR(50);
    DECLARE v_to_asset_code			VARCHAR(50);
    DECLARE v_quantity          	DECIMAL(18,6);
    DECLARE v_unit              	VARCHAR(10);
    
	DECLARE v_from_json             JSON;
    DECLARE v_to_json               JSON;
    
	DECLARE v_from_spot           	DECIMAL(18,6);
    DECLARE v_to_spot             	DECIMAL(18,6);
    
    DECLARE v_value			      	DECIMAL(18,6);
    DECLARE v_result_quantity   	DECIMAL(18,6);
    
    
    main_block: BEGIN
    
	-- Extract values from JSON
	SET v_from_asset_code 		=  getJval(pjReqObj, 'jData.P_METAL_TO_EXCHANGE');
	SET v_to_asset_code   		=  getJval(pjReqObj, 'jData.P_METAL_TO_EXCHANGE_ACQUIRE'); 
    SET v_quantity   	  		=  CAST(getJval(pjReqObj, 'jData.P_QUANTITY') AS DECIMAL(18,6));
    SET v_unit            		=  getJval(pjReqObj, 'jData.P_UNIT');
    
     -- Validate asset codes
        IF v_from_asset_code IS NULL OR v_to_asset_code IS NULL THEN
    
			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid metal selection');

            LEAVE main_block;
        END IF;
        
	-- Prevent exchanging same metal
        IF v_from_asset_code = v_to_asset_code THEN
        
			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Both metals cannot be same');

            LEAVE main_block;
        END IF;
    

	-- Convert all input to grams
			SET v_quantity = CASE v_unit
				WHEN 'kg' THEN v_quantity * 1000
				WHEN 'oz' THEN v_quantity * 28.349523125
				WHEN 'g'  THEN v_quantity
				ELSE NULL
			END;

    
    IF v_quantity IS NULL OR v_quantity <= 0 THEN
  
		SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid or unsupported unit/quantity');

    LEAVE main_block;
	END IF;
    
    -- Get rates
    -- Get latest rate for From Metal
    SELECT 		asset_rate_history_json
    INTO 		v_from_json
    FROM 		asset_rate_history
    WHERE 		asset_code = v_from_asset_code;
    
	-- Get latest rate for TO metal
    SELECT 		asset_rate_history_json
    INTO 		v_to_json
    FROM 		asset_rate_history
    WHERE 		asset_code = v_to_asset_code;
    
      -- Validation
    IF v_from_json IS NULL OR v_to_json IS NULL THEN

		SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Rate not found for selected metals');

        LEAVE main_block;
    END IF;

    
    -- Extract spot price
    SET v_from_spot 	= CAST(getJval(v_from_json,	'spot_rate') AS DECIMAL(18,6));
	SET v_to_spot  		= CAST(getJval(v_to_json,	'spot_rate') AS DECIMAL(18,6));
    
    -- Prevent divide by zero
	IF v_to_spot IS NULL OR v_to_spot <= 0
    OR v_to_spot IS NULL OR v_to_spot <= 0 THEN

		SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid spot rate');
        
		LEAVE main_block;
	END IF;
    
    -- Exchange calculation
    SET v_value 			= v_quantity * v_from_spot;
    SET v_result_quantity 	= v_value / v_to_spot;
    
   
	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 				 	0);
    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 					 	'Exchange successful');

	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.exchange_from',        	 v_from_asset_code);
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.exchange_to',          	 v_to_asset_code);
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.input_quantity_grams', 	 v_quantity);
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.from_spot_rate', 		 	 v_from_spot);
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.to_spot_rate', 		 	 v_to_spot);

	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.result_quantity_grams',	 ROUND(v_result_quantity, 6));

	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.message', 				CONCAT(
																									'You can exchange ',
																									v_quantity, ' g of ',
																									v_from_asset_code,
																									' with ',
																									ROUND(v_result_quantity,6),
																									' g of ',
																									v_to_asset_code
																								));
    
    

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `forgotLoginID` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `forgotLoginID`(
								IN      pjReqObj   JSON,      
								INOUT   pjRespObj   JSON       
							)
BEGIN
    DECLARE v_email         	VARCHAR(255);
    DECLARE v_phone         	VARCHAR(20);
    DECLARE v_cnic		      	VARCHAR(50);
    
    DECLARE v_login_id			VARCHAR(100);

    DECLARE v_err_msg 		    TEXT;
	
	DECLARE EXIT HANDLER FOR SQLEXCEPTION
	BEGIN
			GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;

			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Unexpected Error - ', v_err_msg));

	END;
    
	main_block: BEGIN

    -- Extract info from input JSON
    SET v_email    	= getJval(pjReqObj, 'jData.P_EMAIL');
    SET v_phone    	= getJval(pjReqObj, 'jData.P_PHONE');
    SET v_cnic 		= getJval(pjReqObj, 'jData.P_CNIC');

    -- ============== Find user account =============
    SELECT user_name
    INTO   v_login_id
    FROM   customer
    WHERE (
			(email = v_email AND v_email IS NOT NULL)  OR  (phone = v_phone AND v_phone IS NOT NULL)
		  )
		  AND national_id = v_cnic
    LIMIT 1;

    IF v_login_id IS NULL THEN
        -- No user found
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
    	SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'customer not found');

        LEAVE main_block;
    END IF;

    -- ============ Generate OTP to verified contact ============

    CALL genOtp(
                JSON_OBJECT(
                    'jData', JSON_OBJECT(
                        'P_CONTACT_TYPE', CASE WHEN v_email IS NOT NULL THEN 'email' ELSE 'phone' END,
                        'P_DESTINATION',  COALESCE(v_email, v_phone),
                        'P_PURPOSE',      'FORGOT LOGIN ID'
                    )
                ),
                pjRespObj
            );

  
    END main_block;
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `forgotPassword` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `forgotPassword`(
								IN  pReqJson   JSON,   
								OUT pResJson   JSON
							 )
BEGIN
    
    DECLARE v_input             VARCHAR(255);
    DECLARE v_login_id       	VARCHAR(255);
    DECLARE v_email          	VARCHAR(255);
    DECLARE v_phone         	VARCHAR(20);
	DECLARE v_input_type        ENUM('user_name','email','phone');

    main_block: BEGIN

      -- =========================
        -- Extract login ID input
        -- =========================
        SET v_input = getJval(pReqJson, 'P_LOGIN_ID');
        
		-- =========================
        -- Detect input type
        -- =========================
        IF v_input LIKE '%@%' THEN
            SET v_input_type = 'email';
        ELSEIF v_input REGEXP '^[0-9]+$' THEN
            SET v_input_type = 'phone';
        ELSE
            SET v_input_type = 'username';
        END IF;


        -- ============= Find user account =============
        SELECT  user_name,	 email, 	 phone
        INTO    v_login_id,  v_email, 	 v_phone
        FROM   	customer
		WHERE   (v_input_type = 'user_name' AND  user_name = v_input)
		OR 		(v_input_type = 'email'     AND  email = v_input)
		OR 		(v_input_type = 'phone'     AND  phone = v_input)
        LIMIT 1;

        IF v_login_id IS NULL THEN
            SET pResJson = JSON_OBJECT(
										'status', 	'USER_NOT_FOUND',
										'message', 	'No account matches the provided login ID.'
									 );
            LEAVE main_block;
        END IF;

		   -- =========================
        -- Send OTP according to input type
        -- =========================
        CASE v_input_type
        
         WHEN 'username' THEN
                -- Send OTP to all verified contacts
                IF v_email IS NOT NULL THEN
                    CALL genOtp('email', v_email, 'RESET PASSWORD');
                END IF;
                IF v_phone IS NOT NULL THEN
                    CALL genOtp('phone', v_phone, 'RESET PASSWORD');
                END IF;

            WHEN 'email' THEN
                -- Send OTP only to email
                CALL genOtp('email', v_email, 'RESET PASSWORD');

            WHEN 'phone' THEN
                -- Send OTP only to phone
                CALL genOtp('phone', v_phone, 'RESET PASSWORD');
        END CASE;


        -- ============ Prepare response ============
        SET pResJson = JSON_OBJECT(
									'status', 			'OTP_SENT',
									'message', 			'OTP has been sent to your verified contact. Use it to reset your password.'
								);

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `generateUsername` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `generateUsername`(
									IN  p_first_name  VARCHAR(100),
									IN  p_last_name   VARCHAR(100),
									OUT p_username    VARCHAR(150)
								)
BEGIN

    DECLARE v_base_username 	VARCHAR(150);
    DECLARE v_candidate     	VARCHAR(150);
    DECLARE v_exists        	INT DEFAULT 1;
    DECLARE v_random_num    	INT;
    DECLARE v_attempts      	INT DEFAULT 0;

    -- Normalize name (lowercase + remove spaces)
    SET v_base_username = LOWER(REPLACE(CONCAT(p_first_name, p_last_name), ' ', ''));

    -- Try max 15 times to avoid infinite loop
    WHILE v_exists > 0 AND v_attempts < 15 DO

        -- Generate random 4-digit number (1000–9999)
        SET v_random_num = FLOOR(1000 + (RAND() * 9000));

        SET v_candidate = CONCAT(v_base_username, v_random_num);

        SELECT COUNT(*)
        INTO v_exists
        FROM customer
        WHERE username = v_candidate;

        SET v_attempts = v_attempts + 1;

    END WHILE;

    SET p_username = v_candidate;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `generate_audit_triggers_sql` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `generate_audit_triggers_sql`(
    IN tbl_name VARCHAR(64),
    IN pk_col VARCHAR(64),
    IN json_col VARCHAR(64)
)
BEGIN

SELECT
		CONCAT(
				'DELIMITER $$
				
				CREATE TRIGGER after_update_', tbl_name, '
				AFTER UPDATE ON ', tbl_name, '
				FOR EACH ROW
				BEGIN
                
					  INSERT INTO row_audit_logs
                      SET table_name		= ''', tbl_name, ''',
						  row_rec_id		= OLD.', pk_col, ',
                          prev_row_json		= OLD.', json_col, ',
                          next_row_json		= NEW.', json_col, ',
                          updated_at		= NOW();
						
				END$$
				
				DELIMITER ;'
			) AS update_trigger_sql,

		CONCAT(
				'DELIMITER $$

				CREATE TRIGGER after_delete_', tbl_name, '
				AFTER DELETE ON ', tbl_name, '
				FOR EACH ROW
				BEGIN
					 
					  INSERT INTO row_audit_logs
                      SET table_name		= ''', tbl_name, ''',
						  row_rec_id		= OLD.', pk_col, ',
                          prev_row_json		= OLD.', json_col, ',
                          next_row_json		= NULL,
                          updated_at		= NOW();
						
				END$$

				DELIMITER ;'
			) AS delete_trigger_sql;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `genOtp` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `genOtp`(
						 IN  	pjReqObj 	JSON,
						 INOUT  pjRespObj 	JSON
					   )
BEGIN
    -- =========================
    -- Variable Declarations
    -- =========================
	DECLARE v_contact_type      	VARCHAR(20);
    DECLARE v_destination       	VARCHAR(255);
    DECLARE v_purpose           	TEXT;
    
    DECLARE v_otp                  	CHAR(6);
    DECLARE v_expiry               	DATETIME;
    DECLARE v_otp_rec_id           	INT;
    DECLARE v_outbound_msgs_rec_id 	INT;
    DECLARE v_message_guid         	VARCHAR(100);
    DECLARE v_last_sent_time       	DATETIME;
    
    DECLARE v_outbound_msgs_json   	JSON;
    DECLARE v_row_metadata         	JSON;

    -- =========================
    -- Extract Request Values
    -- =========================
    SET v_contact_type 	= getJval(pjReqObj, 	'jData.P_CONTACT_TYPE');
    SET v_destination  	= getJval(pjReqObj, 	'jData.P_DESTINATION');
    SET v_purpose      	= getJval(pjReqObj, 	'jData.P_PURPOSE');
    
    main_block: BEGIN
	-- =========================
    -- Basic Validation
    -- =========================
    IF v_contact_type IS NULL OR v_destination IS NULL OR v_purpose IS NULL THEN
		
        SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   1);
		SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        'Missing required parameters');

        LEAVE main_block;
    END IF;
    
    -- =========================
    -- Cooldown check (e.g., 60 seconds)
    -- =========================
    SELECT MAX(created_at)
    INTO   v_last_sent_time
    FROM   otp
    WHERE  contact_type 	= v_contact_type
	AND    destination  	= v_destination
    AND    purpose      	= v_purpose;

    IF v_last_sent_time IS NOT NULL 
    AND TIMESTAMPDIFF(SECOND, v_last_sent_time, NOW()) < 60 THEN

		SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   				1);
		SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        				'Please wait before requesting OTP again.');
		SET pjRespObj  = buildJSONSmart(pjRespObj,  'jData.contents.next_otp_in_secs',       60 - TIMESTAMPDIFF(SECOND, v_last_sent_time, NOW()));

        LEAVE main_block;
    END IF;

	
		-- =========================
		-- Expire previous OTPs (for resend)
		-- =========================
		UPDATE  otp
		SET 	expires_at 		= NOW(),
				otp_retries 	= 0
		WHERE   contact_type 	= v_contact_type
		AND 	destination  	= v_destination
		AND     purpose      	= v_purpose
		AND 	expires_at 		> NOW();

		-- =========================
		-- Generate new OTP
		-- =========================
		SET v_otp    	= LPAD(FLOOR(100000 + RAND() * 900000), 6, '0');
		SET v_expiry 	= DATE_ADD(NOW(), INTERVAL 5 MINUTE);
		
	   -- =========================
		-- Generate message guid number
		-- ========================= 
		CALL getSequence('OUTBOUND_MSGS.MESSAGE_GUID','MSG-', 5000,'genOTP SP', v_message_guid);

		-- =========================
		-- Insert OTP record
		-- =========================
		INSERT INTO otp
		SET contact_type      = v_contact_type,
			destination       = v_destination,
			otp_code          = v_otp,
			expires_at        = v_expiry,
			otp_retries       = 3,
			next_otp_in_secs  = 60,
			purpose			  = v_purpose;

		SET v_otp_rec_id 	  = LAST_INSERT_ID();

		-- =========================
		-- Prepare outbound_msgs JSON
		-- =========================
		SET v_outbound_msgs_json = getTemplate('outbound_msgs');

		SET v_outbound_msgs_json = JSON_SET(v_outbound_msgs_json,
											'$.message_guid',                   v_message_guid,
											'$.parent_message_table_name',      'otp',
											'$.parent_message_table_rec_id',    v_otp_rec_id,
											'$.object_name',                    'OTP',

											-- Business Context
											'$.business_context.module_name',   'AUTH',
											'$.business_context.message_name',
																				CASE 
																					WHEN v_contact_type = 'phone' THEN 'Verification of Phone Number'
																					WHEN v_contact_type = 'email' THEN 'Verification of Email'
																					ELSE 'OTP Verification'
																				END,
											'$.business_context.message_type',  'TRANSACTIONAL',
											'$.business_context.notes',          CONCAT('OTP for ', v_purpose),
											'$.business_context.login_id',       v_destination,

											-- Delivery Config
											'$.delivery_config.channel_number', 1,
											'$.delivery_config.priority_level', 1,
											'$.delivery_config.is_need_tracking', TRUE,

											-- Sender Info
											'$.sender_info.from_name',          'GFT',
											'$.sender_info.from_address',       'no-reply@gft.com',

											-- Recipient Info
											'$.recipient_info.to_address',      v_destination,
											'$.recipient_info.is_email_verified',
												IF(v_contact_type = 'email', FALSE, NULL),

											-- Message Content
											'$.message_content.message_subject', 'Your OTP Code',
											'$.message_content.message_body',
												CONCAT(
														'Your OTP is ', v_otp,
														'. It will expire in 5 minutes.',
														' Purpose: ', v_purpose
													),

											-- Scheduling
											'$.scheduling.scheduled_at',        NOW(),
											'$.scheduling.retry_interval',      60,

											-- Lifecycle Status
											'$.lifecycle_status.current_status', 'PENDING',
											'$.lifecycle_status.delivery_status', 'NOT_SENT',
											'$.lifecycle_status.send_attempts',  0,
											'$.lifecycle_status.number_of_retries', 3
										);

		-- =========================
		-- Row Metadata
		-- =========================
		SET v_row_metadata = getTemplate('row_metadata');

		SET v_row_metadata = JSON_SET(v_row_metadata,
									 '$.created_at', NOW(),
									 '$.created_by', 'SYSTEM'
									);

		-- =========================
		-- Insert outbound message
		-- =========================
		INSERT INTO outbound_msgs
		SET message_guid                	= v_message_guid,
			parent_message_table_name   	= 'otp',
			parent_message_table_rec_id 	= v_otp_rec_id,
			object_name                 	= 'OTP',
			current_status					= 'Pending',
			outbound_msgs_json         		= v_outbound_msgs_json,
			row_metadata                	= v_row_metadata;

		SET v_outbound_msgs_rec_id 			= LAST_INSERT_ID();

		-- Update JSON with generated PK
		SET v_outbound_msgs_json = JSON_SET( v_outbound_msgs_json,
											'$.outbound_messages_rec_id', v_outbound_msgs_rec_id
											);

		UPDATE  outbound_msgs
		SET 	outbound_msgs_json 	 = v_outbound_msgs_json
		WHERE 	outbound_msgs_rec_id = v_outbound_msgs_rec_id;
        
            -- =========================
    -- Success Response
    -- =========================

		SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);
	    SET pjRespObj = buildJSONSmart( pjRespObj,'jHeader.message', 'OTP has been sent to your verified contact.');  
    
    END main_block;
    
    -- insert into logs table

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getAuth` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getAuth`(
						  IN  pReqObj JSON,
						  OUT pResObj JSON
						)
BEGIN

	DECLARE v_customer_rec_id 	INT;
    DECLARE v_auth_json       	JSON;
    
	-- =========================
    -- Extract Customer ID
    -- =========================
    SET v_customer_rec_id = getJval(pReqObj, 'P_CUSTOMER_REC_ID');
    
    main_block: BEGIN
    
			-- Validation
		IF v_customer_rec_id IS NULL THEN
			SET pResObj = JSON_OBJECT(
				'status', 'error',
				'message', 'Missing customer_rec_id'
			);
			LEAVE main_block;
		END IF;
		
		
		-- Fetch auth JSON
		SELECT  auth_json
		INTO 	v_auth_json
		FROM auth
		WHERE parent_table_rec_id = v_customer_rec_id
		LIMIT 1;

		-- If not found
		IF p_auth_json IS NULL THEN
			SET pResObj  = JSON_OBJECT(
										'status',			'error',
										'message', 			'Customer does not exist',
										'customer_rec_id',	 v_customer_rec_id
									);
		ELSE
			SET pResObj = JSON_OBJECT(
										'status', 'success',
										'data', v_auth_json
									);
		END IF;
	
    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getCreditCard` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getCreditCard`(
								IN  	pReqObj JSON,
								INOUT 	pjRespObj JSON
							)
BEGIN

	DECLARE v_cc_rec_id 	INT;
    
	DECLARE v_account_num 	    	VARCHAR(50);
	DECLARE v_cc_json   			JSON;
    
	-- =========================
    -- Extract Account Number
    -- =========================

    SET v_account_num 		= getJval(pReqObj, 'P_ACCOUNT_NUM');
    
    main_block: BEGIN
    
		 -- Validation
		IF v_account_num IS NULL THEN

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'Missing Account Number');

			LEAVE main_block;
		END IF;

		-- =========================
        -- Fetch ALL credit cards
        -- =========================

        SELECT  JSON_ARRAYAGG(credit_card_json)
        INTO 	v_cc_json
        FROM 	credit_card
        WHERE 	account_num = v_account_num;
        
		-- =========================
		-- Response Handling
		-- =========================
		IF v_cc_json IS NULL THEN
			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'Record does not exist for given account number');
		ELSE
			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);
	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', CONCAT('Credit Card record found for account number: ', v_account_num));
        	SET pjRespObj = buildJSONSmart( pjRespObj, 'jData.contents', v_cc_json);
		END IF;
        
	END main_block;
    
    -- logging
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getCustomer` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getCustomer`(
							 IN  pjReqObj JSON,
							 INOUT pjRespObj JSON
							)
BEGIN

	DECLARE v_account_num 	    VARCHAR(50);
    DECLARE v_customer_json 	JSON;
    
    SET v_account_num = getJval(pjReqObj, 'jData.P_ACCOUNT_NUMBER');
    
    -- Get customer JSON
    SELECT 	customer_json
    INTO 	v_customer_json
    FROM 	customer
    WHERE   account_num = v_account_num
    LIMIT 1;

    -- If not found
    IF v_customer_json IS NULL THEN
          
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', CONCAT('Customer does not exist', ' for account number: ', v_account_num));
   
    ELSE
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);
	    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', CONCAT('Customer found', ' for account number: ', v_account_num));
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jData.contents', v_customer_json);
        
    END IF;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getDropDownValue` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getDropDownValue`(
								IN    pjReqObj JSON,
								INOUT pjRespObj JSON
							)
BEGIN

	DECLARE v_category      	    VARCHAR(50);
    DECLARE v_column_values_json   	JSON;

	main_block: BEGIN

    -- =========================
        -- Extract Inputs
    -- =========================
        SET v_category 	= getJval(pjReqObj, 'jData.P_CATEGORY');

    -- =========================
        -- Validation
	-- =========================
        IF v_category IS NULL THEN
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'Category is required');
            LEAVE main_block;
        END IF;

    -- =========================    
        -- Fetch Data
    -- =========================
        SELECT column_values_json
        INTO   v_column_values_json
        FROM   column_values
        WHERE  category = v_category;
      
		-- =========================
        -- Handle empty result
        -- =========================
        IF v_column_values_json IS NULL THEN

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'No values found for this category');

            LEAVE main_block;
        END IF;
    
            -- =========================
        -- Response
        -- =========================

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);
	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'Records fetched successfully');
        	SET pjRespObj = buildJSONSmart( pjRespObj, 'jData.contents', v_column_values_json);
		

	END main_block;
    
    -- logging
    

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getInventory` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getInventory`(
								IN    pjReqObj JSON,
								INOUT pjRespObj JSON
							)
BEGIN

    DECLARE v_inventory_json   	JSON;
	DECLARE v_item_type         VARCHAR(50);
	DECLARE v_page              INT;
	DECLARE v_limit             INT;
	DECLARE v_offset            INT;
	DECLARE v_total             INT;

	main_block: BEGIN
    
	-- =========================
        -- Extract Inputs
    -- =========================
        SET v_item_type 	= getJval(pjReqObj, 'jData.P_ITEM_TYPE');
        SET v_page      	= getJval(pjReqObj, 'jMetaData.page');
        SET v_limit     	= getJval(   pjReqObj, 'jMetaData.limit');
        SET v_offset 		= (v_page - 1) * v_limit;

		-- =========================
        -- Validation
        -- =========================
        IF v_page <= 0 THEN
            SET v_page = 1;
        END IF;

		IF v_limit <= 0 THEN
            SET v_limit = 10;
        END IF;

		 -- =========================
        -- Count total records
        -- =========================
        IF v_item_type IS NULL OR v_item_type = 'all' THEN

            SELECT COUNT(*)
            INTO v_total
            FROM inventory;

        ELSE

            SELECT COUNT(*)
            INTO v_total
            FROM inventory
            WHERE item_type = v_item_type;

        END IF;

		-- =========================
        -- Fetch Data (ARRAYAGG + PAGINATION)
        -- =========================
        IF v_item_type IS NULL OR v_item_type = 'all' THEN

            SELECT JSON_ARRAYAGG(inventory_json)
            INTO   v_inventory_json
            FROM (
                SELECT 		  inventory_json
                FROM 		  inventory
                ORDER BY 	  inventory_rec_id DESC
                LIMIT v_limit OFFSET v_offset
            ) t;

        ELSE

            SELECT JSON_ARRAYAGG(inventory_json)
            INTO   v_inventory_json
            FROM (
                SELECT 		  inventory_json
                FROM 		  inventory
                WHERE 		  item_type = v_item_type
                ORDER BY 	  inventory_rec_id DESC
                LIMIT v_limit OFFSET v_offset
            ) t;

        END IF;

		-- =========================
        -- Handle empty result
        -- =========================
        IF v_inventory_json IS NULL THEN

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'Record does not exist for given item type');

			LEAVE main_block;
        END IF;
    
            -- =========================
        -- Response
        -- =========================

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);
	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'Inventory records fetched successfully');
        	SET pjRespObj = buildJSONSmart( pjRespObj, 'jData.contents', v_inventory_json);
		

	END main_block;
    
    -- logging
    

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
