/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getRates` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getRates`(
						   IN     pjReqObj   JSON,
						   INOUT  pjRespObj  JSON
						)
BEGIN
    DECLARE v_asset_rate_json 		JSON;
    DECLARE v_asset_code 			VARCHAR(20);
    DECLARE v_currency   			VARCHAR(10);
    DECLARE v_spot_rate				DECIMAL(18,4);
    DECLARE v_fx_rate    			DECIMAL(18,4);
    DECLARE v_usd_rate   			DECIMAL(18,4);
    DECLARE v_cur_rate   			DECIMAL(18,4);
    DECLARE v_rates_array           JSON;

    -- Denominations
    DECLARE v_denom_1g 				DECIMAL(18,4) 		DEFAULT 1;
    DECLARE v_denom_10g 			DECIMAL(18,4) 		DEFAULT 10;
    DECLARE v_denom_1t 				DECIMAL(18,4) 		DEFAULT 11.6638; 
    DECLARE v_denom_1oz 			DECIMAL(18,4) 		DEFAULT 31.1035; 

	main_block: BEGIN
    -- Extract request values
    SET v_asset_code 	= getJval(pjReqObj, 'jData.P_ASSET_CODE');
    SET v_currency   	= getJval(pjReqObj, 'jData.P_CURRENCY');

    -- Get asset JSON from DB
    SELECT asset_rate_history_json
    INTO   v_asset_rate_json
    FROM   asset_rate_history
    WHERE  asset_code = v_asset_code
    LIMIT 1;

    IF v_asset_rate_json IS NULL THEN

        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', CONCAT('Asset rate not found for ', v_asset_code));

        LEAVE main_block;
    END IF;

    -- Extract USD spot rate
    SET v_spot_rate = getJval(v_asset_rate_json, 'spot_rate');

    -- Extract FX rate for requested currency (default 1 if USD)
    IF v_currency IS NULL OR v_currency = '' OR v_currency = 'USD' THEN
        SET v_fx_rate = 1;
        
    ELSE

		SET v_fx_rate = getJval(v_asset_rate_json, CONCAT('$.foreign_exchange.', v_currency));

        IF v_fx_rate IS NULL THEN
                            
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', CONCAT('FX rate not found for currency ', v_currency));

        LEAVE main_block;
        END IF;

        
    END IF;

    -- Build JSON array of denominations
    SET v_rates_array  = JSON_ARRAY(
                            JSON_OBJECT(
                                        'denomination',     '1g',
                                        'USD',              ROUND(v_spot_rate * v_denom_1g, 2),
                                        v_currency,         ROUND(v_spot_rate * v_fx_rate * v_denom_1g, 2)
                                        ),
                            JSON_OBJECT(
                                        'denomination',     '10g',
                                        'USD',              ROUND(v_spot_rate * v_denom_10g, 2),
                                        v_currency,         ROUND(v_spot_rate * v_fx_rate * v_denom_10g, 2)
                                        ),
                            JSON_OBJECT(
                                        'denomination',     '11.6638g (1 tola)',
                                        'USD',              ROUND(v_spot_rate * v_denom_1t, 2),
                                        v_currency,         ROUND(v_spot_rate * v_fx_rate * v_denom_1t, 2)
                                    ),
                            JSON_OBJECT(
                                        'denomination',     '31.1035g (1 troy oz)',
                                        'USD',              ROUND(v_spot_rate * v_denom_1oz, 2),
                                        v_currency,         ROUND(v_spot_rate * v_fx_rate * v_denom_1oz, 2)
                                    )
                        );

    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode',   0);
    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',        'Rates retrieved successfully');
    SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents',         v_rates_array);
	
    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getSequence` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getSequence`(
							IN  psColumnName       	VARCHAR(255),
							IN  psPrefix           	VARCHAR(255),
							IN  psStartingNumber   	INT,
                            IN  psRequestedBy		VARCHAR(255),
							OUT psSequenceNumber   	VARCHAR(255)
							)
BEGIN
    DECLARE v_prefix           	VARCHAR(255);
    DECLARE v_starting_number  	INT;
    DECLARE v_seq_id           	INT;
    
    DECLARE v_requested_by		VARCHAR(255);

    /* ==============================
       CASE Column-based
       ============================== */
    CASE psColumnName
        WHEN 'CUSTOMER.MAIN_ACCOUNT_NUM' THEN
            SET v_prefix 			= 'P-';
            SET v_starting_number 	= 500;

        WHEN 'ORDERS.ORDER_NUM' THEN
            SET v_prefix 			= 'ORD-';
            SET v_starting_number 	= 1000;

		WHEN 'EMPLOYEE.EMPLOYEE_NUM' THEN
            SET v_prefix 			= 'EMP-';
            SET v_starting_number 	= 2000;

        ELSE
            SET v_prefix 			= 'GEN-';
            SET v_starting_number 	= 1;
    END CASE;

    /* ==============================
       Override defaults
       ============================== */
    IF psPrefix IS NOT NULL AND psPrefix <> '' THEN
        SET v_prefix = psPrefix;
    END IF;

    IF psStartingNumber IS NOT NULL AND psStartingNumber > 0 THEN
        SET v_starting_number = psStartingNumber;
    END IF;
    
	/* ==============================
       Set default value for requested by
	============================== */
    IF psRequestedBy IS NULL OR psRequestedBy = '' THEN
        SET v_requested_by = 'SYSTEM';
    ELSE
        SET v_requested_by = psRequestedBy;
    END IF;

    /* ==============================
       Generate sequence
       ============================== */
	INSERT INTO seq_num
        SET column_name 		= psColumnName,
            sequence_value   	= 'TEMP',
            requested_by   		= v_requested_by;

		SET v_seq_id 			= LAST_INSERT_ID();

    /* ==============================
       Build final sequence
       ============================== */
    SET psSequenceNumber = CONCAT(v_prefix, v_starting_number + v_seq_id);
    
    /* ==============================
       Update stored sequence value
       ============================== */
    UPDATE seq_num
       SET sequence_value 	= psSequenceNumber
	   WHERE seq_rec_id = v_seq_id;
       
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `getWallets` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `getWallets`(
								IN     pjReqObj   JSON,
								INOUT  pjRespObj  JSON
							)
BEGIN

    DECLARE v_account_num 	     VARCHAR(50);
    DECLARE v_customer_json   	 JSON;
    DECLARE v_wallets_json    	 JSON;

    main_block: BEGIN

        -- Extract customer_Account_Number from request
        SET v_account_num    = getJval(pjReqObj, 'jData.P_ACCOUNT_NUMBER');

        -- Fetch customer JSON
        CALL getCustomer(pjReqObj, pjRespObj);
        
        SET v_customer_json = getJval(pjRespObj, 'jData.contents');

        -- If customer not found
        IF v_customer_json IS NULL THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', CONCAT('Customer does not exist ', v_account_num));

            LEAVE main_block;
        END IF;

        -- Extract wallets array from customer JSON
        SET v_wallets_json = getJval(v_customer_json, 'customer_wallets');

        -- If wallets key does not exist, return empty array
        IF v_wallets_json IS NULL THEN
			SET v_wallets_json = JSON_OBJECT(
											'Gold', 	 0,
											'Silver', 	 0,
											'Platinum',  0,
											'Cash', 	 0
										);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message',      CONCAT('Customer wallets not found for account number ', v_account_num));
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jData.contents',       v_wallets_json);

            LEAVE main_block;
		END IF;

        -- Build response

        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode',   0);
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',        'Wallets retrieved successfully');
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents',         v_wallets_json);

    END main_block;
    
    -- logging

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `get_pending_outbound_messages` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `get_pending_outbound_messages`(
                                                IN     pjReqObj     JSON,
                                                INOUT  pjResObj     JSON
                                               )
BEGIN

    /* ===================== Core Variables ===================== */
    
    DECLARE v_outbound_msgs_json            JSON;
    DECLARE v_total_messages_count          INT;

    /* ===================== Validation Variables ===================== */
    
    DECLARE v_error_message        TEXT;

    /* ===================== Error Handler ===================== */
    
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        GET STACKED DIAGNOSTICS CONDITION 1 v_error_message = MESSAGE_TEXT;

        SET pjResObj = buildJSON(pjResObj, 'jHeader.responseCode', 1);
        SET pjResObj = buildJSON(pjResObj, 'jHeader.message', CONCAT('Fetching pending outbound messages failed: ', v_error_message));

    END;

    /* ===================== Main ===================== */
    
    main_block: BEGIN

        /* ===================== Fetch All Pending Messages ===================== */
        
        SELECT      COUNT(*) AS total_count,    JSON_ARRAYAGG(outbound_msgs_json)
        INTO        v_total_messages_count,     v_outbound_msgs_json
        FROM        outbound_msgs
        WHERE       current_status = 'PENDING'
        ORDER BY CAST(JSON_UNQUOTE(JSON_EXTRACT(row_metadata, '$.created_at')) AS DATETIME) DESC;

         /* ===================== Check if pending messages exist ===================== */

        IF v_total_messages_count = 0 OR  isFalsy(v_outbound_msgs_json) THEN

            SET pjResObj = buildJSON(pjResObj, 'jHeader.responseCode',  1);
            SET pjResObj = buildJSON(pjResObj, 'jHeader.message',       'No pending outbound messages found!');

        
            LEAVE main_block;
        END IF;

        /* ===================== Success Response ===================== */

        SET pjResObj = buildJSON(pjResObj, 'jHeader.responseCode',      0);
        SET pjResObj = buildJSON(pjResObj, 'jHeader.message',           CONCAT('Total ', v_total_messages_count, ' Pending outbound messages fetched.'));
        SET pjResObj = buildJSON(pjResObj, 'jData.contents',            v_outbound_msgs_json);
        

    END main_block;

    -- insert general code here like LOG
    -- call log proc

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `handleOtpSuccess` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `handleOtpSuccess`(
									IN    pContactType    ENUM('email','phone','loginid'),
									IN    pDestination    VARCHAR(255),
                                    IN    pPurpose        VARCHAR(100),
                                    OUT   pjRespObj		  JSON
								)
BEGIN

	DECLARE v_customer_rec_id   	INT;
    DECLARE v_login_id        	    VARCHAR(100);
	DECLARE v_email         	    VARCHAR(255);
    DECLARE v_phone         	    VARCHAR(20);
    DECLARE v_reset_token    	    VARCHAR(100);
    DECLARE v_message_guid          VARCHAR(100);
    DECLARE v_outbound_msgs_rec_id  INT;

    DECLARE v_outbound_msgs_json   	JSON;
    DECLARE v_row_metadata         	JSON;

    DECLARE v_err_msg               TEXT;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN

        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Unexpected Error - ', v_err_msg));

    END;

    SET pjRespObj       = getTemplate('reqResp');

    main_block: BEGIN
    
    IF pPurpose <> 'REGISTER' THEN
    -- Get customer first
        SELECT 	 customer_rec_id, 		user_name, 	 email,   phone
        INTO  	 v_customer_rec_id, 	v_login_id,  v_email, v_phone
        FROM   	 customer
        WHERE   (email = pDestination OR phone = pDestination)
        LIMIT 1;
        
         -- If customer not found
        IF isFalsy(v_customer_rec_id) THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj,'jHeader.message', 'Customer not found');

            LEAVE main_block;
        END IF;
        
    END IF;

        CALL getSequence('OUTBOUND_MSGS.MESSAGE_GUID','MSG-', 5000,'genOTP SP', v_message_guid);

        SET v_outbound_msgs_json = getTemplate('outbound_msgs');

        SET v_outbound_msgs_json = JSON_SET(v_outbound_msgs_json,
                                            '$.parent_message_table_name',              'customer',
                                            '$.parent_message_table_rec_id',            v_customer_rec_id,
                                            '$.business_context.module_name',           'AUTH',
                                            '$.business_context.message_type',          'TRANSACTIONAL',
                                            '$.business_context.login_id',              v_login_id,
                                            '$.delivery_config.channel_number',         1,
                                            '$.delivery_config.priority_level',         1,
                                            '$.delivery_config.is_need_tracking',       TRUE,
                                            '$.sender_info.from_name',                  'GFT',
                                            '$.sender_info.from_address',               'no-reply@gft.com',
                                            '$.scheduling.scheduled_at',                NOW(),
                                            '$.scheduling.retry_interval',              60,
                                            '$.lifecycle_status.current_status',        'PENDING',
                                            '$.lifecycle_status.delivery_status',       'NOT_SENT',
                                            '$.lifecycle_status.send_attempts',         0,
                                            '$.lifecycle_status.number_of_retries',     3
                                        );

        -- =========================
		-- Row Metadata
		-- =========================
		SET v_row_metadata = getTemplate('row_metadata');

		SET v_row_metadata = JSON_SET(v_row_metadata,
									 '$.created_at', NOW(),
									 '$.created_by', 'SYSTEM'
									);

        CASE pPurpose

        -- =====================================================
            -- FORGOT LOGIN ID
            -- =====================================================
            WHEN 'FORGOT LOGIN ID' THEN

                -- Set common fields for this purpose
                SET v_outbound_msgs_json = JSON_SET(v_outbound_msgs_json,
                                                '$.object_name',                        'FORGOT_LOGIN_ID',
                                                '$.business_context.message_name',      'Forgot Login ID',
                                                '$.business_context.notes',             'Login ID recovery',
                                                '$.message_content.message_subject',    'Your Login ID',
                                                '$.message_content.message_body',       CONCAT('Your Login ID is: ', v_login_id)
                                            );

                IF pContactType = 'loginid' THEN

                    -- Send to email if exists
                    IF v_email IS NOT NULL THEN

                        CALL getSequence('OUTBOUND_MSGS.MESSAGE_GUID', 'MSG-', 5000, 'handleOtpSuccess SP', v_message_guid);

                        -- Override channel-specific fields
                        SET v_outbound_msgs_json = JSON_SET(v_outbound_msgs_json,
                                                        '$.message_guid',                       v_message_guid,
                                                        '$.business_context.notes',             'Login ID recovery via email',
                                                        '$.recipient_info.to_address',          v_email,
                                                        '$.recipient_info.is_email_verified',   FALSE
                                                    );

                        INSERT INTO outbound_msgs
                        SET message_guid                = v_message_guid,
                            parent_message_table_name   = 'customer',
                            parent_message_table_rec_id = v_customer_rec_id,
                            object_name                 = 'FORGOT_LOGIN_ID',
                            outbound_msgs_json          = v_outbound_msgs_json,
                            row_metadata                = v_row_metadata;

                        SET v_outbound_msgs_rec_id  = LAST_INSERT_ID();
                        SET v_outbound_msgs_json    = JSON_SET(v_outbound_msgs_json, '$.outbound_messages_rec_id', v_outbound_msgs_rec_id);

                        UPDATE outbound_msgs
                        SET    outbound_msgs_json   = v_outbound_msgs_json
                        WHERE  outbound_msgs_rec_id = v_outbound_msgs_rec_id;

                    END IF;

                    -- Send to phone if exists
                    IF v_phone IS NOT NULL THEN

                        CALL getSequence('OUTBOUND_MSGS.MESSAGE_GUID', 'MSG-', 5000, 'handleOtpSuccess SP', v_message_guid);

                        -- Override channel-specific fields
                        SET v_outbound_msgs_json = JSON_SET(v_outbound_msgs_json,
                                                        '$.message_guid',                       v_message_guid,
                                                        '$.business_context.notes',             'Login ID recovery via phone',
                                                        '$.recipient_info.to_address',          v_phone,
                                                        '$.recipient_info.is_email_verified',   NULL
                                                    );

                        INSERT INTO outbound_msgs
                        SET message_guid                = v_message_guid,
                            parent_message_table_name   = 'customer',
                            parent_message_table_rec_id = v_customer_rec_id,
                            object_name                 = 'FORGOT_LOGIN_ID',
                            outbound_msgs_json          = v_outbound_msgs_json,
                            row_metadata                = v_row_metadata;

                        SET v_outbound_msgs_rec_id  = LAST_INSERT_ID();
                        SET v_outbound_msgs_json    = JSON_SET(v_outbound_msgs_json, '$.outbound_messages_rec_id', v_outbound_msgs_rec_id);

                        UPDATE outbound_msgs
                        SET    outbound_msgs_json   = v_outbound_msgs_json
                        WHERE  outbound_msgs_rec_id = v_outbound_msgs_rec_id;

                    END IF;

                ELSEIF pContactType = 'email' THEN

                    CALL getSequence('OUTBOUND_MSGS.MESSAGE_GUID', 'MSG-', 5000, 'handleOtpSuccess SP', v_message_guid);

                    -- Override channel-specific fields
                    SET v_outbound_msgs_json = JSON_SET(v_outbound_msgs_json,
                                                    '$.message_guid',                       v_message_guid,
                                                    '$.business_context.notes',             'Login ID recovery via email',
                                                    '$.recipient_info.to_address',          v_email,
                                                    '$.recipient_info.is_email_verified',   FALSE
                                                );

                    INSERT INTO outbound_msgs
                    SET message_guid                = v_message_guid,
                        parent_message_table_name   = 'customer',
                        parent_message_table_rec_id = v_customer_rec_id,
                        object_name                 = 'FORGOT_LOGIN_ID',
                        outbound_msgs_json          = v_outbound_msgs_json,
                        row_metadata                = v_row_metadata;

                    SET v_outbound_msgs_rec_id  = LAST_INSERT_ID();
                    SET v_outbound_msgs_json    = JSON_SET(v_outbound_msgs_json, '$.outbound_messages_rec_id', v_outbound_msgs_rec_id);

                    UPDATE outbound_msgs
                    SET    outbound_msgs_json   = v_outbound_msgs_json
                    WHERE  outbound_msgs_rec_id = v_outbound_msgs_rec_id;

                ELSEIF pContactType = 'phone' THEN

                    CALL getSequence('OUTBOUND_MSGS.MESSAGE_GUID', 'MSG-', 5000, 'handleOtpSuccess SP', v_message_guid);

                    -- Override channel-specific fields
                    SET v_outbound_msgs_json = JSON_SET(v_outbound_msgs_json,
                                                    '$.message_guid',                       v_message_guid,
                                                    '$.business_context.notes',             'Login ID recovery via phone',
                                                    '$.recipient_info.to_address',          v_phone,
                                                    '$.recipient_info.is_email_verified',   NULL
                                                );

                    INSERT INTO outbound_msgs
                    SET message_guid                = v_message_guid,
                        parent_message_table_name   = 'customer',
                        parent_message_table_rec_id = v_customer_rec_id,
                        object_name                 = 'FORGOT_LOGIN_ID',
                        outbound_msgs_json          = v_outbound_msgs_json,
                        row_metadata                = v_row_metadata;

                    SET v_outbound_msgs_rec_id  = LAST_INSERT_ID();
                    SET v_outbound_msgs_json    = JSON_SET(v_outbound_msgs_json, '$.outbound_messages_rec_id', v_outbound_msgs_rec_id);

                    UPDATE outbound_msgs
                    SET    outbound_msgs_json   = v_outbound_msgs_json
                    WHERE  outbound_msgs_rec_id = v_outbound_msgs_rec_id;

                END IF;

                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',      'Success - Login ID sent via outbound message');

            -- =====================================================
            -- RESET PASSWORD
            -- =====================================================
            WHEN 'RESET PASSWORD' THEN

                SET v_reset_token = UUID();

                UPDATE  customer
                SET     customer_json = JSON_SET(customer_json,
                                            '$.otp_reset_token',    v_reset_token,
                                            '$.reset_token_expiry', NOW() + INTERVAL 10 MINUTE
                                        )
                WHERE   customer_rec_id = v_customer_rec_id;

                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode',                           0);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',                                'Reset token generated successfully');
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.reset_token',                     v_reset_token);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.reset_token_expires_in_minutes',  10);

            -- =====================================================
            -- REGISTER (placeholder)
            -- =====================================================
            WHEN 'REGISTER' THEN

                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',      'OTP verified for registration');

            -- =====================================================
            -- DEFAULT
            -- =====================================================
            ELSE

                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
                SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',      'Invalid purpose');

        END CASE;

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `insertOrder` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `insertOrder`(
                                IN  pjReqObj    JSON,
                                OUT psResObj    JSON
                            )
BEGIN
    /* ===================== Column Variables ===================== */
    DECLARE v_order_rec_id              INT;
    DECLARE v_linked_order_rec_id       INT;
    DECLARE v_customer_rec_id           INT;
    DECLARE v_account_number            VARCHAR(50);
    DECLARE v_order_number              VARCHAR(50);
    DECLARE v_receipt_number            VARCHAR(50);
    DECLARE v_order_date                DATETIME;
    DECLARE v_order_status              VARCHAR(20);
    DECLARE v_next_action_required      VARCHAR(20);
    DECLARE v_order_cat                 VARCHAR(10);
    DECLARE v_order_type                VARCHAR(20);
    DECLARE v_metal                     VARCHAR(50);
    DECLARE v_order_sub_type            VARCHAR(50);  -- Market, Manual, Products

    /* ===================== Rate Variables ===================== */
    DECLARE v_rate_rec_id               INT;
    DECLARE v_spot_rate                 DECIMAL(18,4);
    DECLARE v_currency_unit             VARCHAR(10);
    DECLARE v_rate_source               VARCHAR(100);
    DECLARE v_fx_rate                   DECIMAL(18,4);
    DECLARE v_fx_source                 VARCHAR(100);

    /* ===================== Exchange Variables ===================== */
    DECLARE v_exchange_sell_rec_id      INT;
    DECLARE v_exchange_buy_rec_id       INT;
    DECLARE v_exchange_order_number     VARCHAR(50);
    DECLARE v_exchange_receipt_number   VARCHAR(50);

    /* ===================== Exchange Rate Variables (from_metal / to_metal) ===================== */
    DECLARE v_from_rate_rec_id          INT;
    DECLARE v_from_spot_rate            DECIMAL(18,4);
    DECLARE v_from_currency_unit        VARCHAR(10);
    DECLARE v_from_rate_source          VARCHAR(100);
    DECLARE v_from_fx_rate              DECIMAL(18,4);
    DECLARE v_from_fx_source            VARCHAR(100);

    DECLARE v_to_rate_rec_id            INT;
    DECLARE v_to_spot_rate              DECIMAL(18,4);
    DECLARE v_to_currency_unit          VARCHAR(10);
    DECLARE v_to_rate_source            VARCHAR(100);
    DECLARE v_to_fx_rate                DECIMAL(18,4);
    DECLARE v_to_fx_source              VARCHAR(100);

    /* ===================== JSON Objects ===================== */
    DECLARE v_order_json                JSON;
    DECLARE v_row_metadata              JSON;

    /* ===================== Validation Variables ===================== */
    DECLARE v_errors                    JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg                   TEXT;

    /* ===================== Error Handler ===================== */
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
        ROLLBACK;
        SET psResObj = JSON_OBJECT(
                                    'status',       'error',
                                    'status_code',  '1',
                                    'message',      'Insertion failed',
                                    'system_error', v_err_msg
                                  );
    END;

    /* ===================== Main ===================== */
    main_block: BEGIN

        /* ===================== Extract Common Fields from Request Object ===================== */
        SET v_customer_rec_id   = getJval(pjReqObj, 'customer_rec_id');
        SET v_account_number    = getJval(pjReqObj, 'account_number');
        SET v_order_type        = getJval(pjReqObj, 'order_type');      -- Buy, Sell, Exchange, Redeem
        SET v_order_sub_type    = getJval(pjReqObj, 'order_sub_type');  -- Market, Manual, Products
        SET v_order_cat         = getJval(pjReqObj, 'order_cat');       -- DO, IOC, GTC
        SET v_metal             = getJval(pjReqObj, 'metal');           -- Gold, Silver, Platinum
        SET v_order_date        = NOW();

        /* ===================== Common Validation ===================== */
        IF isFalsy(v_customer_rec_id) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'customer_rec_id is required');
        END IF;

        IF isFalsy(v_order_type) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'order_type is required');
        END IF;

        IF isFalsy(v_metal) AND v_order_type != 'Exchange' THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'metal is required');
        END IF;

        IF JSON_LENGTH(v_errors) > 0 THEN
            SET psResObj = JSON_OBJECT(
                                        'status',       'error',
                                        'status_code',  '2',
                                        'message',      'Validation failed',
                                        'errors',       v_errors
                                      );
            LEAVE main_block;
        END IF;

        /* ===================== Fetch Latest Rate from Rates Table ===================== */
        /* Skip rate fetch for Exchange — rates fetched per leg inside Exchange block */
        IF v_order_type != 'Exchange' THEN
            SELECT  rate_rec_id,    spot_rate,      currency_unit,      rate_source,    foreign_exchange_rate,  foreign_exchange_source
            INTO    v_rate_rec_id,  v_spot_rate,    v_currency_unit,    v_rate_source,  v_fx_rate,              v_fx_source
            FROM    rates
            WHERE   metal       = v_metal
            AND     is_active   = 1
            ORDER BY created_at DESC
            LIMIT 1;
        END IF;

        /* ===================== Get Templates ===================== */
        SET v_order_json    = getTemplate('orders');
        SET v_row_metadata  = getTemplate('row_metadata');

        /* ===================== Branch by Order Type ===================== */

        -- -----------------------------------------------------------------------
        -- BUY
        -- Sub types: Market, Manual, Products
        -- -----------------------------------------------------------------------
        IF v_order_type = 'Buy' THEN

            SET v_order_status          = 'pending';
            SET v_next_action_required  = 'approved';

            -- Buy Market Order (Reserve Gold Slice - Auto Select)
            IF v_order_sub_type = 'Market' THEN

                IF isFalsy(getJval(pjReqObj, 'customer_request.amount')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'amount is required for Market order');
                END IF;

                IF JSON_LENGTH(v_errors) > 0 THEN
                    SET psResObj = JSON_OBJECT('status', 'error', 'status_code', '2', 'message', 'Validation failed', 'errors', v_errors);
                    LEAVE main_block;
                END IF;

                SET v_order_cat = 'DO';  -- Market orders are Day Orders

                SET v_order_json = JSON_SET(v_order_json,
                    '$.order_number',                           v_order_number,
                    '$.receipt_number',                         v_receipt_number,
                    '$.order_date',                             v_order_date,
                    '$.order_status',                           v_order_status,
                    '$.next_action_required',                   v_next_action_required,
                    '$.order_cat',                              v_order_cat,
                    '$.order_type',                             v_order_type,
                    '$.metal',                                  v_metal,
                    '$.customer_info.customer_rec_id',          v_customer_rec_id,
                    '$.customer_info.customer_name',            getJval(pjReqObj, 'customer_info.customer_name'),
                    '$.customer_info.customer_account_number',  v_account_number,
                    '$.customer_info.customer_phone',           getJval(pjReqObj, 'customer_info.customer_phone'),
                    '$.customer_info.whatsapp',                 getJval(pjReqObj, 'customer_info.whatsapp'),
                    '$.customer_info.customer_email',           getJval(pjReqObj, 'customer_info.customer_email'),
                    '$.customer_info.customer_address',         getJval(pjReqObj, 'customer_info.customer_address'),
                    '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'customer_info.customer_ip_address'),
                    '$.customer_info.latitude',                 getJval(pjReqObj, 'customer_info.latitude'),
                    '$.customer_info.longitude',                getJval(pjReqObj, 'customer_info.longitude'),
                    '$.customer_request.amount',                getJval(pjReqObj, 'customer_request.amount'),
                    '$.customer_request.date_of_purchase',      v_order_date,
                    '$.customer_request.payment_method',        getJval(pjReqObj, 'customer_request.payment_method'),
                    '$.rate_info.rate_rec_id',                  v_rate_rec_id,
                    '$.rate_info.spot_rate',                    v_spot_rate,
                    '$.rate_info.currency_unit',                v_currency_unit,
                    '$.rate_info.rate_source',                  v_rate_source,
                    '$.rate_info.foreign_exchange_rate',        v_fx_rate,
                    '$.rate_info.foreign_exchange_source',      v_fx_source
                );

            -- Buy Manual Price
            ELSEIF v_order_sub_type = 'Manual' THEN

                IF isFalsy(getJval(pjReqObj, 'customer_request.rate')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'rate is required for Manual order');
                END IF;
                IF isFalsy(getJval(pjReqObj, 'customer_request.weight')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'weight is required for Manual order');
                END IF;
                IF isFalsy(getJval(pjReqObj, 'customer_request.Expiration_time')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'Expiration_time is required for Manual order');
                END IF;

                IF JSON_LENGTH(v_errors) > 0 THEN
                    SET psResObj = JSON_OBJECT('status', 'error', 'status_code', '2', 'message', 'Validation failed', 'errors', v_errors);
                    LEAVE main_block;
                END IF;

                SET v_order_json = JSON_SET(v_order_json,
                    '$.order_number',                               v_order_number,
                    '$.receipt_number',                             v_receipt_number,
                    '$.order_date',                                 v_order_date,
                    '$.order_status',                               v_order_status,
                    '$.next_action_required',                       v_next_action_required,
                    '$.order_cat',                                  v_order_cat,
                    '$.order_type',                                 v_order_type,
                    '$.metal',                                      v_metal,
                    '$.customer_info.customer_rec_id',              v_customer_rec_id,
                    '$.customer_info.customer_name',                getJval(pjReqObj, 'customer_info.customer_name'),
                    '$.customer_info.customer_account_number',      v_account_number,
                    '$.customer_info.customer_phone',               getJval(pjReqObj, 'customer_info.customer_phone'),
                    '$.customer_info.whatsapp',                     getJval(pjReqObj, 'customer_info.whatsapp'),
                    '$.customer_info.customer_email',               getJval(pjReqObj, 'customer_info.customer_email'),
                    '$.customer_info.customer_address',             getJval(pjReqObj, 'customer_info.customer_address'),
                    '$.customer_info.customer_ip_address',          getJval(pjReqObj, 'customer_info.customer_ip_address'),
                    '$.customer_info.latitude',                     getJval(pjReqObj, 'customer_info.latitude'),
                    '$.customer_info.longitude',                    getJval(pjReqObj, 'customer_info.longitude'),
                    '$.customer_request.rate',                      getJval(pjReqObj, 'customer_request.rate'),
                    '$.customer_request.weight',                    getJval(pjReqObj, 'customer_request.weight'),
                    '$.customer_request.amount',                    getJval(pjReqObj, 'customer_request.amount'),
                    '$.customer_request.Expiration_time',           getJval(pjReqObj, 'customer_request.Expiration_time'),
                    '$.customer_request.is_partial_fill_allowed',   getJval(pjReqObj, 'customer_request.is_partial_fill_allowed'),
                    '$.customer_request.payment_method',            getJval(pjReqObj, 'customer_request.payment_method'),
                    '$.customer_request.date_of_purchase',          v_order_date,
                    '$.rate_info.rate_rec_id',                      v_rate_rec_id,
                    '$.rate_info.spot_rate',                        v_spot_rate,
                    '$.rate_info.currency_unit',                    v_currency_unit,
                    '$.rate_info.rate_source',                      v_rate_source,
                    '$.rate_info.foreign_exchange_rate',            v_fx_rate,
                    '$.rate_info.foreign_exchange_source',          v_fx_source
                );

            -- Buy Gold Products
            ELSEIF v_order_sub_type = 'Products' THEN

                IF isFalsy(getJval(pjReqObj, 'buy_items')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'buy_items are required for Products order');
                END IF;

                IF JSON_LENGTH(v_errors) > 0 THEN
                    SET psResObj = JSON_OBJECT('status', 'error', 'status_code', '2', 'message', 'Validation failed', 'errors', v_errors);
                    LEAVE main_block;
                END IF;

                SET v_order_json = JSON_SET(v_order_json,
                    '$.order_number',                           v_order_number,
                    '$.receipt_number',                         v_receipt_number,
                    '$.order_date',                             v_order_date,
                    '$.order_status',                           v_order_status,
                    '$.next_action_required',                   v_next_action_required,
                    '$.order_cat',                              v_order_cat,
                    '$.order_type',                             v_order_type,
                    '$.metal',                                  v_metal,
                    '$.customer_info.customer_rec_id',          v_customer_rec_id,
                    '$.customer_info.customer_name',            getJval(pjReqObj, 'customer_info.customer_name'),
                    '$.customer_info.customer_account_number',  v_account_number,
                    '$.customer_info.customer_phone',           getJval(pjReqObj, 'customer_info.customer_phone'),
                    '$.customer_info.whatsapp',                 getJval(pjReqObj, 'customer_info.whatsapp'),
                    '$.customer_info.customer_email',           getJval(pjReqObj, 'customer_info.customer_email'),
                    '$.customer_info.customer_address',         getJval(pjReqObj, 'customer_info.customer_address'),
                    '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'customer_info.customer_ip_address'),
                    '$.customer_info.latitude',                 getJval(pjReqObj, 'customer_info.latitude'),
                    '$.customer_info.longitude',                getJval(pjReqObj, 'customer_info.longitude'),
                    '$.buy_items',                              getJval(pjReqObj, 'buy_items'),
                    '$.customer_request.payment_method',        getJval(pjReqObj, 'customer_request.payment_method'),
                    '$.customer_request.date_of_purchase',      v_order_date,
                    '$.rate_info.rate_rec_id',                  v_rate_rec_id,
                    '$.rate_info.spot_rate',                    v_spot_rate,
                    '$.rate_info.currency_unit',                v_currency_unit,
                    '$.rate_info.rate_source',                  v_rate_source,
                    '$.rate_info.foreign_exchange_rate',        v_fx_rate,
                    '$.rate_info.foreign_exchange_source',      v_fx_source
                );

            END IF; -- End Buy sub types

            START TRANSACTION;
                CALL getSequence('ORDER.ORDER_NUM',   NULL, NULL, 'insertOrder sp', v_order_number);
                CALL getSequence('ORDER.RECEIPT_NUM', NULL, NULL, 'insertOrder sp', v_receipt_number);

                INSERT INTO orders
                    SET customer_rec_id         = v_customer_rec_id,
                        account_number          = v_account_number,
                        order_number            = v_order_number,
                        receipt_number          = v_receipt_number,
                        order_date              = v_order_date,
                        order_status            = v_order_status,
                        next_action_required    = v_next_action_required,
                        order_cat               = v_order_cat,
                        order_type              = v_order_type,
                        metal                   = v_metal,
                        order_json              = v_order_json,
                        row_metadata            = v_row_metadata;

                SET v_order_rec_id = LAST_INSERT_ID();
            COMMIT;

        -- -----------------------------------------------------------------------
        -- SELL
        -- Sub types: Market / Auto-Select, Manual
        -- -----------------------------------------------------------------------
        ELSEIF v_order_type = 'Sell' THEN

            SET v_order_status          = 'pending';
            SET v_next_action_required  = 'approved';

            -- Sell Market / Auto Select
            IF v_order_sub_type = 'Market' THEN

                IF isFalsy(getJval(pjReqObj, 'customer_request.weight')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'weight is required for Market Sell order');
                END IF;

                IF JSON_LENGTH(v_errors) > 0 THEN
                    SET psResObj = JSON_OBJECT('status', 'error', 'status_code', '2', 'message', 'Validation failed', 'errors', v_errors);
                    LEAVE main_block;
                END IF;

                SET v_order_cat = 'DO';

                SET v_order_json = JSON_SET(v_order_json,
                    '$.order_number',                           v_order_number,
                    '$.receipt_number',                         v_receipt_number,
                    '$.order_date',                             v_order_date,
                    '$.order_status',                           v_order_status,
                    '$.next_action_required',                   v_next_action_required,
                    '$.order_cat',                              v_order_cat,
                    '$.order_type',                             v_order_type,
                    '$.metal',                                  v_metal,
                    '$.customer_info.customer_rec_id',          v_customer_rec_id,
                    '$.customer_info.customer_name',            getJval(pjReqObj, 'customer_info.customer_name'),
                    '$.customer_info.customer_account_number',  v_account_number,
                    '$.customer_info.customer_phone',           getJval(pjReqObj, 'customer_info.customer_phone'),
                    '$.customer_info.whatsapp',                 getJval(pjReqObj, 'customer_info.whatsapp'),
                    '$.customer_info.customer_email',           getJval(pjReqObj, 'customer_info.customer_email'),
                    '$.customer_info.customer_address',         getJval(pjReqObj, 'customer_info.customer_address'),
                    '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'customer_info.customer_ip_address'),
                    '$.customer_info.latitude',                 getJval(pjReqObj, 'customer_info.latitude'),
                    '$.customer_info.longitude',                getJval(pjReqObj, 'customer_info.longitude'),
                    '$.customer_request.weight',                getJval(pjReqObj, 'customer_request.weight'),
                    '$.customer_request.date_of_purchase',      v_order_date,
                    '$.rate_info.rate_rec_id',                  v_rate_rec_id,
                    '$.rate_info.spot_rate',                    v_spot_rate,
                    '$.rate_info.currency_unit',                v_currency_unit,
                    '$.rate_info.rate_source',                  v_rate_source,
                    '$.rate_info.foreign_exchange_rate',        v_fx_rate,
                    '$.rate_info.foreign_exchange_source',      v_fx_source
                );

            -- Sell Manual
            ELSEIF v_order_sub_type = 'Manual' THEN

                IF isFalsy(getJval(pjReqObj, 'customer_request.rate')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'rate is required for Manual Sell order');
                END IF;
                IF isFalsy(getJval(pjReqObj, 'customer_request.weight')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'weight is required for Manual Sell order');
                END IF;
                IF isFalsy(getJval(pjReqObj, 'customer_request.Expiration_time')) THEN
                    SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'Expiration_time is required for Manual Sell order');
                END IF;

                IF JSON_LENGTH(v_errors) > 0 THEN
                    SET psResObj = JSON_OBJECT('status', 'error', 'status_code', '2', 'message', 'Validation failed', 'errors', v_errors);
                    LEAVE main_block;
                END IF;

                SET v_order_json = JSON_SET(v_order_json,
                    '$.order_number',                               v_order_number,
                    '$.receipt_number',                             v_receipt_number,
                    '$.order_date',                                 v_order_date,
                    '$.order_status',                               v_order_status,
                    '$.next_action_required',                       v_next_action_required,
                    '$.order_cat',                                  v_order_cat,
                    '$.order_type',                                 v_order_type,
                    '$.metal',                                      v_metal,
                    '$.customer_info.customer_rec_id',              v_customer_rec_id,
                    '$.customer_info.customer_name',                getJval(pjReqObj, 'customer_info.customer_name'),
                    '$.customer_info.customer_account_number',      v_account_number,
                    '$.customer_info.customer_phone',               getJval(pjReqObj, 'customer_info.customer_phone'),
                    '$.customer_info.whatsapp',                     getJval(pjReqObj, 'customer_info.whatsapp'),
                    '$.customer_info.customer_email',               getJval(pjReqObj, 'customer_info.customer_email'),
                    '$.customer_info.customer_address',             getJval(pjReqObj, 'customer_info.customer_address'),
                    '$.customer_info.customer_ip_address',          getJval(pjReqObj, 'customer_info.customer_ip_address'),
                    '$.customer_info.latitude',                     getJval(pjReqObj, 'customer_info.latitude'),
                    '$.customer_info.longitude',                    getJval(pjReqObj, 'customer_info.longitude'),
                    '$.customer_request.rate',                      getJval(pjReqObj, 'customer_request.rate'),
                    '$.customer_request.weight',                    getJval(pjReqObj, 'customer_request.weight'),
                    '$.customer_request.amount',                    getJval(pjReqObj, 'customer_request.amount'),
                    '$.customer_request.Expiration_time',           getJval(pjReqObj, 'customer_request.Expiration_time'),
                    '$.customer_request.is_partial_fill_allowed',   getJval(pjReqObj, 'customer_request.is_partial_fill_allowed'),
                    '$.customer_request.date_of_purchase',          v_order_date,
                    '$.rate_info.rate_rec_id',                      v_rate_rec_id,
                    '$.rate_info.spot_rate',                        v_spot_rate,
                    '$.rate_info.currency_unit',                    v_currency_unit,
                    '$.rate_info.rate_source',                      v_rate_source,
                    '$.rate_info.foreign_exchange_rate',            v_fx_rate,
                    '$.rate_info.foreign_exchange_source',          v_fx_source
                );

            END IF; -- End Sell sub types

            START TRANSACTION;
                CALL getSequence('ORDER.ORDER_NUM',   NULL, NULL, 'insertOrder sp', v_order_number);
                CALL getSequence('ORDER.RECEIPT_NUM', NULL, NULL, 'insertOrder sp', v_receipt_number);

                INSERT INTO orders
                    SET customer_rec_id         = v_customer_rec_id,
                        account_number          = v_account_number,
                        order_number            = v_order_number,
                        receipt_number          = v_receipt_number,
                        order_date              = v_order_date,
                        order_status            = v_order_status,
                        next_action_required    = v_next_action_required,
                        order_cat               = v_order_cat,
                        order_type              = v_order_type,
                        metal                   = v_metal,
                        order_json              = v_order_json,
                        row_metadata            = v_row_metadata;

                SET v_order_rec_id = LAST_INSERT_ID();
            COMMIT;

        -- -----------------------------------------------------------------------
        -- EXCHANGE
        -- Two linked orders: one Sell (from_metal) + one Buy (to_metal)
        -- -----------------------------------------------------------------------
        ELSEIF v_order_type = 'Exchange' THEN

            IF isFalsy(getJval(pjReqObj, 'exchange.from_metal')) THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'from_metal is required for Exchange');
            END IF;
            IF isFalsy(getJval(pjReqObj, 'exchange.to_metal')) THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'to_metal is required for Exchange');
            END IF;
            IF isFalsy(getJval(pjReqObj, 'exchange.weight')) THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'weight is required for Exchange');
            END IF;

            IF JSON_LENGTH(v_errors) > 0 THEN
                SET psResObj = JSON_OBJECT('status', 'error', 'status_code', '2', 'message', 'Validation failed', 'errors', v_errors);
                LEAVE main_block;
            END IF;

            SET v_order_status          = 'pending';
            SET v_next_action_required  = 'approved';
            SET v_order_cat             = 'DO';

            /* Fetch rates separately for from_metal and to_metal */
            SELECT  rate_rec_id,        spot_rate,          currency_unit,          rate_source,        foreign_exchange_rate,  foreign_exchange_source
            INTO    v_from_rate_rec_id, v_from_spot_rate,   v_from_currency_unit,   v_from_rate_source, v_from_fx_rate,         v_from_fx_source
            FROM    rates
            WHERE   metal       = getJval(pjReqObj, 'exchange.from_metal')
            AND     is_active   = 1
            ORDER BY created_at DESC
            LIMIT 1;

            SELECT  rate_rec_id,        spot_rate,          currency_unit,          rate_source,        foreign_exchange_rate,  foreign_exchange_source
            INTO    v_to_rate_rec_id,   v_to_spot_rate,     v_to_currency_unit,     v_to_rate_source,   v_to_fx_rate,           v_to_fx_source
            FROM    rates
            WHERE   metal       = getJval(pjReqObj, 'exchange.to_metal')
            AND     is_active   = 1
            ORDER BY created_at DESC
            LIMIT 1;

            /* Sequences generated INSIDE transaction */
            START TRANSACTION;

                CALL getSequence('ORDER.ORDER_NUM',   NULL, NULL, 'insertOrder sp', v_order_number);
                CALL getSequence('ORDER.RECEIPT_NUM', NULL, NULL, 'insertOrder sp', v_receipt_number);
                CALL getSequence('ORDER.ORDER_NUM',   NULL, NULL, 'insertOrder sp', v_exchange_order_number);
                CALL getSequence('ORDER.RECEIPT_NUM', NULL, NULL, 'insertOrder sp', v_exchange_receipt_number);

                -- Leg 1: SELL order (from_metal)
                SET v_order_json = getTemplate('orders');
                SET v_order_json = JSON_SET(v_order_json,
                    '$.order_number',                           v_order_number,
                    '$.receipt_number',                         v_receipt_number,
                    '$.order_date',                             v_order_date,
                    '$.order_status',                           v_order_status,
                    '$.next_action_required',                   v_next_action_required,
                    '$.order_cat',                              v_order_cat,
                    '$.order_type',                             'Sell',
                    '$.metal',                                  getJval(pjReqObj, 'exchange.from_metal'),
                    '$.customer_info.customer_rec_id',          v_customer_rec_id,
                    '$.customer_info.customer_name',            getJval(pjReqObj, 'customer_info.customer_name'),
                    '$.customer_info.customer_account_number',  v_account_number,
                    '$.customer_info.customer_phone',           getJval(pjReqObj, 'customer_info.customer_phone'),
                    '$.customer_info.whatsapp',                 getJval(pjReqObj, 'customer_info.whatsapp'),
                    '$.customer_info.customer_email',           getJval(pjReqObj, 'customer_info.customer_email'),
                    '$.customer_info.customer_address',         getJval(pjReqObj, 'customer_info.customer_address'),
                    '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'customer_info.customer_ip_address'),
                    '$.customer_info.latitude',                 getJval(pjReqObj, 'customer_info.latitude'),
                    '$.customer_info.longitude',                getJval(pjReqObj, 'customer_info.longitude'),
                    '$.customer_request.weight',                getJval(pjReqObj, 'exchange.weight'),
                    '$.customer_request.date_of_purchase',      v_order_date,
                    '$.rate_info.rate_rec_id',                  v_from_rate_rec_id,
                    '$.rate_info.spot_rate',                    v_from_spot_rate,
                    '$.rate_info.currency_unit',                v_from_currency_unit,
                    '$.rate_info.rate_source',                  v_from_rate_source,
                    '$.rate_info.foreign_exchange_rate',        v_from_fx_rate,
                    '$.rate_info.foreign_exchange_source',      v_from_fx_source
                );

                INSERT INTO orders
                    SET customer_rec_id         = v_customer_rec_id,
                        account_number          = v_account_number,
                        order_number            = v_order_number,
                        receipt_number          = v_receipt_number,
                        order_date              = v_order_date,
                        order_status            = v_order_status,
                        next_action_required    = v_next_action_required,
                        order_cat               = v_order_cat,
                        order_type              = 'Sell',
                        metal                   = getJval(pjReqObj, 'exchange.from_metal'),
                        order_json              = v_order_json,
                        row_metadata            = v_row_metadata;

                SET v_exchange_sell_rec_id = LAST_INSERT_ID();

                -- Leg 2: BUY order (to_metal)
                SET v_order_json = getTemplate('orders');
                SET v_order_json = JSON_SET(v_order_json,
                    '$.order_number',                           v_exchange_order_number,
                    '$.receipt_number',                         v_exchange_receipt_number,
                    '$.order_date',                             v_order_date,
                    '$.order_status',                           v_order_status,
                    '$.next_action_required',                   v_next_action_required,
                    '$.order_cat',                              v_order_cat,
                    '$.order_type',                             'Buy',
                    '$.metal',                                  getJval(pjReqObj, 'exchange.to_metal'),
                    '$.customer_info.customer_rec_id',          v_customer_rec_id,
                    '$.customer_info.customer_name',            getJval(pjReqObj, 'customer_info.customer_name'),
                    '$.customer_info.customer_account_number',  v_account_number,
                    '$.customer_info.customer_phone',           getJval(pjReqObj, 'customer_info.customer_phone'),
                    '$.customer_info.whatsapp',                 getJval(pjReqObj, 'customer_info.whatsapp'),
                    '$.customer_info.customer_email',           getJval(pjReqObj, 'customer_info.customer_email'),
                    '$.customer_info.customer_address',         getJval(pjReqObj, 'customer_info.customer_address'),
                    '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'customer_info.customer_ip_address'),
                    '$.customer_info.latitude',                 getJval(pjReqObj, 'customer_info.latitude'),
                    '$.customer_info.longitude',                getJval(pjReqObj, 'customer_info.longitude'),
                    '$.customer_request.weight',                getJval(pjReqObj, 'exchange.to_weight'),
                    '$.customer_request.date_of_purchase',      v_order_date,
                    '$.rate_info.rate_rec_id',                  v_to_rate_rec_id,
                    '$.rate_info.spot_rate',                    v_to_spot_rate,
                    '$.rate_info.currency_unit',                v_to_currency_unit,
                    '$.rate_info.rate_source',                  v_to_rate_source,
                    '$.rate_info.foreign_exchange_rate',        v_to_fx_rate,
                    '$.rate_info.foreign_exchange_source',      v_to_fx_source
                );

                INSERT INTO orders
                    SET customer_rec_id         = v_customer_rec_id,
                        account_number          = v_account_number,
                        order_number            = v_exchange_order_number,
                        receipt_number          = v_exchange_receipt_number,
                        order_date              = v_order_date,
                        order_status            = v_order_status,
                        next_action_required    = v_next_action_required,
                        order_cat               = v_order_cat,
                        order_type              = 'Buy',
                        metal                   = getJval(pjReqObj, 'exchange.to_metal'),
                        order_json              = v_order_json,
                        row_metadata            = v_row_metadata;

                SET v_exchange_buy_rec_id = LAST_INSERT_ID();

                UPDATE orders SET linked_order_rec_id = v_exchange_buy_rec_id  WHERE order_rec_id = v_exchange_sell_rec_id;
                UPDATE orders SET linked_order_rec_id = v_exchange_sell_rec_id WHERE order_rec_id = v_exchange_buy_rec_id;

                SET v_order_rec_id = v_exchange_sell_rec_id;

            COMMIT;

        -- -----------------------------------------------------------------------
        -- REDEEM
        -- Multiple products as array in buy_items, single order row
        -- -----------------------------------------------------------------------
        ELSEIF v_order_type = 'Redeem' THEN

            IF isFalsy(getJval(pjReqObj, 'buy_items')) THEN
                SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'buy_items are required for Redeem order');
            END IF;

            IF JSON_LENGTH(v_errors) > 0 THEN
                SET psResObj = JSON_OBJECT('status', 'error', 'status_code', '2', 'message', 'Validation failed', 'errors', v_errors);
                LEAVE main_block;
            END IF;

            SET v_order_status          = 'pending';
            SET v_next_action_required  = 'approved';
            SET v_order_cat             = 'DO';

            SET v_order_json = JSON_SET(v_order_json,
                '$.order_number',                           v_order_number,
                '$.receipt_number',                         v_receipt_number,
                '$.order_date',                             v_order_date,
                '$.order_status',                           v_order_status,
                '$.next_action_required',                   v_next_action_required,
                '$.order_cat',                              v_order_cat,
                '$.order_type',                             v_order_type,
                '$.metal',                                  v_metal,
                '$.customer_info.customer_rec_id',          v_customer_rec_id,
                '$.customer_info.customer_name',            getJval(pjReqObj, 'customer_info.customer_name'),
                '$.customer_info.customer_account_number',  v_account_number,
                '$.customer_info.customer_phone',           getJval(pjReqObj, 'customer_info.customer_phone'),
                '$.customer_info.whatsapp',                 getJval(pjReqObj, 'customer_info.whatsapp'),
                '$.customer_info.customer_email',           getJval(pjReqObj, 'customer_info.customer_email'),
                '$.customer_info.customer_address',         getJval(pjReqObj, 'customer_info.customer_address'),
                '$.customer_info.customer_ip_address',      getJval(pjReqObj, 'customer_info.customer_ip_address'),
                '$.customer_info.latitude',                 getJval(pjReqObj, 'customer_info.latitude'),
                '$.customer_info.longitude',                getJval(pjReqObj, 'customer_info.longitude'),
                '$.buy_items',                              getJval(pjReqObj, 'buy_items'),
                '$.order_pickup_info.pickup_required',      TRUE,
                '$.order_pickup_info.pickup_status',        'Pending',
                '$.rate_info.rate_rec_id',                  v_rate_rec_id,
                '$.rate_info.spot_rate',                    v_spot_rate,
                '$.rate_info.currency_unit',                v_currency_unit,
                '$.rate_info.rate_source',                  v_rate_source,
                '$.rate_info.foreign_exchange_rate',        v_fx_rate,
                '$.rate_info.foreign_exchange_source',      v_fx_source
            );

            START TRANSACTION;
                CALL getSequence('ORDER.ORDER_NUM',   NULL, NULL, 'insertOrder sp', v_order_number);
                CALL getSequence('ORDER.RECEIPT_NUM', NULL, NULL, 'insertOrder sp', v_receipt_number);

                INSERT INTO orders
                    SET customer_rec_id         = v_customer_rec_id,
                        account_number          = v_account_number,
                        order_number            = v_order_number,
                        receipt_number          = v_receipt_number,
                        order_date              = v_order_date,
                        order_status            = v_order_status,
                        next_action_required    = v_next_action_required,
                        order_cat               = v_order_cat,
                        order_type              = v_order_type,
                        metal                   = v_metal,
                        order_json              = v_order_json,
                        row_metadata            = v_row_metadata;

                SET v_order_rec_id = LAST_INSERT_ID();
            COMMIT;

        ELSE
            -- Unknown order type
            SET psResObj = JSON_OBJECT(
                                        'status',       'error',
                                        'status_code',  '3',
                                        'message',      'Unknown order_type. Must be Buy, Sell, Exchange or Redeem'
                                      );
            LEAVE main_block;
        END IF;

        /* ===================== Success Response ===================== */
        SET psResObj = JSON_OBJECT(
                                    'status',           'success',
                                    'status_code',      '0',
                                    'message',          'Order inserted successfully',
                                    'order_rec_id',     v_order_rec_id,
                                    'order_number',     v_order_number,
                                    'receipt_number',   v_receipt_number,
                                    'order_type',       v_order_type,
                                    'order_sub_type',   v_order_sub_type
                                  );

    END; -- main_block

END ;;
DELIMITER ;
