CREATE DEFINER=`root`@`localhost` PROCEDURE `logActivity`(
								IN psLoggingObj     VARCHAR(64),
								IN pjlogJson        JSON
							)
BEGIN

    DECLARE v_activity_log_rec_id   INT;
	DECLARE v_activity_log          JSON;
    DECLARE v_row_metadata 		    JSON;


    SET v_activity_log          = getTemplate('activity_log');
    SET v_activity_log          = fillTemplate(pjlogJson, v_activity_log);

    SET v_activity_log          = buildJSONSmart(v_activity_log,   'log_time',      NOW());
    
    SET v_row_metadata 			= getTemplate('row_metadata');

    SET v_row_metadata          = buildJSONSmart(v_row_metadata,   'created_at',      NOW());
    SET v_row_metadata          = buildJSONSmart(v_row_metadata,   'created_by',      getJval(pjlogJson, 'P_CUSTOMER_REC_ID'));


    INSERT INTO user_activity_log
    SET logging_object          = psLoggingObj,
        action_code       		= getJval(pjlogJson, 'action_code'),
        client_ip           	= getJval(pjlogJson, 'client_ip'),
        log_time              	= NOW(),

        user_activity_log_json  = v_activity_log,
        row_meta_data		    = v_row_metadata;
    
    SET v_activity_log_rec_id   = LAST_INSERT_ID();

    SET v_activity_log          = buildJSONSmart(v_activity_log, 'activity_log_rec_id', v_activity_log_rec_id);

    UPDATE  user_activity_log
	SET 	user_activity_log_json    = v_activity_log
	WHERE   activity_log_rec_id       = v_activity_log_rec_id;
        
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `loginCustomer` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `loginCustomer`(
                                IN    pReqObj  JSON,
                                INOUT pjRespObj  JSON
                              )
BEGIN
    DECLARE v_login_id  		 	VARCHAR(255);
    DECLARE v_password   			VARCHAR(255);
    
    DECLARE v_customer_rec_id 		INT;
    DECLARE v_user_name       		VARCHAR(255);
    DECLARE v_email          		VARCHAR(255);
    DECLARE v_phone           		VARCHAR(20);
    DECLARE v_db_password     		VARCHAR(255);

    main_block: BEGIN

        -- =========================
        -- Extract values from JSON
        -- =========================
        SET v_login_id 		= getJval(pReqObj, 'P_LOGIN_ID');
        SET v_password 		= getJval(pReqObj, 'P_PASSWORD');

        -- Validate input
        IF v_login_id IS NULL OR v_password IS NULL THEN
            
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj,'jHeader.message', 'Login ID and Password are required.');

            LEAVE main_block;
        END IF;

        -- =========================
        -- Find user and get password
        -- =========================
        SELECT c.customer_rec_id, c.user_name, c.email, c.phone, getJval(a.auth_json,'login_credentials.password') AS db_password
        INTO   v_customer_rec_id, v_user_name, v_email, v_phone, v_db_password
        FROM   auth a
        JOIN   customer c ON a.parent_table_rec_id = c.customer_rec_id
        WHERE  c.user_name = v_login_id
            OR c.email  = v_login_id
            OR c.phone  = v_login_id
        LIMIT 1;

        -- User not found
        IF v_customer_rec_id IS NULL THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj,'jHeader.message', 'USER_NOT_FOUND - No account matches the provided login ID.');

            LEAVE main_block;
        END IF;

        -- =========================
        -- Validate password
        -- =========================
        IF SHA2(v_password,256) <> v_db_password THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);
	    	SET pjRespObj = buildJSONSmart( pjRespObj,'jHeader.message', 'INVALID_PASSWORD - The password is incorrect.');
            

            LEAVE main_block;
        END IF;

        -- =========================
        -- Success response
        -- =========================

        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);
	    SET pjRespObj = buildJSONSmart( pjRespObj,'jHeader.message', 'LOGIN_SUCCESS - Login successful.');

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `metalToCashConverter` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `metalToCashConverter`(
										IN   pjReqObj   JSON,
										INOUT  pjRespObj  JSON
									)
BEGIN

    DECLARE v_asset_code    VARCHAR(50);
    DECLARE v_weight        DECIMAL(24,10);
    DECLARE v_amount        DECIMAL(24,10);
    DECLARE v_unit          VARCHAR(10);

    DECLARE v_json          JSON;
    DECLARE v_spot          DECIMAL(24,10);

    main_block: BEGIN

        -- Extract values from JSON
        SET v_asset_code 	= getJval(pjReqObj, 'jData.P_METAL_CODE');
        SET v_unit       	= getJval(pjReqObj, 'jData.P_UNIT');

        -- Extract either weight or amount
        SET v_weight     = CAST(getJval(pjReqObj, 'jData.P_WEIGHT') AS DECIMAL(24,10));
        SET v_amount     = CAST(getJval(pjReqObj, 'jData.P_AMOUNT') AS DECIMAL(24,10));

        -- Validate metal code
        IF v_asset_code IS NULL THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid metal selection');

            LEAVE main_block;
        END IF;

        -- Must provide either weight or amount, not both null
        IF (v_weight IS NULL OR v_weight <= 0) AND (v_amount IS NULL OR v_amount <= 0) THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Provide either weight or amount');

            LEAVE main_block;
        END IF;

        -- Convert weight to grams if provided
        IF v_weight IS NOT NULL THEN
            SET v_weight = CASE v_unit
                WHEN 'kg' THEN v_weight * 1000
                WHEN 'oz' THEN v_weight * 28.349523125
                WHEN 'g'  THEN v_weight
                ELSE NULL
            END;

            IF v_weight IS NULL OR v_weight <= 0 THEN
            
                SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
                SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid or unsupported unit');

                LEAVE main_block;
            END IF;
        END IF;

        -- Get latest rate JSON
        SELECT  asset_rate_history_json
        INTO 	v_json
        FROM 	asset_rate_history
        WHERE	asset_code = v_asset_code;

        IF v_json IS NULL THEN
 
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Rate not found');

            LEAVE main_block;
        END IF;

        -- Extract spot price
        SET v_spot = CAST(getJval(v_json,'spot_rate') AS DECIMAL(24,10));

        IF v_spot IS NULL OR v_spot <= 0 THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid spot rate');

            LEAVE main_block;
        END IF;

        -- Calculation
        IF v_weight IS NOT NULL THEN
            -- Weight to cash
            SET v_amount = v_weight * v_spot;
        ELSE
            -- Amount to weight
            SET v_weight = v_amount / v_spot;
        END IF;

        -- Response

    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 				 	0);
    SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 					 	'Exchange successful');

	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.metal',          	        v_asset_code);
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.unit', 	                'grams');
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.weight_grams', 		 	 ROUND(v_weight,6));
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.amount', 		 	         ROUND(v_amount,6));

	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.spot_rate',	             v_spot);

	SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.message', 				CONCAT( 'You can buy ',
                                                                                                ROUND(v_weight,6), ' g of ',
                                                                                                v_asset_code,
                                                                                                ' for USD ', FORMAT(ROUND(v_amount,2),0)													)
                                                                                                );

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `queueOutboundMessage` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'NO_AUTO_VALUE_ON_ZERO' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `queueOutboundMessage`(
										IN  	pjReqObj JSON,
										INOUT 	pjRespObj JSON
									)
BEGIN
	DECLARE v_outbound_msgs_rec_id		INT;
    DECLARE v_message_guid 				VARCHAR(100);
    DECLARE v_new_json 					JSON;
    DECLARE v_outbound_msgs_json		JSON;
    DECLARE v_row_metadata				JSON;

    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
 
		SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Failed to queue message');

    END;

     -- =========================
    -- Generate message guid number
    -- ========================= 
    SET v_message_guid = CONCAT(
								 'MSG-',
								 DATE_FORMAT(NOW(), '%Y%m%d%H%i%s'),
								 '-',
								 FLOOR(RAND() * 1000)
							 );

    -- =========================
    -- Get template JSON
    -- =========================                             
	SET v_outbound_msgs_json		 = getTemplate('outbound_msgs');
    
    -- =========================
    -- Set default values to json
    -- ========================= 
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'message_guid', 						v_message_guid);   
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'delivery_config.channel_number',   	1);
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'delivery_config.priority_level',   	'Normal');

	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'delivery_config.is_need_tracking',   'TRUE');
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'scheduling.scheduled_at',   NOW());
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'scheduling.retry_interval',   15);

	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'lifecycle_status.current_status',   'Queued');
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'lifecycle_status.delivery_status',   'Pending');
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'lifecycle_status.send_attempts',   	  0);
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'lifecycle_status.number_of_retries',  3);
	-- =========================
    -- fill remaining data from ReqObj
    -- =========================                                          
                                            
    SET v_outbound_msgs_json	= fillTemplate(pjReqObj, v_outbound_msgs_json);
                                            
	
    SET v_row_metadata 			= getTemplate('row_metadata');

	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'created_at',   	  NOW());
	SET v_outbound_msgs_json   = buildJSONSmart( v_outbound_msgs_json, 'created_by',  	 'System');

    INSERT INTO outbound_msgs
    SET message_guid					= v_message_guid, 
        parent_message_table_name		= getJval(pjReqObj, 'parent_message_table_name'),
        parent_message_table_rec_id		= getJval(pjReqObj, 'parent_message_table_rec_id'),
        object_name						= getJval(pjReqObj, 'object_name'),
        outbound_msgs_json				= v_outbound_msgs_json,
        row_metadata					= v_row_metadata;
        
	SET v_outbound_msgs_rec_id 			= LAST_INSERT_ID();

	SET v_outbound_msgs_json   			= buildJSONSmart( v_outbound_msgs_json, 'outbound_msgs_rec_id',   v_outbound_msgs_rec_id);
                                                    
	UPDATE  outbound_msgs
			SET 	outbound_msgs_json   = v_outbound_msgs_json
			WHERE   outbound_msgs_rec_id = v_outbound_msgs_rec_id;
    

	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 			0);
    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.queuedMessage', 	   'Message queued successfully');

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `requestHandler` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `requestHandler`(
                                    IN    pClientIp       VARCHAR(45),
                                    IN    pAppName        VARCHAR(32),
                                    IN    pActionCode     VARCHAR(50),
                                    IN    pJsonRequest    TEXT,
                                    OUT   pJsonResponse   TEXT
                                )
BEGIN
    -- constants
    DECLARE vdStart             DATETIME(3)               DEFAULT NOW(3);
    DECLARE vThisObj            VARCHAR(32)               DEFAULT 'requestHandler';
    DECLARE vAccessToken        VARCHAR(64)               DEFAULT 'fad9017e31bd0927a6bc42996df9e22708b736112f3ef801fd30d7213c146a03';
    DECLARE vAccessKey          VARCHAR(64)               DEFAULT '0f5aac120ac2746e8548dcdb565b06d9772248b51ab669f45c08dc51a4291f16';

    -- variables
    DECLARE vRespCode           VARCHAR(8);
    DECLARE vRespMessage        VARCHAR(255);
    DECLARE vLogReqStatus       VARCHAR(32);
    DECLARE vLogFailReason      VARCHAR(128);

    DECLARE vTemp               VARCHAR(255);
    DECLARE viTemp              INTEGER;
    DECLARE vjReqObj            JSON;
    DECLARE vjLogObj            JSON;
    DECLARE vjResponse          JSON                      DEFAULT getTemplate('reqResp');

    DECLARE vResponse           JSON;
    DECLARE vAction             VARCHAR(50);
    DECLARE vResponseTime       DATETIME(3);
    DECLARE vDuration           DECIMAL(10,3);   
    DECLARE vIsKnownAction      BOOLEAN                   DEFAULT TRUE;
    DECLARE vFailureReason      VARCHAR(100)              DEFAULT NULL;


    -- Exception handler
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        SET vResponseTime       = NOW(3);                                        
        SET vDuration           = TIMESTAMPDIFF(MICROSECOND, vdStart, vResponseTime) / 1000000.0;
        SET vFailureReason      = 'unexpected_error';

        SET vjLogObj            = buildJSONSmart(vjLogObj,  'failure_reason',   vFailureReason);
        SET vjLogObj            = buildJSONSmart(vjLogObj,  'action_code',      pActionCode);
        SET vjLogObj            = buildJSONSmart(vjLogObj,  'client_ip',        pClientIp);
        SET vjLogObj            = buildJSONSmart(vjLogObj,  'request_time',     vdStart);
        SET vjLogObj            = buildJSONSmart(vjLogObj,  'response_time',    vResponseTime);
        SET vjLogObj            = buildJSONSmart(vjLogObj,  'proc_duration',    vDuration);                                    

        CALL logActivity(vThisObj, vjLogObj);

        RESIGNAL;
    END;
    -- --------------------------------------------------------------------------------------
    -- -----------------------------   Show Starts   ----------------------------------------

    IF vjResponse IS NULL THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Response object is null';
    END IF;

    -- ---------------------------    House Keeping    --------------------------------------
    -- --------------------------------------------------------------------------------------


    SET vjLogObj    = buildJSONSmart(null,       'logging_object',   vThisObj);

    SET vjLogObj    = buildJSONSmart(vjLogObj,   'action_code',    pActionCode);

    SET vjLogObj    = buildJSONSmart(vjLogObj,   'json_request',     pJsonRequest);
    SET vjLogObj    = buildJSONSmart(vjLogObj,   'request_time',     vdStart);

    SET vjLogObj    = buildJSONSmart(vjLogObj,   'app_name',         pAppName);
    SET vjLogObj    = buildJSONSmart(vjLogObj,   'user_id',          getJval(pJsonRequest, 'jData.P_ACCOUNT_NUM'));
    SET vjLogObj    = buildJSONSmart(vjLogObj,   'device_info',      getJval(pJsonRequest, 'jHeader.P_DEVICE_INFO'));
    SET vjLogObj    = buildJSONSmart(vjLogObj,   'client_ip',        pClientIp);
    SET vjLogObj    = buildJSONSmart(vjLogObj,   'latitude',         getJval(pJsonRequest, 'jHeader.P_LATITUDE'));
    SET vjLogObj    = buildJSONSmart(vjLogObj,   'longitude',        getJval(pJsonRequest, 'jHeader.P_LONGITUDE'));


    CALL debugLog(vThisObj, 'Create Temp Table');
    -- Create the temporary tables for static data
    -- CREATE TEMPORARY TABLE IF NOT EXISTS temp_IP_WhiteList AS       SELECT * FROM IP_WhiteList;

    -- --------------------------------------------------------------------------------------
    -- ----------------------- Perform validity checks   ------------------------------------
    -- --------------------------------------------------------------------------------------

    thisProc:BEGIN

        IF NOT isValidIP(pClientIp) THEN
            SET vTemp           = CONCAT('Unauthorized hit. IP: ', pClientIp);
            CALL debugLog(vThisObj, vTemp);

            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.responseCode',    1);
            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.message',         vTemp);

            SET vLogReqStatus   = 'FAIL';
            SET vLogFailReason  = vTemp;

            LEAVE thisProc;
        END IF;

        -- Validate request JSON
        IF JSON_VALID(pJsonRequest) = 0 THEN
            SET vTemp = 'request is not a JSON object';

            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.responseCode',    2);
            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.message',         vTemp);

            SET vLogReqStatus   = 'FAIL';
            SET vLogFailReason  = vTemp;

            CALL debugLog(vThisObj, vTemp);

            LEAVE thisProc;
        END IF;
 -- convert request to JSON object
    SET vjReqObj = CONVERT(pJsonRequest, JSON);

        IF      STRCMP(getJval(vjReqObj, 'jHeader.accessToken'),   vAccessToken)   <> 0
            OR  STRCMP(getJval(vjReqObj, 'jHeader.accessKey'),     vAccessKey)     <> 0 THEN

            SET vTemp           = 'DB access credential are not valid: ';

            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.responseCode',    3);
            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.message',         vTemp);

            SET vLogReqStatus   = 'FAIL';
            SET vLogFailReason  = vTemp;
            
            SET vTemp = CONCAT( vTemp,
                               getJval(vjReqObj, 'jHeader.accessToken'), ' == ', vAccessToken, ' <==> ',
                               getJval(vjReqObj, 'jHeader.accessKey'),   ' == ', vAccessKey
                             );
            CALL debugLog(vThisObj, vTemp);

            LEAVE thisProc;
        END IF;

        -- TODO: check if parameter action code and json action code are the same or not.


        -- --------------------------------------------------------------------------------------
        -- ----------------------- All is okay. Perform Action   --------------------------------
        -- --------------------------------------------------------------------------------------

        CALL debugLog(vThisObj, '----- All checks are okay. Execute the Action  -----');


        -- ---------------------------------------------------------
        --  Service: Common
        -- ---------------------------------------------------------
        

        -- Extract jData from request and set it as main request object for ease of use in procedures.
        -- SET vjReqObj = getJval(vjReqObj, 'jData');

        -- Process action_code for meta data
        CASE pActionCode

            WHEN 'somenameGETVIEW' THEN
                -- Gets the entire json response doc
                CALL debugLog(vThisObj, 'Calling getViewJSON');
                SET vjResponse = getViewJSON(
                                              getJval(vjReqObj, 'jData.PAPPNAME'),
                                              getJval(vjReqObj, 'jData.P_VIEW_NAME')
                                            );

        -- =====================================================
        -- CUSTOMER MODULE (CUS)
        -- =====================================================
        WHEN 'CUS.U.CUSTOMER'                THEN CALL upsertCustomer(vjReqObj, vjResponse);
        WHEN 'CUS.S.CUSTOMER'                THEN CALL getCustomer(vjReqObj, vjResponse);
        WHEN 'CUS.U.PREFERENCES'             THEN CALL savePreferences(vjReqObj, vjResponse);

        -- =====================================================
        -- AUTH / SECURITY MODULE (AUT)
        -- =====================================================
        WHEN 'AUT.S.LOGIN'                   THEN CALL loginCustomer(vjReqObj, vjResponse);
        WHEN 'AUT.S.AUTH'                    THEN CALL getAuth(vjReqObj, vjResponse);
        WHEN 'AUT.S.VERIFY_EXISTING_NUMBER'  THEN CALL verifiyExistingNumber(vjReqObj, vjResponse);

        WHEN 'AUT.I.OTP'                     THEN CALL genOtp(vjReqObj, vjResponse);
        WHEN 'AUT.S.VERIFY_OTP'              THEN CALL verifyOtp(vjReqObj, vjResponse);

        WHEN 'AUT.S.FORGOT_LOGIN_ID'         THEN CALL forgotLoginID(vjReqObj, vjResponse);
        WHEN 'AUT.S.FORGOT_PASSWORD_OTP'     THEN CALL forgotPassword(vjReqObj, vjResponse);

        WHEN 'AUT.U.RESET_PASSWORD'          THEN CALL resetPassword(vjReqObj, vjResponse);
        WHEN 'AUT.U.CHANGE_PASSWORD'         THEN CALL changePassword(vjReqObj, vjResponse);

        -- =====================================================
        -- WALLET MODULE (WLT)
        -- =====================================================
        WHEN 'WLT.I.CUSTOMER_WALLET'         THEN CALL createAcustomerWallet(vjReqObj, vjResponse);
        WHEN 'WLT.I.ACTIVITY'                THEN CALL wallet_activity(vjReqObj, vjResponse);
        WHEN 'WLT.S.WALLETS'                 THEN CALL getWallets(vjReqObj, vjResponse);

        -- =====================================================
        -- PRODUCT MODULE (PRD)
        -- =====================================================
        WHEN 'PRD.U.PRODUCT'                 THEN CALL upsertProduct(vjReqObj, vjResponse);
        WHEN 'PRD.S.PRODUCT'                 THEN CALL getProduct(vjReqObj, vjResponse);

        -- =====================================================
        -- INVENTORY MODULE (INV)
        -- =====================================================
        WHEN 'INV.U.INVENTORY'               THEN CALL upsertInventory(vjReqObj, vjResponse);
        WHEN 'INV.S.INVENTORY'               THEN CALL getInventory(vjReqObj, vjResponse);

        -- =====================================================
        -- TRANSACTION MODULE (TRN)
        -- =====================================================
        WHEN 'TRN.I.MONEY_TRANSACTION'       THEN CALL createMoneyTransaction(vjReqObj, vjResponse);
        WHEN 'TRN.U.MONEY_TRANSACTION'       THEN CALL updateMoneyTransaction(vjReqObj, vjResponse);
        WHEN 'TRN.S.MONEY_TRANSACTION'       THEN CALL getMoneyManager(vjReqObj, vjResponse);

        -- =====================================================
        -- FINANCE MODULE (FIN)
        -- =====================================================
        WHEN 'FIN.S.CREDIT_CARD'             THEN CALL getCreditCard(vjReqObj, vjResponse);
        WHEN 'FIN.S.RATES'                   THEN CALL getRates(vjReqObj, vjResponse);
        WHEN 'FIN.S.ACCOUNT_VERIFICATION'    THEN CALL verifyAccountNum(vjReqObj, vjResponse);

        -- =====================================================
        -- CALCULATOR / UTILITY MODULE (CAL)
        -- =====================================================
        WHEN 'CAL.S.EXCHANGE_METAL'          THEN CALL exchangeMetalCalculator(vjReqObj, vjResponse);
        WHEN 'CAL.S.METAL_TO_CASH'           THEN CALL metalToCashConverter(vjReqObj, vjResponse);

        -- =====================================================
        -- CONTENT MODULE (CNT)
        -- =====================================================
        WHEN 'CNT.S.NEWS'                    THEN CALL getNews(vjReqObj, vjResponse);
        WHEN 'CNT.S.PROMOTIONS'              THEN CALL getPromotions(vjReqObj, vjResponse);

        -- =====================================================
        -- MESSAGING MODULE (MSG)
        -- =====================================================
        WHEN 'MSG.I.OUTBOUND_QUEUE'          THEN CALL queueOutboundMessage(vjReqObj, vjResponse);

        -- =====================================================
        -- ORDER MODULE (ORD)
        -- =====================================================
        WHEN 'ORD.I.BUY_ORDER'               THEN CALL createBuyOrder(vjReqObj, vjResponse);
        WHEN 'ORD.S.BUY_ORDER'               THEN CALL getOrder(vjReqObj, vjResponse); 
        WHEN 'ORD.U.BUY_ORDER'               THEN CALL updateOrder(vjReqObj, vjResponse); -- not done yet
        WHEN 'ORD.D.BUY_ORDER'               THEN CALL deleteOrder(vjReqObj, vjResponse); -- not done yet

        WHEN 'ORD.I.SELL_ORDER'              THEN CALL createSellOrder(vjReqObj, vjResponse);
        WHEN 'ORD.S.SELL_ORDER'              THEN CALL getOrder(vjReqObj, vjResponse); 
        WHEN 'ORD.U.SELL_ORDER'              THEN CALL updateOrder(vjReqObj, vjResponse); -- not done yet
        WHEN 'ORD.D.SELL_ORDER'              THEN CALL deleteOrder(vjReqObj, vjResponse); -- not done yet

        WHEN 'ORD.I.EXCHANGE_ORDER'          THEN CALL createExchangeOrder(vjReqObj, vjResponse);
        WHEN 'ORD.S.EXCHANGE_ORDER'          THEN CALL getOrder(vjReqObj, vjResponse); 
        WHEN 'ORD.U.EXCHANGE_ORDER'          THEN CALL updateOrder(vjReqObj, vjResponse); -- not done yet
        WHEN 'ORD.D.EXCHANGE_ORDER'          THEN CALL deleteOrder(vjReqObj, vjResponse); -- not done yet

        WHEN 'ORD.I.REDEEM_ORDER'            THEN CALL createRedeemOrder(vjReqObj, vjResponse);
        WHEN 'ORD.S.REDEEM_ORDER'            THEN CALL getOrder(vjReqObj, vjResponse); 
        WHEN 'ORD.U.REDEEM_ORDER'            THEN CALL updateOrder(vjReqObj, vjResponse); -- not done yet
        WHEN 'ORD.D.REDEEM_ORDER'            THEN CALL deleteOrder(vjReqObj, vjResponse); -- not done yet

        -- =====================================================
        -- MISC MODULE
        -- =====================================================
        WHEN 'DOC.U.MANAGEMENT'              THEN CALL documentManagment(vjReqObj, vjResponse);
        WHEN 'DDVAL.S.DROPDOWN'              THEN CALL getDropDownValue(vjReqObj, vjResponse);

      

        -- =====================================================
        -- UNKNOWN ACTION
        -- =====================================================
        ELSE
            SET vAction = 'unknown_action';

    END CASE;


        -- ---------------------------------------------------------
        --  Catch unknown action code
        -- ---------------------------------------------------------
        IF getJval(vjResponse, 'jHeader.message') = 'default_error' THEN
            -- action code was NOT valid and none of the procedures were executed.
            SET vTemp = CONCAT('----- Unknown Action Code is called.   -----: ', pActionCode);
            CALL debugLog(vThisObj, vTemp);

            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.responseCode',    4);
            SET vjResponse      = buildJSONSmart(vjResponse, 'jHeader.message',         vTemp);

            SET vLogReqStatus   = 'FAIL';
            SET vLogFailReason  = vTemp;

            LEAVE thisProc;
        END IF;


    -- ---------------------------------------------------------
    --           exit point of the procedure.
    -- ---------------------------------------------------------
    END thisProc;

    -- Send response
    SET pJsonResponse = vjResponse;

    -- Log request and response
    SET vResponseTime = NOW(3);
    SET vDuration     = TIMESTAMPDIFF(MICROSECOND, vdStart, vResponseTime) / 1000000.0;

    SET vjLogObj      = buildJSONSmart(vjLogObj, 'action_status',    COALESCE(vLogReqStatus, 'SUCCESS'));
    SET vjLogObj      = buildJSONSmart(vjLogObj, 'failure_reason',   COALESCE(vLogFailReason, getJval(vjResponse, 'jHeader.message')));

    SET vjLogObj      = buildJSONSmart(vjLogObj,  'json_response',    pJsonResponse);
    SET vjLogObj      = buildJSONSmart(vjLogObj, 'response_time',     vResponseTime);
    SET vjLogObj      = buildJSONSmart(vjLogObj, 'proc_duration',     vDuration);

    CALL logActivity(vThisObj, vjLogObj);

    -- Temp: debug info
    CALL debugLog(vThisObj, CAST(vjResponse AS CHAR));

    CALL debugLog(vThisObj, '----- PROC Ends  -----');
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `resetPassword` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `resetPassword`(
                                IN  pReqJson       JSON,
                                OUT pResJson      JSON
                              )
BEGIN

    DECLARE v_login_id            VARCHAR(255);
    DECLARE v_new_password        VARCHAR(255);
    DECLARE v_reset_token         VARCHAR(100);
    
    DECLARE v_customer_rec_id     INT;
    DECLARE v_user_name           VARCHAR(255);
    DECLARE v_email               VARCHAR(255);
    DECLARE v_phone               VARCHAR(20);
    DECLARE v_token_expiry        DATETIME;
    DECLARE v_db_reset_token 	 VARCHAR(100);

    main_block: BEGIN

        -- =========================
        -- Extract values from JSON
        -- =========================
        SET v_login_id    		 = getJval(pReqJson, 'P_LOGIN_ID');
        SET v_new_password 		 = getJval(pReqJson, 'P_NEW_PASSWORD');
        SET v_reset_token 		 = getJval(pReqJson, 'P_RESET_TOKEN');

        -- Validate input
        IF v_login_id IS NULL OR v_new_password IS NULL OR v_reset_token IS NULL THEN
            SET pResJson = JSON_OBJECT(
										'status',  'INVALID_REQUEST',
										'message', 'Login ID, New Password and Reset Token are required.'
									);
            LEAVE main_block;
        END IF;

        -- =========================
        -- Find customer & validate reset token
        -- =========================
        SELECT customer_rec_id, 	user_name, 		email, 		phone, 	  getJval(customer_json,'$.otp_reset_token') AS token, 	getJval(customer_json,'$.reset_token_expiry') AS token_expiry
        INTO   v_customer_rec_id, 	v_user_name, 	v_email, 	v_phone,  v_db_reset_token, 									v_token_expiry
        FROM   customer
        WHERE  user_name = v_login_id
            OR email = v_login_id
            OR phone = v_login_id
        LIMIT 1;

        -- Customer not found
        IF v_customer_rec_id IS NULL THEN
            SET pResJson = JSON_OBJECT(
										'status',  'USER_NOT_FOUND',
										'message', 'No account matches the provided login ID.'
									);
            LEAVE main_block;
        END IF;

        -- Token mismatch
        IF v_reset_token <>  v_db_reset_token THEN
            SET pResJson = JSON_OBJECT(
										'status', 'INVALID_TOKEN',
										'message', 'The reset token is invalid.'
									);
            LEAVE main_block;
        END IF;

        -- Token expired
        IF NOW() > v_token_expiry THEN
            SET pResJson = JSON_OBJECT(
										'status', 'EXPIRED_TOKEN',
										'message', 'The reset token has expired.'
									);
            LEAVE main_block;
        END IF;

        -- =========================
        -- Prevent reuse of last passwords
        -- =========================
        IF EXISTS (
            SELECT 1 
            FROM password_history
            WHERE 	parent_table_name = 'customer'
            AND		parent_table_rec_id = v_customer_rec_id
			AND 	password_hash = SHA2(v_new_password,256)
        ) THEN
            SET pResJson = JSON_OBJECT(
										'status',  'PASSWORD_REUSED',
										'message', 'You cannot reuse a previous password.'
									);
            LEAVE main_block;
        END IF;

        -- =========================
        -- Update password in auth table
        -- =========================
        UPDATE auth
        SET auth_json  = JSON_SET(auth_json, '$.login_credentials.password', SHA2(v_new_password,256))
        WHERE 	parent_table_name = 'customer'
		AND		parent_table_rec_id = v_customer_rec_id;
        
		-- =========================
        -- Deactivate previous passwords
        -- =========================
        UPDATE password_history
		SET is_active = 0
		WHERE 	parent_table_name 	= 'customer'
		AND 	parent_table_rec_id = v_customer_rec_id
		AND 	is_active 			= 1;

        -- =========================
        -- Insert into password history NEW ROW
        -- =========================
        INSERT INTO password_history
        SET   parent_table_name 		= 'customer',
              parent_table_rec_id		= v_customer_rec_id,
              password_hash				= SHA2(v_new_password,256),
              password_set_at			= NOW(),
              password_change_by		= 'customer',
              password_change_reason	= 'forgot password',
              last_password_updated_at  = NOW(),
              password_expiration_date	= DATE_ADD(NOW(), INTERVAL 90 DAY),
             is_active					= 1;

        -- =========================
        -- Clear reset token
        -- =========================
        UPDATE customer
        SET customer_json = JSON_REMOVE(customer_json,'$.otp_reset_token','$.reset_token_expiry')
        WHERE customer_rec_id = v_customer_rec_id;

        -- =========================
        -- Success Response
        -- =========================
        SET pResJson = JSON_OBJECT(
            'status',  'PASSWORD_RESET_SUCCESS',
            'message', 'Your password has been successfully reset.'
        );

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `savePreferences` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `savePreferences`(
									IN      pjReqObj  JSON,
									INOUT   pjRespObj JSON
								)
BEGIN

    DECLARE v_login_id              VARCHAR(255);
    DECLARE v_preference_key        VARCHAR(255);
    DECLARE v_preference_value      VARCHAR(255);
    DECLARE v_preference_rec_id 	INT;

    DECLARE v_customer_rec_id       INT;
    DECLARE v_existing_pref_id      INT;
    DECLARE v_old_value             VARCHAR(255);

    DECLARE v_app_preferences_json  JSON;
    DECLARE v_existing_json         JSON;
    DECLARE v_row_metadata          JSON;

    DECLARE v_effective_from        DATETIME;
    DECLARE v_effective_until       DATETIME;

    main_block: BEGIN

        -- =========================
        -- Extract values
        -- =========================
        SET v_login_id         = getJval(pjReqObj, 'jData.P_LOGIN_ID');
        SET v_preference_key   = getJval(pjReqObj, 'jData.P_PREFERENCE_KEY');
        SET v_preference_value = getJval(pjReqObj, 'jData.P_PREFERENCE_VALUE');

        -- =========================
        -- Validation
        -- =========================
        IF isFalsy(v_login_id) OR isFalsy(v_preference_key) THEN
    
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Login ID, Preference Key are required.');

            LEAVE main_block;
        END IF;

        -- =========================
        -- Get Customer
        -- =========================
        SELECT  customer_rec_id
        INTO    v_customer_rec_id
        FROM 	customer
        WHERE 	user_name = v_login_id
        OR 	  	email     = v_login_id
        OR 	  	phone     = v_login_id
        LIMIT 1;

        IF v_customer_rec_id IS NULL THEN

            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Customer not found.');

            LEAVE main_block;
        END IF;

        -- =========================
        -- Check if preference exists
        -- =========================
        SELECT  preference_rec_id, 	 preference_value, 	app_preferences_json
        INTO    v_existing_pref_id,  v_old_value, 		v_existing_json
        FROM    app_preferences
        WHERE   customer_rec_id  = v_customer_rec_id
        AND     preference_key   = v_preference_key
        LIMIT 1;

        -- =========================
        -- Determine Effective Dates
        -- =========================
        SET v_effective_from  	= NULL;
        SET v_effective_until 	= NULL;

        -- FIRST TIME
        IF v_existing_pref_id IS NULL THEN

            SET v_effective_from  = NOW();
            SET v_effective_until = DATE_ADD(NOW(), INTERVAL 365 DAY);

        ELSE

            -- If value cleared ? expire immediately
            IF isFalsy(v_preference_value) THEN

                SET v_effective_from  = NULL;
                SET v_effective_until = NOW();

            -- If value changed ? reset validity
            ELSEIF v_old_value <> v_preference_value THEN

                SET v_effective_from  = NOW();
                SET v_effective_until = DATE_ADD(NOW(), INTERVAL 365 DAY);

            -- If same value ? keep old dates
            ELSE

                SET v_effective_from  = getJval(v_existing_json,  'preference_behavior.effective_from');
                SET v_effective_until = getJval(v_existing_json,  'preference_behavior.effective_until');

            END IF;

        END IF;

        -- =========================
        -- Prepare JSON
        -- =========================
        SET v_app_preferences_json = getTemplate('app_preferences');

        SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_behavior.is_user_editable', TRUE);
        SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_behavior.is_system_defined', TRUE);
        SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_behavior.effective_from', v_effective_from);
        SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_behavior.effective_until', v_effective_until);

        SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_key', v_preference_key);
        SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_value', v_preference_value);

        SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'customer_rec_id',   v_customer_rec_id);

        -- =========================
        -- Row metadata
        -- =========================
        SET v_row_metadata = getTemplate('row_metadata');

        SET v_row_metadata = buildJSONSmart( v_row_metadata, 'status',     'Active');
        SET v_row_metadata = buildJSONSmart( v_row_metadata, 'updated_at', NOW());

        -- =========================
        -- INSERT or UPDATE
        -- =========================
        IF v_existing_pref_id IS NULL THEN

            INSERT INTO app_preferences
            SET customer_rec_id      	= v_customer_rec_id,
                preference_key       	= v_preference_key,
                preference_value     	= v_preference_value,
                app_preferences_json 	= v_app_preferences_json,
                row_metadata         	= v_row_metadata;
			
            SET v_preference_rec_id 	= LAST_INSERT_ID();
            
            SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_rec_id', v_preference_rec_id);
                                                            
			UPDATE  app_preferences
			SET 	app_preferences_json  	= v_app_preferences_json
			WHERE   preference_rec_id 		= v_preference_rec_id;
            

        ELSE
            UPDATE app_preferences
            SET preference_value      	= v_preference_value,
                app_preferences_json  	= v_app_preferences_json,
                row_metadata          	= v_row_metadata
            WHERE preference_rec_id  	= v_existing_pref_id;

            SET v_app_preferences_json = buildJSONSmart( v_app_preferences_json, 'preference_rec_id', v_existing_pref_id);

            UPDATE  app_preferences
			SET 	app_preferences_json  	= v_app_preferences_json
			WHERE   preference_rec_id 		= v_existing_pref_id;

        END IF;

        -- =========================
        -- Success Response
        -- =========================
        
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	0);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		IF( v_existing_pref_id IS NULL,
                                                                                'Success - Preference saved successfully',
                                                                                'Success - Preference updated successfully'
                                                                            )
									);

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `updateMoneyTransaction` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `updateMoneyTransaction`(
										IN    pjReqObj JSON,
										INOUT pjRespObj JSON
									  )
BEGIN
    DECLARE v_mm_rec_id        INT;
    DECLARE v_new_status       VARCHAR(50);
    DECLARE v_mm_json          JSON;
    DECLARE v_cc_json          JSON;
    DECLARE v_row_metadata     JSON;
    DECLARE v_life_cycle       JSON;
    
    
    DECLARE v_errors           JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg          VARCHAR(1000);

    /* ================= Exception Handler ================= */
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;

        SET pjRespObj       = buildJSONSmart( pjRespObj,  'jHeader.responseCode',   '1');
        SET pjRespObj 	   = buildJSONSmart( pjRespObj,
                                            'jHeader.message', CONCAT('Unexpected Error - Money transaction update failed', v_err_msg)
                                            );                                   
    END;

    main_block: BEGIN

        /* =============== Extract Inputs =============== */
        SET v_mm_rec_id  		= CAST(getJval(pjReqObj,'P_MONEY_MANAGER_REC_ID') AS UNSIGNED);
        SET v_new_status 		= getJval(pjReqObj,'P_STATUS');

        /* =============== Validations =============== */
        IF isFalsy(v_mm_rec_id) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','money_manager_rec_id is required');
        END IF;

        IF isFalsy(v_new_status) THEN
            SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','new_status is required');
        END IF;

        IF JSON_LENGTH(v_errors) > 0 THEN

			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        v_errors); 

            LEAVE main_block;
        END IF;

        /* =============== Fetch Existing Record =============== */
        SET v_mm_json = getMoneyManager(v_mm_rec_id);

        IF getJval(v_mm_json,'status') IS NULL THEN

            SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        'Transaction not found');

            LEAVE main_block;
        END IF;

        /* =============== Status Transition Rules =============== */
        IF getJval(v_mm_json,'status') = 'POSTED' THEN

            SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        'Posted transaction cannot be modified');

            LEAVE main_block;
        END IF;
        
     

       
           /* =============== get existed json of money manager and update with req obj  =============== */
        SET v_mm_json	    = getMoneyManager(v_mm_rec_id);

         /* =============== Prepare Lifecycle Entry =============== */
        SET v_life_cycle    = getTemplate('transaction_life_cycle');
        
        SET v_life_cycle 	= JSON_SET( v_life_cycle,
                                        '$.status',     v_new_status,
                                        '$.user_name',  getJval(pjReqObj,           'P_USER_NAME'),
                                        '$.action_by',  getJval(pjReqObj,           'P_ACTION_BY'),
                                        '$.action_at',  COALESCE(getJval(pjReqObj,  'P_ACTION_AT'), NOW()),
                                        '$.notes',      getJval(pjReqObj,           'P_NOTES')
                                );

	   /* ================ APPEND OBJ in life cycle array in money manager ============ */
        SET v_mm_json 			= JSON_ARRAY_APPEND( v_mm_json,
													 '$.life_cycle',  v_life_cycle
												  );

        /* =============== Update Row Metadata =============== */
        SET v_row_metadata = getTemplate('row_metadata');
        SET v_row_metadata = JSON_SET( v_row_metadata,
									   '$.status',       v_new_status,
									   '$.updated_at',   NOW(),
									   '$.updated_by',   getJval(v_mm_json,'action_by')
									);

        /* =============== Start Transaction =============== */
        START TRANSACTION;

        UPDATE money_manager
        SET	  status             			= v_new_status,
              backoffice_post_number		= getJval(pjReqObj,'P_BACKOFFICE_POST_NUMBER'),
              trans_posted_at				= getJval(pjReqObj,'P_TRANS_POSTED_AT'),
              money_manager_json 			= v_mm_json,
			  row_metadata       			= v_row_metadata
        WHERE money_manager_rec_id = v_mm_rec_id;

        /* =============== Credit Card Update (If Exists) =============== */
        IF JSON_EXTRACT(v_mm_json,'$.transaction_type') = 'credit card' THEN
        
	  /* =============== get existed json of credit card and update with req obj  =============== */
        SET v_cc_json	 = fillTemplate(pjReqObj, getCreditCard(v_mm_rec_id));
        
     /* ================ APPEND OBJ in life cycle array in credit card ============ */
		SET v_cc_json	 		= JSON_ARRAY_APPEND( v_cc_json,
													'$.life_cycle', v_life_cycle
												  );		
        
            UPDATE credit_card
            SET	  status     				= v_new_status,
                  backoffice_post_number	= getJval(pjReqObj,         'P_BACKOFFICE_POST_NUMBER'),
				  trans_posted_at			= COALESCE(getJval(pjReqObj,'P_TRANS_POSTED_AT'), NOW()),
                  card_json  				= v_cc_json,
                  row_metadata 				= v_row_metadata
            WHERE money_manager_rec_id = v_mm_rec_id;

        END IF;

        COMMIT;

        /* =============== Success Response =============== */
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);

	    SET pjRespObj = buildJSONSmart( pjRespObj,
								   'jHeader.message', 'Success - Transaction updated successfully.'
								);  

    END main_block;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `upsertCustomer` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `upsertCustomer`(
								 IN  	 pjReqObj   JSON,
								 INOUT   pjRespObj   JSON
								)
BEGIN

    DECLARE v_customer_rec_id     		 	INT;
    DECLARE v_auth_rec_id         		 	INT;

    /* ===================== Customer Core ===================== */
    DECLARE v_customer_status     			VARCHAR(30) DEFAULT 'registration_request';
    DECLARE v_customer_type       			VARCHAR(30) DEFAULT 'personal';
    DECLARE v_email               			VARCHAR(100);
    DECLARE v_user_name           			VARCHAR(100);
    DECLARE v_password_plain      			VARCHAR(255);
    DECLARE v_password_hashed     			VARCHAR(255);
    DECLARE v_account_seq 		  			VARCHAR(255);
    DECLARE v_mode 							VARCHAR(20);

    /* ===================== JSON Objects ===================== */
    DECLARE v_customer_json       		JSON;
    DECLARE v_auth_json           		JSON;
    DECLARE v_row_metadata   			JSON;

    /* ===================== Validation Variables ===================== */
    DECLARE v_errors              		JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg       			TEXT;
    
   /* ===================== Variable for tradable_assets table and for cursor ===================== */
	DECLARE done 						INT;
	DECLARE v_tradable_asset_rec_id 	INT;

	DECLARE 	asset_cursor 			CURSOR FOR
    SELECT  	tradable_assets_rec_id
    FROM    	tradable_assets
    WHERE   	available_to_customers = TRUE  AND tradable_assets_rec_id > 0;

	DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
	/* ===================== Error Handler ===================== */

	DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
		SET pjRespObj       = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
		SET pjRespObj 	   = buildJSONSmart( pjRespObj,
											'jHeader.message', CONCAT('Registration failed - Unexpected Error', v_err_msg)
											);
    END;
    /* ===================== Main ===================== */
    main_block: BEGIN

        /* ===================== Extract Scalars ===================== */
        SET v_email     		= getJval(pjReqObj, 'P_EMAIL');
        SET v_user_name 		= v_email;
	
            /* ===================== Set template values from Request Object ===================== */
        SET v_customer_json 			= fillTemplate(pjReqObj, getTemplate('customer'));
		SET v_row_metadata 				= getTemplate('row_metadata');
        
    SET v_mode =
				CASE
					WHEN isFalsy(getJval(pjReqObj,'P_CUSTOMER_REC_ID')) THEN
					'INSERT'
					ELSE
					'UPDATE'
				END;
                
		/* ========================================================================================= */
        /* ======================================= INSERT ========================================== */
        /* ========================================================================================= */
    
    CASE v_mode
        
		WHEN 'INSERT' THEN
        
            /* ===================== Validations ===================== */
			IF isFalsy(getJval(pjReqObj,'P_FIRST_NAME')) THEN
				SET v_errors		= JSON_ARRAY_APPEND(v_errors,'$','First name is required');
			END IF;

			IF isFalsy(getJval(pjReqObj,'P_LAST_NAME')) THEN
				SET v_errors 		= JSON_ARRAY_APPEND(v_errors,'$','Last name is required');
			END IF;

			IF isFalsy(getJval(pjReqObj,'P_NATIONAL_ID')) THEN
				SET v_errors 		= JSON_ARRAY_APPEND(v_errors,'$','National ID is required');
			END IF;

			IF isFalsy(getJval(pjReqObj,'P_PHONE')) THEN
				SET v_errors 		= JSON_ARRAY_APPEND(v_errors,'$','Phone number is required');
			END IF;

			IF isFalsy(getJval(pjReqObj,'P_PASSWORD')) THEN
				SET v_errors		= JSON_ARRAY_APPEND(v_errors,'$','Password is required');
			END IF;

			IF getJval(pjReqObj, 'P_RESIDENTIAL_ADDRESS') IS NULL THEN
    			SET v_errors = JSON_ARRAY_APPEND(v_errors, '$', 'residential_address is required or invalid');
			END IF;
        
        /* ===================== Check the INSERT uniqueness ===================== */

			IF EXISTS (
						SELECT 1 FROM customer
						WHERE national_id = getJval(pjReqObj,'P_NATIONAL_ID')
					  ) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$', 'Customer already exists with this National ID');
			END IF;

			IF EXISTS (
						SELECT 1 FROM customer
						WHERE email = v_email
					  ) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','Email already exists');
			END IF;
            
			IF JSON_LENGTH(v_errors) > 0 THEN
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj, 'jHeader.message', v_errors);
											
            LEAVE main_block;
			END IF;


			/* =============== CREATE CUSTOMER: INSERT NEW ROW IF REC ID NOT EXISTS in Request ============= */
            
			CALL getSequence('CUSTOMER.MAIN_ACCOUNT_NUM',NULL, NULL,'creatCustomer sp', v_account_seq);
        
			SET v_customer_json				= JSON_SET( v_customer_json,
														'$.customer_status',		v_customer_status,
														'$.customer_type', 			v_customer_type,
														'$.user_name', 				v_user_name,
														'$.main_account_num',		v_account_seq,
														'$.account_num',			v_account_seq
											  );
            
			SET v_row_metadata				= JSON_SET( v_row_metadata,
														'$.status', 		v_customer_status,   -- reg req
														'$.created_at',		DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
														'$.created_by', 	'SYSTEM'
														);
                                                   
			INSERT INTO customer
			SET customer_status 			= v_customer_status,		-- registration_request
					customer_type   		= v_customer_type,			-- personal
					first_name				= getJval(pjReqObj, 'P_FIRST_NAME'),
					last_name				= getJval(pjReqObj, 'P_LAST_NAME'),
					user_name       		= v_user_name,
					email           		= v_email,
					phone           		= getJval(pjReqObj,'P_PHONE'),
					whatsapp_num    		= getJval(pjReqObj,'P_WHATSAPP_NUMBER'),
					national_id     		= getJval(pjReqObj,'P_NATIONAL_ID'),
					main_account_num       	= v_account_seq,
					account_num            	= v_account_seq,
					customer_json   		= v_customer_json,
					row_metadata    		= v_row_metadata;

			SET v_customer_rec_id 			= LAST_INSERT_ID();

			SET v_customer_json 			= JSON_SET( v_customer_json,
														'$.customer_rec_id', v_customer_rec_id
													  );

			UPDATE  customer
			SET 	customer_json  	  = v_customer_json
			WHERE   customer_rec_id   = v_customer_rec_id;
				
				 /* ---------- get Auth JSON ---------- */
			SET v_auth_json 	= getTemplate('auth');
                
				/* ===================== Password ===================== */
			SET v_password_plain  			= getJval(pjReqObj,'P_PASSWORD');
			SET v_password_hashed 			= SHA2(v_password_plain,256);
            
            

				/* ---------- Prepare Auth JSON ---------- */
			SET v_auth_json					= JSON_SET( v_auth_json,
														'$.parent_table_name',						'customer',
														'$.parent_table_rec_id',					v_customer_rec_id,
														'$.user_name',								v_user_name,
														'$.login_credentials.password',				v_password_hashed,
														'$.login_credentials.username',				v_email                                               
													);
                                      
				/* ---------- Insert Auth ---------- */
			INSERT INTO auth
			SET parent_table_name   			= 'customer',
					parent_table_rec_id 		= v_customer_rec_id,
					user_name           		= v_user_name,
					auth_json           		= v_auth_json,
					row_metadata        		= v_row_metadata;

			SET v_auth_rec_id 	= LAST_INSERT_ID();
				
			SET v_auth_json 	= JSON_SET( v_auth_json,'$.auth_rec_id', v_auth_rec_id );

			UPDATE  auth
			SET 	auth_json 	  = v_auth_json
			WHERE   auth_rec_id   = v_auth_rec_id;
            
            INSERT INTO password_history
			SET 	parent_table_name   		= 'customer',
					parent_table_rec_id 		= v_customer_rec_id,
					password_hash           	= v_password_hashed,
					password_set_at           	= DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
					password_changed_by        	= null,
                    password_change_reason		= 'Initial password setup',
                    last_password_updated_at	= DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
                    password_expiration_date	= DATE_ADD(NOW(),INTERVAL 90 DAY),
                    is_active					= TRUE;
                
				/* ===================== CREATE CUSTOMER WALLETS ===================== */
			
            SET done = FALSE;
			OPEN asset_cursor;

				asset_loop: LOOP
				FETCH asset_cursor INTO v_tradable_asset_rec_id;
				IF done THEN
					LEAVE asset_loop;
				END IF;
			
				CALL createAcustomerWallet(v_customer_rec_id,v_tradable_asset_rec_id);
		
				END LOOP asset_loop;

			CLOSE asset_cursor;
            


		/* ***************************************************************************************** */            
		/* ***************************************************************************************** */            
		/* ***************************************************************************************** */            
		/* ***************************************************************************************** */     
        
        
        
		
		WHEN 'UPDATE' THEN
        
				SET v_customer_rec_id 		= getJval(pjReqObj,'P_CUSTOMER_REC_ID');
                
		/* ===================== Update Validations ===================== */
            
		/* ===================== UPDATE must target existing record ===================== */
			IF NOT EXISTS (
							SELECT 1 FROM customer
							WHERE customer_rec_id = v_customer_rec_id
						  ) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','Invalid customer_rec_id: record does not exist');
			END IF;

	 /* ===================== Check NIC Uniqueness ===================== */
			IF EXISTS (
						SELECT 1 FROM customer
						WHERE national_id	 = getJval(pjReqObj,'P_NATIONAL_ID')
						AND customer_rec_id  <> v_customer_rec_id
					  ) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$', 'National ID already used by another customer');
			END IF;
	
    /* ===================== Check Email Uniqueness ===================== */
			IF EXISTS (
					SELECT 1 FROM customer
					WHERE email = v_email
					AND customer_rec_id <> v_customer_rec_id
				) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','Email already used by another customer');
            END IF;
            
   /* ===================== Stop if errors  ===================== */
			IF JSON_LENGTH(v_errors) > 0 THEN

			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj, 'jHeader.message', v_errors);

            LEAVE main_block;
			END IF;
            
			 /* =============== Customer Profile and password update: UPDATE EXISTING ROW IF REC ID EXISTS in Request ============= */
            
             /* =============== fil existed CustomerJson from reqObj ============= */
			SET v_customer_json = fillTemplate(pjReqObj, getCustomer(v_customer_rec_id));
            
            SELECT 	row_metadata
            INTO 	v_row_metadata
            FROM 	customer
            WHERE 	customer_rec_id = v_customer_rec_id;
				
			SET v_row_metadata	  		= JSON_SET( v_row_metadata,
													'$.status',			COALESCE(getJval(pjReqObj, 'P_CUSTOMER_STATUS'),	v_customer_status),	
													'$.updated_by', 	'SYSTEM',
													'$.updated_at', 	DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')
												 );
			
			UPDATE customer
			SET customer_status 			= COALESCE(getJval(v_customer_json, 'customer_status'),		 v_customer_status),		-- registration_request
				customer_type   			= COALESCE(getJval(v_customer_json, 'customer_type'),		 v_customer_type),			-- personal
                corporate_account_rec_id	= getJval(pjReqObj, 				'P_CORPORATE_ACCOUNT_REC_ID'),			
				first_name					= getJval(v_customer_json,			'first_name'),
				last_name					= getJval(v_customer_json,			'last_name'), 						
				user_name       			= getJval(v_customer_json,			'email'), 						
				email           			= getJval(v_customer_json,			'email'), 							
				phone           			= getJval(v_customer_json,			'phone'),							
				whatsapp_num    			= getJval(v_customer_json,			'whatsapp_number'),					
				national_id     			= getJval(v_customer_json,			'national_id'),						
				customer_json   			= v_customer_json,
				row_metadata    			= v_row_metadata
				WHERE customer_rec_id		= v_customer_rec_id;
				
                
			/* =============== get existed AuthJson ============= */
                
            SET v_auth_json			= getAuth(v_customer_rec_id);
            
            		/* ---------- update Auth Json ---------- */
			SET v_auth_json					= JSON_SET( v_auth_json,
														'$.user_name',								getJval(v_customer_json, 'email'),
														'$.login_credentials.username',				getJval(v_customer_json, 'email')                                               
													);
												   
			/* ---------- Update password if provided  ---------- */
            IF NOT isFalsy(getJval(pjReqObj,'P_PASSWORD')) THEN
            
					SET v_password_plain  		= getJval(pjReqObj,'P_PASSWORD');
					SET v_password_hashed 		= SHA2(v_password_plain,256);
					
					UPDATE  password_history
					SET 	is_active 				= FALSE
					WHERE   parent_table_name 		= 'customer'
					AND 	parent_table_rec_id 	= v_customer_rec_id
					AND 	is_active 				= TRUE;

					INSERT INTO password_history
					SET parent_table_name         	= 'customer',
						parent_table_rec_id       	= v_customer_rec_id,
						password_hash             	= v_password_hashed,
						password_set_at           	= DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
						password_changed_by 		= CONCAT(getJval(v_customer_json, 'first_name'),' ', getJval(v_customer_json, 'last_name')),
						password_change_reason    	= 'UPDATE',
						last_password_updated_at  	= DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s'),
						password_expiration_date  	= DATE_ADD(NOW(), INTERVAL 90 DAY),
						is_active                 	= TRUE;

					SET v_auth_json 				= JSON_SET( v_auth_json, '$.login_credentials.password', v_password_hashed );
			 END IF;
	

				/* ---------- Update Auth table with  ---------- */
			UPDATE auth
			SET   user_name        		= COALESCE(getJval(pjReqObj, 'P_EMAIL'),getJval(v_auth_json, 'user_name')),
				  auth_json        		= v_auth_json,
				  row_metadata     		= v_row_metadata
			WHERE parent_table_rec_id 	= v_customer_rec_id;
				
			IF ROW_COUNT() = 0 THEN
				SIGNAL SQLSTATE '45000'
				SET MESSAGE_TEXT = 'Update failed: no rows affected';
			END IF;

	END CASE;



		        /* ===================== Successful Registration ===================== */
	SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);

	SET pjRespObj = buildJSONSmart( pjRespObj,
								   'jHeader.message', IF( isFalsy(getJval(pjReqObj, 'P_CUSTOMER_REC_ID')),
														  'Success - Customer created successfully',
														  'Success - Customer updated successfully'
														)
								);


    END main_block;
    
	-- inert general code here like LOG
	-- call log proc
    
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `upsertInventory` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `upsertInventory`(
								IN    pjReqObj JSON,
								INOUT pjRespObj JSON
							  )
BEGIN
    /* ================ VARIABLE DECLARATIONS ================ */
    
	DECLARE v_inventory_rec_id      INT;
    DECLARE v_mode 					VARCHAR(20);
    
    DECLARE v_inventory_json        JSON;
    DECLARE v_row_metadata          JSON;
	DECLARE v_product_json			JSON;

    DECLARE v_errors                JSON DEFAULT JSON_ARRAY();
    DECLARE v_err_msg               VARCHAR(1000);

    /* =============== GLOBAL ERROR HANDLER ============ */

    -- EXIT HANDLER for any SQL exception
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
        SET pjRespObj       = buildJSONSmart( pjRespObj,  'jHeader.responseCode',   '1');
		SET pjRespObj 	   = buildJSONSmart( pjRespObj,
													'jHeader.message', CONCAT('Unexpected Error - Inventory creation failed ', v_err_msg)
													);                                
    END;

    main_block: BEGIN
    
    SET v_mode =
                CASE
                    WHEN isFalsy(getJval(pjReqObj,'P_INVENTORY_REC_ID')) THEN
                    'INSERT'
                    ELSE
                    'UPDATE'
				END;
                    
	CASE v_mode
    
    WHEN 'INSERT' THEN

    /* =============== INVENTORTY Insert VALIDATIONS : If required fields are missing in reqObj ================ */

		IF isFalsy(getJval(pjReqObj,'P_PRODUCT_REC_ID')) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','product_rec_id is required');
		END IF;

		IF isFalsy(getJval(pjReqObj,'P_ITEM_NAME')) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','item_name is required');
		END IF;

		IF isFalsy(getJval(pjReqObj,'P_ITEM_TYPE')) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','item_type is required');
		END IF;

		IF isFalsy(getJval(pjReqObj,'P_AVAILABILITY_STATUS')) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','availability_status is required');
		END IF;

		IF JSON_LENGTH(v_errors) > 0 THEN
            SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        v_errors);                                    
        LEAVE main_block;
        END IF;

        /* =============== CREATE INVENTORY: Inventory Insertation started ================ */

        /* ============= JSON PREPARATION =========== */

        SET v_inventory_json 	= getTemplate('inventory');

            -- fill template from reqJson
    
        SET v_inventory_json 	= fillTemplate(pjReqObj, v_inventory_json);
        
        SET v_row_metadata   	= getTemplate('row_metadata');

        SET v_row_metadata      = JSON_SET(v_row_metadata,
                                            '$.created_by', 'SYSTEM',
											'$.created_at', DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')
                                         );

        INSERT INTO inventory
        SET product_rec_id       = getJval(pjReqObj,'P_PRODUCT_REC_ID'),
            item_name            = getJval(pjReqObj,'P_ITEM_NAME'),
            item_type            = getJval(pjReqObj,'P_ITEM_TYPE'),
            asset_type           = getJval(pjReqObj,'P_ASSET_TYPE'),
            availability_status  = getJval(pjReqObj,'P_AVAILABILITY_STATUS'),
            inventory_json       = v_inventory_json,
            row_metadata         = v_row_metadata;

        SET v_inventory_rec_id   = LAST_INSERT_ID();

        -- Sync REC ID back into Inventory JSON
        SET v_inventory_json = JSON_SET(v_inventory_json,'$.inventory_rec_id', v_inventory_rec_id);

        -- get json of existed product from product table
        
         SET v_product_json     = getProduct(getJval(pjReqObj,'P_PRODUCT_REC_ID'));

		-- fill the inventory json from product json
		SET v_inventory_json 	= mergeIfMissing( v_inventory_json,
													JSON_ARRAY(
																'product_quality',
																'approximate_weight',
																'weight_unit',
																'is_physical',
																'is_SliceAble',
																'standard_price',
																'standard_premium',
																'price_currency',
																'applicable_taxes',
																'quantity_on_hand',
																'minimum_order_quantity',
																'total_sold',
																'offer_to_customer',
																'display_order',
																'Alert_on_low_stock',
																'transaction_fee'
																),
													v_product_json
												);

        UPDATE  inventory
        SET 	inventory_json = v_inventory_json
        WHERE  inventory_rec_id = v_inventory_rec_id; 


    /* =============== UPDATE Inventory: Product UPDATION started ================ */

    WHEN 'UPDATE' THEN
        
        /* =============== Inventory Insert VALIDATIONS: UPDATE must target existing record ================ */
        SET v_inventory_rec_id = getJval(pjReqObj,'P_INVENTORY_REC_ID');
     
		IF v_inventory_rec_id IS NOT NULL
		AND NOT EXISTS (
                          SELECT 1
                          FROM   inventory
                          WHERE  inventory_rec_id = getJval(pjReqObj,'P_INVENTORY_REC_ID')
                        ) THEN
                                                              
			   SET v_errors = JSON_ARRAY_APPEND( v_errors,'$','Invalid inventory_rec_id: record does not exist');
		END IF;

    
    IF JSON_LENGTH(v_errors) > 0 THEN

			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message', 		v_errors);   

        LEAVE main_block;
    END IF;

             /* =============== Update started: update the existed row ================ */   

        SET v_inventory_json = getInventory(v_inventory_rec_id);

        SET v_inventory_json = fillTemplate(pjReqObj,v_inventory_json);

        SELECT  row_metadata
        INTO 	v_row_metadata
        FROM 	inventory
        WHERE 	inventory_rec_id = v_inventory_rec_id;

        SET v_row_metadata = JSON_SET( v_row_metadata,
										'$.updated_by', 'SYSTEM',
										'$.updated_at', DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')
                                  );

        UPDATE inventory
        SET product_rec_id       = getJval(v_inventory_json,'product_rec_id'),	
            item_name            = getJval(v_inventory_json,'item_name'), 		
            item_type            = getJval(v_inventory_json,'item_type'), 		
            asset_type           = getJval(v_inventory_json,'asset_type'), 		
            availability_status  = getJval(v_inventory_json,'availability_status'),
            inventory_json       = v_inventory_json,
            row_metadata         = v_row_metadata
        WHERE inventory_rec_id   = v_inventory_rec_id;

        IF ROW_COUNT() = 0 THEN
            SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT = 'Update failed: no rows affected';
        END IF;
	END CASE;

     /* =============== Final response preparation: success response with updated/created inventory json ================ */
   
    SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 0);

	SET pjRespObj = buildJSONSmart( pjRespObj,
								   'jHeader.message', IF( isFalsy(getJval(pjReqObj, 'P_INVENTORY_REC_ID')),
														  'Success - Inventory saved successfully',
														  'Success - Inventory updated successfully'
														)
								);                              

    END main_block;

    -- inert general code here like LOG
	-- call log proc
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `upsertProduct` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `upsertProduct`(
								IN    pjReqObj JSON,
								INOUT pjRespObj JSON
							  )
BEGIN
		/* ================ VARIABLE DECLARATIONS ================ */

		DECLARE v_product_rec_id         	INT;
        DECLARE v_tradable_assets_rec_id	INT;
        DECLARE v_mode 						VARCHAR(20);
        
		DECLARE v_products_json          	JSON;
		DECLARE v_row_metadata           	JSON;
    
		DECLARE v_errors 					JSON 				DEFAULT JSON_ARRAY();
		DECLARE v_err_msg       		    VARCHAR(1000);

    /* =============== GLOBAL ERROR HANDLER ============ */

		-- EXIT HANDLER for any SQL exception
		DECLARE EXIT HANDLER FOR SQLEXCEPTION
		BEGIN
				GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
				SET pjRespObj       = buildJSONSmart( pjRespObj,  'jHeader.responseCode',   '1');
				SET pjRespObj 	   = buildJSONSmart( pjRespObj,
													'jHeader.message', CONCAT('Unexpected Error - Product creation failed ', v_err_msg)
													);
		END;

	main_block: BEGIN
     
     	SET v_mode =
					CASE
						WHEN isFalsy(getJval(pjReqObj,'P_PRODUCT_REC_ID')) THEN
						'INSERT'
						ELSE
						'UPDATE'
					END;
	
    CASE v_mode
    
		WHEN 'INSERT' THEN

			/* =============== Product Insert VALIDATIONS : If required fields are missing in reqObj ================ */

			IF isFalsy(getJval(pjReqObj,'P_TRADABLE_ASSETS_REC_ID')) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','tradable_assets_rec_id is required');
			END IF;
			
			IF isFalsy(getJval(pjReqObj,'P_ASSET_CODE')) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','asset_code is required');
			END IF;
			
			IF isFalsy(getJval(pjReqObj,'P_PRODUCT_CODE')) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','product_code is required');
			END IF;
			
			IF isFalsy(getJval(pjReqObj,'P_PRODUCT_NAME')) THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','product_name is required');
			END IF;
    
			/* =============== Duplicate product code check for INSERT ================ */
		   IF EXISTS (
						SELECT 1
						FROM products
						WHERE product_code = getJval(pjReqObj,'P_PRODUCT_CODE')
					) 	THEN
				SET v_errors = JSON_ARRAY_APPEND(v_errors,'$',CONCAT('Product already exists with product_code: ', getJval(pjReqObj,'product_code')));
		   END IF;
       
	   	/* =============== Show errors in array in response Obj ================ */  
		   IF JSON_LENGTH(v_errors) > 0 THEN
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message',        v_errors);
		   LEAVE main_block;
		   END IF;


			/* =============== CREATE PRODUCT: Product Insertation started ================ */
            
                /* ============= JSON PREPARATION ================== */
    
		 SET v_products_json 	= getTemplate('products');
		 SET v_products_json 	= fillTemplate(pjReqObj, v_products_json);
			
		 SET v_row_metadata		= getTemplate('row_metadata');
		 SET v_row_metadata 	= JSON_SET( v_row_metadata,
											'$.created_by', 	'SYSTEM',
											'$.created_at', 	 DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')
										  );

		 INSERT INTO products
				SET	tradable_assets_rec_id		= getJval(pjReqObj,	 'P_TRADABLE_ASSETS_REC_ID'),
					asset_code					= getJval(pjReqObj,	 'P_ASSET_CODE'),
					product_code				= getJval(pjReqObj,	 'P_PRODUCT_CODE'),
					product_type				= getJval(pjReqObj,	 'P_PRODUCT_TYPE'),
					product_name				= getJval(pjReqObj,	 'P_PRODUCT_NAME'),
					products_json				= v_products_json,
					row_metadata				= v_row_metadata;
					
				SET v_product_rec_id 			= LAST_INSERT_ID();

				-- Sync generated ID back into JSON
				SET v_products_json 			= JSON_SET( v_products_json,
															'$.product_rec_id', v_product_rec_id
														  );

				UPDATE products
				SET    products_json 	= v_products_json
				WHERE  product_rec_id 	= v_product_rec_id;
    
    

    /* =============== UPDATE PRODUCT: Product UPDATION started ================ */

    WHEN 'UPDATE' THEN

      	/* =============== Product Insert VALIDATIONS: UPDATE must target existing record ================ */

		SET v_product_rec_id = getJval(pjReqObj,'P_PRODUCT_REC_ID');
      
		IF v_product_rec_id IS NOT NULL
		AND NOT EXISTS (
						SELECT 1
						FROM products
						WHERE product_rec_id = v_product_rec_id
					 )  THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$','Invalid product_rec_id: record does not exist');

		END IF;
        
    /* =============== Duplicate check with other rows except the updated row ================ */  
    
        IF EXISTS (
					SELECT 1
					FROM products
					WHERE product_code = getJval(pjReqObj,'P_PRODUCT_CODE')
					AND product_rec_id <> v_product_rec_id
					) THEN
			SET v_errors = JSON_ARRAY_APPEND(v_errors,'$',CONCAT('Product already exists with product_code: ', getJval(pjReqObj,'P_PRODUCT_CODE')));
		END IF;	
    
	/* =============== Show errors in array in response Obj ================ */  
		IF JSON_LENGTH(v_errors) > 0 THEN
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.responseCode',   '1');
			SET pjRespObj  = buildJSONSmart(pjRespObj,  'jHeader.message', 		v_errors);
		LEAVE main_block;
		END IF;
        
     /* =============== Update started ================ */    


        SET v_products_json 	= getProduct(v_product_rec_id);

		SET v_products_json 	= fillTemplate(pjReqObj, v_products_json);

		SELECT 	row_metadata
		INTO 	v_row_metadata
		FROM 	products
		WHERE 	product_rec_id = v_product_rec_id;

        SET v_row_metadata = JSON_SET(
										v_row_metadata,
										'$.updated_by', 	'SYSTEM',
										'$.updated_at', 	DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s')
									);
		

        
        UPDATE products
        SET tradable_assets_rec_id		= getJval(v_products_json, 'tradable_assets_rec_id'),
			asset_code					= getJval(v_products_json, 'asset_code'), 			
            product_code				= getJval(v_products_json, 'product_code'),			
            product_type				= getJval(v_products_json, 'product_type'),			
            product_name				= getJval(v_products_json, 'product_name'),			
            products_json				= v_products_json,
			row_metadata				= v_row_metadata
		WHERE product_rec_id			= v_product_rec_id;
        
		IF ROW_COUNT() = 0 THEN
            SIGNAL SQLSTATE '45000'
            SET MESSAGE_TEXT = 'Update failed: no rows affected';
        END IF;
    END CASE;

	SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);

	SET pjRespObj = buildJSONSmart( pjRespObj,
								   'jHeader.message', IF( isFalsy(getJval(pjReqObj, 'P_PRODUCT_REC_ID')),
														  'Success - Product saved successfully',
														  'Success - Product updated successfully'
														)
								);
    
    
     END main_block;
     
     -- inert general code here like LOG
	-- call log proc
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `verifiyExistingNumber` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `verifiyExistingNumber`(
										IN     pjReqObj   JSON,
										INOUT  pjRespObj  JSON
									  )
BEGIN
    DECLARE v_phone          			VARCHAR(20);
    DECLARE v_err_msg        			TEXT;
    DECLARE v_reverser_lookup_json   	JSON;

    /* ===================== Error Handler ===================== */
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;

		SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
        SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Unexpected Error - Verification failed ', v_err_msg));

    END;

    /* ===================== Main ===================== */
    main_block: BEGIN

        /* ===================== Extract Phone ===================== */
        SET v_phone = getJval(pjReqObj, 'jData.P_PHONE_NUM');

        IF isFalsy(v_phone) THEN
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',      'Phone number is required'); 
            LEAVE main_block;
        END IF;

        /* ===================== 1. CUSTOMER CHECK ===================== */
        IF EXISTS (
					SELECT 1
					FROM   customer
					WHERE  phone = v_phone
		) THEN
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',      'User already exists with this phone number'); 									
		    LEAVE main_block;
        END IF;

        /* ===================== 2. Reverse Lookup ===================== */
        IF EXISTS (
					SELECT 1
					FROM   reverse_lookup
					WHERE  phone = v_phone
		) THEN

            -- Fetch reverse lookup data
            SELECT JSON_OBJECT(
								'first_name', 	first_name,
								'last_name',  	last_name,
								'email',      	email,
								'address',    	address,
								'city',       	city,
								'state',      	state,
								'zip_code',   	zip_code
							)
            INTO  v_reverser_lookup_json
            FROM  reverse_lookup
            WHERE phone = v_phone
            LIMIT 1;

            -- Generate OTP
            CALL genOtp(
                    JSON_OBJECT(
                        'jData', JSON_OBJECT(
												'P_CONTACT_TYPE', 'phone',
												'P_DESTINATION',  v_phone,
												'P_PURPOSE',      'For phone number verification at the time of signup'
											)
                    			),
                    				pjRespObj
                			);

            -- If genOtp failed (e.g. cooldown), leave immediately with genOtp's error message intact
            IF getJval(pjRespObj, 'jHeader.responseCode') != 0 THEN
                LEAVE main_block;
            END IF;

            -- genOtp succeeded, now write our own success response
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', '0');
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',      'Success - Phone exists in reverse lookup. Get the user info from jData.contents and proceed with registration.');
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents',       v_reverser_lookup_json);

            LEAVE main_block;
        END IF;

        /* ===================== 3. NEW USER ===================== */

        -- Generate OTP
        CALL genOtp(
                JSON_OBJECT(
                    'jData', JSON_OBJECT(
                        'P_CONTACT_TYPE', 'phone',
                        'P_DESTINATION',  v_phone,
                        'P_PURPOSE',      'For phone number verification at the time of signup'
                    )
                ),
                pjRespObj
            );

        -- If genOtp failed (e.g. cooldown), leave immediately with genOtp's error message intact
        IF getJval(pjRespObj, 'jHeader.responseCode') != 0 THEN
            LEAVE main_block;
        END IF;

        -- genOtp succeeded, now write our own success response
		SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);
		SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message',      'New user - Phone number is not found, proceed with registration.');

    END main_block;
END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `verifyAccountNum` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `verifyAccountNum`(
										IN  pjReqObj JSON,
										INOUT pjRespObj JSON
									)
BEGIN

	-- Declare variables for input extraction
	DECLARE v_contact_type		VARCHAR(100);
    DECLARE v_account_num		VARCHAR(255);
    
    -- Declare variables to hold database query results
    DECLARE v_account_num_db 	VARCHAR(255);
    DECLARE v_full_name			VARCHAR(255);
    
	-- Handler for NO ROW FOUND
    -- If SELECT INTO returns no row, set error JSON instead of raising an exception
	DECLARE EXIT HANDLER FOR NOT FOUND
		BEGIN
	
			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid account number or login ID');

		END;

 
    main_block: BEGIN
    
		-- Extract login ID and account number from input JSON
		SET v_contact_type 		= getJval(pjReqObj, 'jData.P_LOGIN_ID');
		SET v_account_num 		= getJval(pjReqObj, 'jData.P_ACCOUNT_NUM');
		
		-- Validate input: both login ID and account number must be provided
		IF isFalsy(v_contact_type) OR isFalsy(v_account_num) THEN

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 	1);
            SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 		'Invalid input');

			LEAVE main_block;
		END IF;
		
		-- Fetch account info from customers table
		SELECT  account_num,		CONCAT(first_name,' ',last_name)
		INTO    v_account_num_db, 	v_full_name
		FROM 	customer
		WHERE 	(LOWER(email) = LOWER(v_contact_type) OR LOWER(phone) = LOWER(v_contact_type) OR LOWER(user_name) = LOWER(v_contact_type))
		AND 	main_account_num = v_account_num
		LIMIT 	1;
		
		-- If a row is found, return success JSON with full name and account number
		SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 			0);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 				'Account verified successfully');
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jData.contents.customer_name', 	v_full_name);
        SET pjRespObj = buildJSONSmart( pjRespObj, 'jData.contents.account_num', 	v_account_num_db);	
									
			

    END main_block;

END ;;
DELIMITER ;
/*!50003 SET sql_mode              = @saved_sql_mode */ ;
/*!50003 SET character_set_client  = @saved_cs_client */ ;
/*!50003 SET character_set_results = @saved_cs_results */ ;
/*!50003 SET collation_connection  = @saved_col_connection */ ;
/*!50003 DROP PROCEDURE IF EXISTS `verifyOtp` */;
/*!50003 SET @saved_cs_client      = @@character_set_client */ ;
/*!50003 SET @saved_cs_results     = @@character_set_results */ ;
/*!50003 SET @saved_col_connection = @@collation_connection */ ;
/*!50003 SET character_set_client  = utf8mb4 */ ;
/*!50003 SET character_set_results = utf8mb4 */ ;
/*!50003 SET collation_connection  = utf8mb4_0900_ai_ci */ ;
/*!50003 SET @saved_sql_mode       = @@sql_mode */ ;
/*!50003 SET sql_mode              = 'ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION' */ ;
DELIMITER ;;
CREATE DEFINER=`root`@`localhost` PROCEDURE `verifyOtp`(
                            IN    pjReqObj 	JSON,
							INOUT pjRespObj   JSON
						 )
BEGIN
    DECLARE v_otp_rec_id    INT;
    DECLARE v_actual_otp    CHAR(6);
    DECLARE v_expiry        DATETIME;
    DECLARE v_retries       INT;
    DECLARE v_status        VARCHAR(20);
    DECLARE v_otp_token		JSON;
    
	DECLARE vContactType    ENUM('email','phone','loginid');
    DECLARE vDestination    VARCHAR(255);
    DECLARE vPurpose        VARCHAR(100);
    DECLARE vOtpCode        CHAR(6);
    
    DECLARE v_login_id      VARCHAR(100);

	DECLARE v_err_msg TEXT;
	DECLARE EXIT HANDLER FOR SQLEXCEPTION
	BEGIN

			GET STACKED DIAGNOSTICS CONDITION 1 v_err_msg = MESSAGE_TEXT;
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', CONCAT('Unexpected Error - ', v_err_msg));

	END;
    
	main_block: BEGIN
    
		-- =========================
			-- Extract values from JSON
		-- =========================
		SET vContactType 		= getJval(pjReqObj, 'jData.P_CONTACT_TYPE');
		SET vDestination 		= getJval(pjReqObj, 'jData.P_DESTINATION');
		SET vOtpCode     		= getJval(pjReqObj, 'jData.P_OTP_CODE');
		SET vPurpose    		= getJval(pjReqObj, 'jData.P_PURPOSE');

		IF isFalsy(vContactType) OR isFalsy(vDestination) OR isFalsy(vOtpCode) OR isFalsy(vPurpose) THEN
    		
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
    		SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', 'Missing required parameters');

    		LEAVE main_block;
		END IF;

		-- =========================
		-- Get latest OTP
		-- =========================
		SELECT otp_rec_id, 		otp_code, 		expires_at, 	otp_retries
		INTO   v_otp_rec_id, 	v_actual_otp, 	v_expiry, 		v_retries
		FROM   otp
		WHERE  contact_type = vContactType
		AND    destination  = vDestination
		AND    purpose      = vPurpose
		ORDER BY otp_rec_id DESC
		LIMIT 1;

		-- =========================
		-- No OTP found
		-- =========================
		IF v_otp_rec_id IS NULL THEN

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);

	    	SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.message', 'OTP not found' );  
			
			LEAVE main_block;
		END IF;

		-- =========================
		-- OTP expired
		-- =========================
		IF NOW() > v_expiry THEN

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);

	    	SET pjRespObj = buildJSONSmart( pjRespObj,
								   			'jHeader.message', 'OTP EXPIRED'
							               );  
			
			LEAVE main_block;
		END IF;

		-- =========================
		-- OTP mismatch
		-- =========================
		IF v_actual_otp <> vOtpCode THEN
			IF v_retries > 1 THEN
				UPDATE  otp
				SET 	otp_retries = otp_retries - 1
				WHERE 	otp_rec_id 	= v_otp_rec_id;
				
				SET 	v_status 	= 'INVALID';
				SET 	v_retries 	= v_retries - 1;
			ELSE
				-- No retries left
				UPDATE otp
				SET    otp_retries 	= 0,
					   expires_at 	= NOW()
				WHERE  otp_rec_id	= v_otp_rec_id;
				
				SET v_status 		= 'FAILED';
				SET v_retries 		= 0;
			END IF;

			SET pjRespObj = buildJSONSmart( pjRespObj, 'jHeader.responseCode', 1);

	    	SET pjRespObj = buildJSONSmart( pjRespObj,
								   			'jHeader.message', CONCAT('OTP IS ',v_status, ', ', v_retries, ' retries left.')
							               );  
			LEAVE main_block;
		END IF;

		-- =========================
		-- OTP SUCCESS
		-- =========================
		UPDATE 	otp
		SET 	expires_at 		= NOW(),
				otp_retries 	= 0
		WHERE otp_rec_id = v_otp_rec_id;
		
		-- =========================
		-- Call Handle Otp Success SP
		-- =========================
		
		CALL handleOtpSuccess(vContactType, vDestination, vPurpose, v_otp_token);
		
		
			-- =========================
			-- Final Success Response
			-- =========================

		-- If handleOtpSuccess failed, leave with its error message intact
		IF getJval(v_otp_token, 'jHeader.responseCode') != 0 THEN

			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 1);
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', getJval(v_otp_token, 'jHeader.message'));

			LEAVE main_block;
		END IF;

		-- handleOtpSuccess succeeded, copy its full response into pjRespObj
		SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.responseCode', 0);
		SET pjRespObj = buildJSONSmart(pjRespObj, 'jHeader.message', getJval(v_otp_token, 'jHeader.message'));  


		IF getJval(v_otp_token, 'jData.contents.reset_token') IS NOT NULL THEN
		
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.reset_token', getJval(v_otp_token, 'jData.contents.reset_token'));
			SET pjRespObj = buildJSONSmart(pjRespObj, 'jData.contents.reset_token_expires_in_minutes', getJval(v_otp_token, 'jData.contents.reset_token_expires_in_minutes'));

		END IF;
			
    END main_block;
    -- logging
END ;;
DELIMITER ;
